import type { GrammarPoint } from './types';

// 여행 팁 — 세션 끝에 1개씩 회전(안 본 것 우선). 문법·문화·발음·여행 매너 골고루.
export const grammar: GrammarPoint[] = [
  // ── 문법 ──
  { id: 'g_masuka', category: '문법', tags: ['호텔', '억양', '조사', '반말', '어미'], label: '〜ますか (정중 의문)', tipKo: '문장 끝 ますか는 정중한 질문. 한국어 "~합니까?"처럼 끝만 올리면 됩니다.', detail: 'ます는 동사를 정중체로 바꾸는 어미이고, 그 뒤에 의문 조사 か를 붙이면 그대로 정중한 질문이 됩니다. 반말체 동사(예: 使える)를 정중체(使えます)로 바꾸는 규칙만 알면 어떤 동사든 같은 패턴으로 질문을 만들 수 있어서 활용도가 매우 높습니다. 점원·역무원·호텔 직원처럼 처음 만나는 사람에게는 항상 이 형태를 쓰는 것이 안전하며, 친구 사이의 편한 대화에서는 か를 빼고 억양만 올리는 경우가 많습니다. 여행 중에는 "〜られますか(~할 수 있나요)", "〜ありますか(~있나요)"처럼 뒤에 오는 동사만 바꿔 끼우면 되므로, 이 문형 하나로 정말 많은 상황을 커버할 수 있어요.', exampleJa: 'カードは使えますか', exampleKo: '카드 사용할 수 있나요?', commonMistake: '질문인데 끝 억양을 너무 낮추면 확인보다 단정처럼 들려요.', action: '마지막 か를 살짝 올려 한 번 말해 보세요.', n5Refs: ['n5_g_masu'] },
  { id: 'g_kudasai', category: '문법', tags: ['편의점', '식당', 'ください'], label: '〜ください (주세요)', tipKo: '명사 + ください는 "~ 주세요". 동사 て형 + ください면 "~해 주세요"가 됩니다.', detail: 'ください는 원래 "주시다"라는 뜻의 존경 동사 くださる에서 온 명령형으로, 상대에게 무언가를 정중하게 요청할 때 쓰는 가장 기본적인 표현입니다. 명사 뒤에 바로 붙이면 "그 물건을 주세요"라는 뜻이 되고(みずください), 동사의 て형 뒤에 붙이면 "그 행동을 해 주세요"라는 뜻으로 확장됩니다(みせてください=보여주세요). 이 두 가지 쓰임을 구분하는 것이 핵심인데, 동사 기본형이나 ます형에 바로 ください를 붙이면 문법적으로 어색해지므로 반드시 て형을 거쳐야 합니다. 편의점·식당·매표소 등 물건을 살 때는 명사+ください, 직원에게 어떤 동작을 부탁할 때는 て형+ください로 나눠서 기억해 두면 실전에서 헷갈리지 않아요.', exampleJa: 'これを見せてください', exampleKo: '이것을 보여 주세요.', commonMistake: '동사 기본형 뒤에 바로 ください를 붙이지 않아요.', action: 'これください와 みせてください를 소리 내어 비교해 보세요.' },
  { id: 'g_wo', category: '문법', tags: ['조사', '발음', '목적어'], label: '조사 を (목적어)', tipKo: '"~을/를". みずをください(물을 주세요). 회화에선 자주 생략 — みず、ください만 해도 통합니다.', detail: '조사 を는 문장에서 동작이 미치는 대상, 즉 목적어를 표시하는 역할을 합니다. 표기는 を지만 실제 발음은 단모음 お와 완전히 같아서, 옛 발음이 남아 있는 표기와 현대 발음 사이에 차이가 생긴 대표적인 예입니다. 격식 있는 글이나 안내 방송에서는 꼬박꼬박 등장하지만, 실제 구어체 대화에서는 생략되는 일이 아주 흔해서 "みずをください" 대신 그냥 "みず、ください"라고만 해도 자연스럽게 통합니다. 여행 중 급하게 말할 때는 조사를 다 갖추려 하지 말고 명사만 나열한 뒤 쉼표 느낌으로 끊고 요청 표현을 붙이는 것도 충분히 통하는 실전 전략입니다.', exampleJa: 'みずをください', exampleKo: '물을 주세요.', commonMistake: 'を를 「お」로 발음해요 — 단, 회화에서는 생략하거나 약하게 말해도 자연스러워요.', action: 'みずをください와 みず、ください를 둘 다 소리 내어 비교해 보세요.' },
  { id: 'g_desu', category: '문법', tags: ['반말', 'です'], label: '〜です (정중한 ~입니다)', tipKo: '명사·형용사 뒤 정중체. ひとりです(한 명입니다), だいじょうぶです(괜찮습니다). 끝에 です만 붙이면 공손해져요.', detail: 'です는 명사나 な형용사 뒤에 붙어 문장을 정중체로 만들어주는 서술어로, 한국어의 "~입니다"에 대응합니다. 반말체인 だ를 그대로 です로 바꾸기만 하면 되므로 활용 부담이 거의 없고, 그만큼 여행 회화에서 가장 먼저 익혀야 할 표현 중 하나입니다. 인원수를 말할 때(ひとりです), 상태를 말할 때(だいじょうぶです), 이름이나 소속을 말할 때(かんこくじんです)까지 명사 자리만 바꿔 끼우면 되는 만능 틀이에요. 다만 い형용사는 です 없이도 그 자체로 문장이 끝날 수 있는데, 이때 です를 붙이면 더 정중해지는 정도의 차이만 생긴다는 점도 함께 알아두면 좋습니다.', exampleJa: 'ひとりです', exampleKo: '혼자입니다.', commonMistake: '정중한 자리에서 です를 빠뜨리면 반말처럼 들릴 수 있어요.', action: '인원수나 상황을 말하고 뒤에 です를 붙이는 연습을 해 보세요.' },
  { id: 'g_counting', category: '문법', tags: ['편의점', '한자', '개수', 'ひとつ・ふたつ'], label: '개수 ひとつ・ふたつ', tipKo: '물건 셀 때 ひとつ(하나)・ふたつ(둘)・みっつ(셋). これ、ひとつください처럼 그대로 쓰면 됩니다.', detail: 'ひとつ・ふたつ・みっつ 시리즈는 일본 고유어(和語) 숫자 체계로, とお(열)까지 존재하는 아주 오래된 세는 방식입니다. 물건의 종류에 관계없이 "이거 ひとつ, 저거 ふたつ"처럼 그대로 쓸 수 있다는 점이 최대 장점이라, 조수사(枚·個·本 등)를 다 못 외웠어도 이 시리즈 하나만 알면 편의점이나 노점에서 웬만한 개수 표현은 다 해결됩니다. 다만 11개 이상으로 넘어가면 이 고유어 시리즈가 끊기고 한자어 숫자+개(こ)로 바뀌므로, 소량 구매 상황(1~10개)에 특히 유용한 표현이라는 점을 기억해 두세요. 여행 중에는 물건을 가리키며 개수만 말해도 의사소통이 충분히 되는 경우가 많습니다.', exampleJa: 'これをひとつください', exampleKo: '이거 하나 주세요.', action: 'ひとつ·ふたつ·みっつ를 손가락과 함께 세면서 말해 보세요.' },
  { id: 'g_onegai', category: '문법', tags: ['카드', '택시', '한자', 'おねがいします', '부탁'], label: '〜おねがいします (부탁)', tipKo: '명사·부사 뒤에 붙이는 요청 만능 표현입니다.', detail: 'おねがいします는 한자로 お願いします라고 쓰며, 직역하면 "부탁합니다"지만 실제로는 명사나 부사 뒤에 거의 무엇이든 붙일 수 있는 만능 요청 표현으로 기능합니다. ください가 구체적인 물건이나 행동을 지시하는 느낌이라면, おねがいします는 좀 더 부드럽고 격식 있게 부탁하는 뉴앙스가 있어서 택시 목적지, 결제 수단, 속도 조절 등 다양한 맥락에 자연스럽게 어울립니다. "ゆっくりお願いします(천천히 부탁합니다)", "カードでお願いします(카드로 부탁합니다)"처럼 앞에 명사나 부사만 바꿔 끼우면 되므로 실전에서 가장 활용도가 높은 표현 중 하나입니다. 목소리를 또렷하게 내야 요청이라는 것이 전달되므로, 작게 웅얼거리기보다 분명하게 말하는 것이 중요합니다.', exampleJa: 'ゆっくりお願いします', exampleKo: '천천히 부탁합니다.', commonMistake: '친절하지만 너무 작게 말하면 요청인지 알아듣기 어려워요.', action: '필요한 단어를 먼저 말하고 おねがいします로 마무리하세요.' },
  { id: 'g_kosoado', category: '문법', tags: ['これ・それ・あれ'], label: 'これ・それ・あれ', tipKo: '이거(これ, 내 가까이)·그거(それ, 상대 가까이)·저거(あれ, 둘 다 멀리). 가리키며 これください면 안전.', detail: 'これ・それ・あれ는 일본어의 지시대명사 체계인 こそあど(こ·そ·あ·ど) 계열의 대표 예로, 화자와 청자를 기준으로 거리를 나눕니다. これ는 말하는 사람에게 가까운 것, それ는 듣는 사람에게 가까운 것, あれ는 둘 다에서 먼 것을 가리키며, 이 구조는 장소를 가리키는 ここ・そこ・あそこ, 방향을 가리키는 こちら・そちら・あちら에도 그대로 이어집니다. 실전에서는 정확한 거리 구분에 자신이 없어도 손가락으로 가리키면서 これください라고 하면 대부분 자연스럽게 통하므로, 이 세 단어의 차이를 몰라도 급할 때는 これ 하나로 밀고 나가도 괜찮습니다. 진열대 너머의 물건을 가리킬 때는 それ, 멀리 있는 메뉴판이나 상품을 가리킬 때는 あれ를 쓰면 더 자연스럽습니다.', exampleJa: 'それをください', exampleKo: '그거 주세요.', action: 'これ·それ·あれ를 가리키면서 순서대로 말해 보세요.' },
  { id: 'g_intonation', category: '문법', tags: ['억양', '조사', '질문'], label: '억양만으로 질문', tipKo: 'か 없이 끝을 올리기만 해도 질문이 됩니다. これ?(이거요?) 처럼 — 회화에서 아주 흔해요.', detail: '일본어는 문장 끝에 의문 조사 か를 붙이지 않고도 억양만 올려서 질문을 만드는 경우가 회화에서 매우 흔합니다. 이는 한국어에서 "이거?"처럼 짧게 되물을 때 끝을 올리는 것과 원리가 같아서 한국어 화자에게는 오히려 익숙하게 느껴질 수 있는 패턴입니다. 격식 있는 자리나 글에서는 반드시 か를 붙이지만, 친근한 대화나 짧은 확인 질문에서는 명사나 짧은 문장 끝을 올리는 것만으로 충분히 질문의 의미가 전달됩니다. 여행 중 시간이 급하거나 긴 문장을 만들기 어려울 때는 これ？, いくら？처럼 단어 하나에 억양만 올려도 상대가 질문으로 알아듣는 경우가 많으니 부담 없이 활용해 보세요.', exampleJa: 'これ、いくらですか', exampleKo: '이거 얼마예요?', action: '문장 끝 억양을 올리며 これ？를 짧게 말해 보세요.' },

  // ── 문화·매너 ──
  { id: 'g_no_tip', category: '문화', tags: ['잔돈', '팁', '택시', '료칸', '호텔'], label: '팁 문화 없음', tipKo: '일본은 팁이 없어요. 거스름돈을 두고 나오면 오히려 점원이 쫓아옵니다. 계산한 만큼만 내면 됩니다.', detail: '일본은 서비스업 전반에 팁을 주고받는 문화가 없으며, 이는 "정해진 요금 안에 이미 충분한 서비스가 포함되어 있다"는 인식이 사회 전반에 자리잡고 있기 때문입니다. 오히려 계산 후 거스름돈이나 잔돈을 테이블·카운터에 그대로 두고 나오면, 직원이 손님이 돈을 놓고 갔다고 생각해 밖까지 쫓아 나와 돌려주는 상황이 자주 벌어집니다. 고급 료칸이나 특수한 서비스(짐 옮겨주기 등)에서 아주 예외적으로 팁 봉투 문화가 남아 있는 경우도 있지만, 일반적인 식당·카페·택시·호텔에서는 팁을 주려는 시도 자체가 오히려 상대를 당황하게 만들 수 있습니다. 정중하게 감사를 표현하고 싶다면 돈보다 말 한마디, 즉 계산 후 가벼운 목례와 ありがとうございました 인사가 훨씬 자연스럽고 확실하게 전달됩니다.', commonMistake: '거스름돈을 테이블에 남겨 두면 직원이 쫓아와 돌려줍니다.', action: '계산 후 거스름돈을 꼭 챙기고 ありがとうございました 한마디를 남기세요.', missionIds: ['C2'] },
  { id: 'g_bow', category: '문화', tags: ['가벼운', '목례', 'おじぎ'], label: '가벼운 목례(おじぎ)', tipKo: '인사·감사·사과에 가볍게 고개를 숙이면 자연스러워요. 손님은 말 없이 목례만 해도 충분합니다.', detail: 'おじぎ(목례)는 일본 사회 전반에서 인사·감사·사과·부탁 등 거의 모든 상황에 쓰이는 만능 비언어 표현으로, 각도에 따라 뉘앙스가 달라집니다. 가벼운 인사나 감사는 15도 정도로 고개만 살짝 숙이는 것으로 충분하고, 정중한 사과나 격식 있는 자리에서는 30~45도까지 깊게 숙이기도 하지만 여행자 입장에서는 가벼운 목례만으로도 예의를 충분히 갖춘 것으로 받아들여집니다. 말이 잘 통하지 않는 상황에서도 목례는 언어 장벽 없이 감사나 사과의 마음을 전달할 수 있는 가장 안전한 수단이라, 점원의 안내를 받았을 때나 실수로 부딪혔을 때 등 말이 막히는 순간에 특히 유용합니다. 손을 흔들거나 악수를 시도하기보다는, 현지인처럼 고개를 숙이는 쪽이 훨씬 자연스럽게 받아들여집니다.', exampleJa: 'ありがとうございます', exampleKo: '감사합니다.', action: 'ありがとうございます를 말하면서 15도 정도 가볍게 고개를 숙여 보세요.' },
  { id: 'g_quiet_train', category: '문화', tags: ['전철', '버스', '마트', '매너'], label: '전철에선 통화 자제', tipKo: '전철·버스 안 통화는 민폐로 봐요. 진동으로 바꾸고 대화도 작게. 「マナーモード」(매너 모드).', detail: '일본의 대중교통에서는 통화 소리가 다른 승객에게 방해가 되는 대표적인 민폐(迷惑) 행위로 여겨져, 열차 안내 방송에서도 매번 스마트폰을 진동 모드(マナーモード)로 바꾸고 통화는 자제해 달라는 안내가 나올 정도로 사회적 규범이 강합니다. 급한 전화가 오더라도 대부분 문자로 답하거나, 정차 후 플랫폼에 내려서 통화하는 것이 일반적인 관행입니다. 옆 사람과의 대화 자체는 허용되지만 목소리를 낮추는 것이 예의이며, 특히 우선석(優先席) 근처에서는 더욱 조용히 하는 것이 권장됩니다. 영상이나 음악을 들을 때도 이어폰 없이 스피커로 재생하면 큰 실례가 되므로, 탑승 전에 항상 이어폰과 진동 모드를 미리 준비해 두는 습관을 들이는 것이 좋습니다.', commonMistake: '이어폰 없이 영상 소리를 틀면 민폐로 봐요 — 반드시 이어폰을 사용하세요.', action: '탑승 전 스마트폰을 진동(マナーモード)으로 전환하는 습관을 들이세요.', missionIds: ['C3'] },
  { id: 'g_queue', category: '문화', tags: ['지하철', '도쿄', '오사카', '줄서기', '에스컬레이터'], label: '줄서기·에스컬레이터', tipKo: '승강장 표시선에 줄 서고, 에스컬레이터에서는 걷지 않는 것이 현재 권장 원칙입니다.', detail: '일본 지하철 승강장에는 줄을 서야 하는 위치가 바닥에 표시되어 있어, 열차 문이 열리는 지점을 미리 확인하고 그 앞에 순서대로 줄을 서는 문화가 매우 철저하게 지켜집니다. 내리는 사람이 먼저 완전히 내린 뒤에 타는 것이 기본 원칙이며, 새치기 없이 줄 순서를 지키는 것이 당연시됩니다. 에스컬레이터의 경우 예전에는 한쪽을 비워 걷는 사람이 지나가도록 하는 관행(도쿄는 왼쪽, 오사카는 오른쪽 서기)이 있었지만, 최근에는 안전사고 예방을 위해 양쪽 모두 서서 타고 걷지 않는 것을 공식적으로 권장하는 지자체와 사업자가 늘고 있습니다. 지역과 시기에 따라 안내가 다를 수 있으므로, 옛 관행만 믿기보다는 그 자리의 바닥 표시나 방송 안내를 우선적으로 따르는 것이 가장 안전합니다.', commonMistake: '지역별 관행만 믿고 급하게 걷다가 충돌하기 쉬워요.', action: '바닥 표시와 현장 안내를 우선 확인하세요.', missionIds: ['C46'] },
  { id: 'g_cash', category: '문화', tags: ['현금', '카드', '수수료', 'IC카드', 'Suica'], label: '현금도 챙기기', tipKo: '카드·IC가 늘었지만 작은 가게·식권기는 현금만인 곳도. 동전·천엔권을 조금 준비하면 편해요.', detail: '최근 일본은 신용카드와 교통 IC카드(Suica·PASMO 등) 결제가 빠르게 보급되었지만, 여전히 개인이 운영하는 작은 식당이나 노포, 일부 식권 자판기, 신사·절의 새전함, 코인로커 등은 현금만 받는 경우가 많습니다. 특히 관광객이 몰리지 않는 골목 식당이나 지방 소도시로 갈수록 현금 결제 비중이 높아지는 경향이 있어, 카드만 믿고 다니면 계산대 앞에서 당황할 수 있습니다. 100엔·500엔 동전과 1000엔권을 넉넉히 챙겨 두면 자판기·코인로커·소액 결제 상황에서 훨씬 여유롭게 대응할 수 있고, 큰 액수의 지폐(1만엔권)는 작은 가게에서 거스름돈이 없어 거절당할 수도 있으니 미리 잔돈으로 바꿔 두는 것이 좋습니다. 편의점 ATM은 대부분 24시간 운영되고 해외 카드 인출도 잘 지원되므로, 현금이 부족해지면 가까운 편의점부터 찾는 것이 가장 확실한 방법입니다.', exampleJa: 'ATMはどこですか', exampleKo: 'ATM은 어디에 있나요?', action: '편의점 ATM에서 소액 인출하면 수수료가 낮을 수 있어요.', missionIds: ['C10', 'C43'] },
  { id: 'g_shoes', category: '문화', tags: ['료칸', '숙소', '식당', '매너', '다다미'], label: '신발 벗는 곳', tipKo: '다다미방·일부 식당·숙소는 신발을 벗어요. 입구에 단차나 신발장이 있으면 벗으라는 신호.', detail: '일본에서는 다다미가 깔린 방, 전통 료칸, 일부 좌식 식당, 사원이나 가정집을 방문할 때 신발을 벗는 것이 기본 예절입니다. 신발을 벗어야 하는 공간인지는 대개 입구의 높낮이 차이(단차, 玄関)나 신발장(下駄箱)의 유무로 쉽게 구분할 수 있어, 처음 가보는 곳이라도 입구를 잘 살펴보면 판단할 수 있습니다. 신발을 벗은 뒤에는 뒤꿈치가 바깥쪽(문 쪽)을 향하도록 가지런히 돌려놓는 것이 세련된 매너로 여겨지며, 양말이나 스타킹 없이 맨발로 다니는 것은 피하는 것이 좋습니다. 료칸이나 다다미방에서는 실내용 슬리퍼가 따로 준비되어 있는 경우가 많지만, 다다미 바닥 위에서는 슬리퍼조차 벗고 맨발이나 양말로 다니는 것이 원칙이라는 점도 함께 기억해 두면 좋습니다.', exampleJa: '靴を脱ぎますか', exampleKo: '신발을 벗어야 하나요?', action: '입구에 단차나 신발장이 보이면 신발을 벗고 뒤꿈치를 문 쪽으로 가지런히 놓으세요.', missionIds: ['C4'] },
  { id: 'g_itadakimasu', category: '문화', tags: ['이자카야', '식당', '한자', 'いただきます', 'ごちそうさま'], label: 'いただきます / ごちそうさま', tipKo: '먹기 전 いただきます, 다 먹고 ごちそうさま(でした). 식당 나설 때 한마디면 인상이 좋아져요.', detail: 'いただきます는 원래 "받겠습니다"라는 겸양 표현에서 온 식사 전 인사말로, 음식을 만들어 준 사람과 재료가 된 생명 모두에 대한 감사의 의미를 담고 있습니다. 식사가 끝난 뒤에는 ごちそうさまでした("잘 먹었습니다", 한자로 御馳走様)를 말하는데, 이는 예전에 손님을 대접하기 위해 이곳저곳 뛰어다니며(馳走) 음식을 마련했던 데서 유래한 표현이라고 알려져 있습니다. 혼자 식사할 때도 마음속으로 되뇌는 경우가 많을 만큼 일상 깊숙이 자리잡은 습관이라, 여행자가 이 두 마디를 자연스럽게 사용하면 현지인들에게 좋은 인상을 남길 수 있습니다. 특히 작은 식당이나 이자카야에서 나갈 때 계산 후 ごちそうさまでした 한마디를 덧붙이면 단순한 손님을 넘어 예의를 아는 사람으로 여겨져 더 친절한 응대를 받게 되는 경우도 많습니다.', exampleJa: 'ごちそうさまでした', exampleKo: '잘 먹었습니다.', action: '식사 전후 소리 내어 いただきます / ごちそうさまでした를 말해 보세요.', missionIds: ['C2', 'C13'] },
  { id: 'g_oshibori', category: '문화', tags: ['식당', '매너', 'おしぼり', '물수건'], label: 'おしぼり(물수건)', tipKo: '식당에서 주는 물수건은 손을 닦는 용도예요. 얼굴·테이블을 닦는 건 매너가 아니에요.', detail: 'おしぼり는 식당에 앉으면 가장 먼저 제공되는 물수건으로, 식사 전에 손을 청결히 하라는 배려에서 나온 일본 특유의 서비스입니다. 여름에는 시원한 물수건, 겨울에는 따뜻한 물수건이 나오는 등 계절에 맞춰 온도를 조절하는 세심함도 특징입니다. 손을 닦는 용도로만 사용하는 것이 원칙이며, 땀을 닦으려고 얼굴을 문지르거나 테이블 위 물기를 닦는 용도로 쓰는 것은 매너에 어긋나는 행동으로 여겨질 수 있으니 주의해야 합니다. 사용이 끝난 오시보리는 아무렇게나 두지 말고 처음 놓여 있던 모양대로 접어서 받침 위에 가지런히 올려두면, 정갈하게 마무리하는 인상을 줄 수 있습니다.', commonMistake: '얼굴이나 테이블을 닦으면 실례로 볼 수 있어요.', action: '오시보리는 손만 닦은 뒤 접어서 받침 위에 올려두세요.', missionIds: ['C2', 'C13'] },

  // ── 발음 ──
  { id: 'g_long_vowel', category: '발음', tags: ['발음', '장음', '가나', '히라가나', '가타카나'], label: '장음(길게)', tipKo: '일본어는 모음 길이로 뜻이 달라질 수 있습니다.', detail: '일본어는 박자 언어(モーラ言語)라서 모음의 길이 자체가 별개의 음운으로 기능하며, 짧은 모음과 긴 모음(장음)은 완전히 다른 단어를 만듭니다. ビル(빌딩)와 ビール(맥주)처럼 한 박만 차이가 나도 뜻이 통째로 바뀌므로, 한국어 화자가 무심코 장음을 짧게 줄여 말하면 전혀 다른 단어로 들려 오해가 생길 수 있습니다. 히라가나에서는 같은 모음을 한 번 더 적어(おかあさん) 장음을 표시하고, 가타카나에서는 장음 부호 ー를 사용하는 것이 기본 규칙입니다. 장음이 있는 단어를 발음할 때는 앞 모음의 입 모양을 그대로 유지한 채 박자 하나만큼 더 길게 끄는 느낌으로 연습하면, 짧은 모음과의 차이를 몸으로 익힐 수 있습니다.', exampleJa: 'ビル / ビール', exampleKo: '빌딩 / 맥주', commonMistake: '한국어처럼 길이를 줄이면 다른 단어로 들릴 수 있어요.', action: 'ビール의 イ 뒤를 한 박 더 유지해 보세요.' },
  { id: 'g_sokuon', category: '발음', tags: ['촉음', '멈춤'], label: '촉음 っ (짧게 멈춤)', tipKo: '작은 っ는 다음 자음 전에 한 박 멈추는 표시입니다.', detail: '작게 표기하는 っ(촉음)는 그 자체로는 소리를 내지 않고, 다음에 오는 자음 앞에서 숨을 한 박 멈추는 무음의 박자를 나타냅니다. 로마자로 옮길 때는 다음 자음을 겹쳐 써서(きって=kitte) 이 멈춤을 표시하는데, 이 한 박의 정지가 실제로 단어의 뜻을 완전히 바꿔 놓습니다. 예를 들어 きって(우표)는 き・(멈춤)・て로 세 박이지만, 촉음 없이 きて라고 읽으면 "와 주세요"라는 전혀 다른 동사가 되어 버립니다. 한국어에는 이런 무음의 박자 개념이 없다 보니 촉음을 건너뛰고 빨리 읽어버리기 쉬운데, 손가락으로 박자를 하나씩 짚어가며 끊어 읽는 연습을 하면 이 멈춤의 길이감을 몸에 익히는 데 도움이 됩니다.', exampleJa: 'きって', exampleKo: '우표', commonMistake: 'きて처럼 멈춤 없이 읽으면 "와서"로 들릴 수 있어요.', action: 'き・(멈춤)・て 세 박으로 말해 보세요.' },
  { id: 'g_r_sound', category: '발음', tags: ['발음', 'ら행', 'r/l', '중간'], label: 'ら행 (r/l 중간)', tipKo: 'ら·り·る·れ·ろ는 한국어 ㄹ에 가깝게 살짝 튕기듯. 영어 R처럼 굴리지 않아요.', detail: '일본어의 ら행(ら・り・る・れ・ろ)은 혀끝을 윗잇몸 뒤쪽에 한 번 가볍게 튕기듯 대는 탄음(弾き音)으로, 음성학적으로는 영어의 R보다 한국어의 ㄹ이나 스페인어의 짧은 r에 훨씬 더 가깝습니다. 영어를 먼저 배운 학습자일수록 R처럼 혀를 말거나 굴리려는 습관이 나오기 쉬운데, 이렇게 발음하면 오히려 원어민에게는 어색하고 부자연스럽게 들립니다. 반대로 한국어의 받침 ㄹ(달, 물처럼 혀가 윗잇몸에 붙어 멈추는 소리)과도 다르며, 혀가 닿았다 바로 떨어지는 아주 짧고 가벼운 접촉이라는 점이 핵심입니다. ありがとう처럼 자주 쓰는 인사말로 연습하면서 り 부분에서 혀끝이 윗잇몸을 한 번만 톡 치고 바로 떨어지는 감각을 익혀보는 것이 효과적입니다.', exampleJa: 'ありがとうございます', exampleKo: '감사합니다.', commonMistake: '영어 R처럼 혀를 굴리면 원어민에게 어색하게 들려요.', action: 'ありがとう를 세 번 말하면서 り 소리를 혀끝으로 한 번만 가볍게 튕겨 보세요.' },
  { id: 'g_fu', category: '발음', tags: ['발음'], label: 'ふ 발음', tipKo: 'ふ는 영어 f와 한국어 ㅎ의 중간 — 입술을 살짝 모으되 물지 않고 바람을 내요. "후"에 가깝게.', detail: 'は행 중 유독 ふ만 다른 발음 방식을 쓰는데, 언어학적으로는 양순 마찰음(両唇摩擦音)이라고 불리는 소리로 영어의 f와 한국어의 ㅎ 그 중간 어디쯤에 위치합니다. 영어 f는 윗니로 아랫입술을 살짝 물고 바람을 내보내는 소리지만, 일본어 ふ는 이와 이가 닿지 않고 두 입술만 살짝 오므린 채 그 틈으로 바람을 내보내는 소리라는 점이 결정적인 차이입니다. 그래서 영어식 f 발음 습관이 있는 학습자가 ふ를 발음하면 치아가 입술에 닿아 원어민이 듣기에 다소 부자연스럽게 느껴질 수 있습니다. 발음할 때는 마치 촛불을 살살 불어서 끄듯 입술만 둥글게 모으고 바람을 내보내는 느낌으로 연습하면, 치아가 닿지 않는 올바른 입 모양을 익히기 쉽습니다.', exampleJa: 'ふたつ', exampleKo: '둘 (개수)', commonMistake: '영어 f처럼 아랫입술을 윗니에 대면 일본어 발음과 달라져요.', action: 'ふたつ를 소리 내어 말하며 입술이 이에 닿지 않는지 거울로 확인해 보세요.' },

  // ── 여행 실전 ──
  { id: 'g_konbini', category: '여행', tags: ['카드', '숙소', '편의점', '마트', '택배'], label: '편의점 만능', tipKo: '편의점에서 ATM 출금·택배(택큐빈)·티켓·복사·공과금까지 돼요. 막히면 일단 편의점.', detail: '일본 여행에서 무언가 막히면 일단 편의점부터 찾으라는 말이 나올 정도로, 세븐일레븐·로손·패밀리마트 같은 편의점은 단순한 매점을 넘어 종합 생활 서비스 창구 역할을 합니다. ATM에서 해외 카드로 엔화를 인출할 수 있고, 택배(택큐빈) 접수·발송이 가능하며, 공연·전시 티켓 예매기(로피·세븐 티켓 등)로 현장 발권도 할 수 있습니다. 복합기에서는 복사·스캔은 물론 각종 공과금·세금 납부용지 결제까지 처리할 수 있어서, 여행 중 서류 출력이 필요하거나 짐을 숙소로 미리 보내고 싶을 때도 편의점 하나로 대부분 해결됩니다. 24시간 운영되는 곳이 많아 늦은 밤이나 이른 아침에 문제가 생겨도 가장 먼저 의지할 수 있는 곳이라는 점도 큰 장점입니다.', exampleJa: 'コピー機はありますか', exampleKo: '복사기가 있나요?', action: '편의점에서 ATM·택배·티켓 발권·복사·스캔·공과금 납부까지 할 수 있어요.', missionIds: ['C1', 'C12', 'C43', 'C44'] },
  { id: 'g_menzei', category: '여행', tags: ['면세', '영수증', '백화점', '여권', '필수'], label: '면세는 여권 필수', tipKo: '면세(免税)는 여권이 있어야 해요. 보통 한 점포 5,000엔 이상. 개봉 금지 봉투로 포장해 줍니다.', detail: '일본의 소비세 면세(免税) 제도는 외국인 관광객이 같은 매장에서 일정 금액 이상(보통 세금 포함 5,000엔 이상) 구매할 때 소비세를 면제해 주는 제도로, 반드시 여권 원본을 계산대에 제시해야 적용받을 수 있습니다. 면세 처리가 완료되면 영수증이 여권에 부착되거나 별지로 첨부되고, 소모품(화장품·식품 등)은 개봉하지 않고 일본을 출국할 때까지 뜯지 말라는 조건의 투명 봉투로 밀봉해 주는 경우가 많습니다. 출국 심사 전에 세관에서 면세품 확인 절차가 있을 수 있으므로, 영수증과 여권을 잘 보관하고 봉투를 임의로 개봉하지 않는 것이 중요합니다. 백화점이나 대형 매장은 별도의 면세 카운터가 있는 경우도 많으니, 계산 전에 免税できますか(면세 되나요)라고 먼저 물어보는 것이 시간을 절약하는 방법입니다.', exampleJa: '免税できますか', exampleKo: '면세 되나요?', action: '계산대에서 여권을 바로 꺼낼 수 있게 미리 손에 들고 계세요.', missionIds: ['C7', 'C40'] },
  { id: 'g_ic_card', category: '여행', tags: ['카드', '수수료', 'IC카드', 'Suica', 'PASMO'], label: 'IC카드(Suica) 한 장', tipKo: '전철·버스·편의점·자판기까지 탭 한 번. 충전은 「チャージ」. 모바일 Suica도 편해요.', detail: 'Suica·PASMO 같은 교통 IC카드 한 장만 있으면 전철·버스 개찰은 물론 편의점·자판기·일부 택시·코인로커 결제까지 탭 한 번으로 해결되어, 매번 잔돈을 세거나 표를 사는 번거로움을 크게 줄여 줍니다. 역 자동발매기나 편의점에서 카드를 구매한 뒤 「チャージ」(충전) 기능으로 원하는 금액을 넣으면 되고, 잔액이 부족하면 개찰구에서 오류가 나므로 이동 전에 미리 충전해 두는 습관이 중요합니다. 최근에는 실물 카드 없이 스마트폰의 모바일 Suica 앱으로도 발급·충전이 가능해, 실물 카드를 잃어버릴 걱정 없이 스마트폰 하나로 여행을 다니는 사람도 늘고 있습니다. 여행이 끝나고 남은 잔액과 보증금은 일부 역의 창구에서 환불받을 수 있지만 수수료가 붙을 수 있으니, 남은 금액을 자판기나 편의점에서 다 쓰고 가는 것도 좋은 방법입니다.', exampleJa: 'チャージしてください', exampleKo: '충전해 주세요.', action: '역 자동발매기에서 「チャージ」 버튼을 찾아 원하는 금액으로 충전하세요.', missionIds: ['C3'] },
  { id: 'g_translate', category: '여행', tags: ['번역앱', '마트', '알레르기', '한자'], label: '막히면 번역앱 카메라', tipKo: '메뉴·간판이 안 읽히면 번역앱 카메라로 비추면 돼요. 그래도 인사·숫자는 입으로 해보는 게 빨라요.', detail: '한자로 빽빽한 메뉴판이나 표지판을 마주쳤을 때, 스마트폰 번역 앱의 카메라 기능으로 화면을 비추기만 하면 실시간으로 번역된 글자가 화면에 겹쳐 보이는 기능은 여행자에게 매우 든든한 안전망입니다. 특히 알레르기 성분이나 재료명처럼 정확도가 중요한 정보를 확인할 때 유용하며, 사진을 찍어 저장해 두면 나중에 다시 찾아볼 수도 있습니다. 다만 번역 앱은 인터넷 연결이 필요하거나 번역 품질이 문맥에 따라 부정확할 수 있어 전적으로 의지하기보다 보조 수단으로 쓰는 것이 좋고, 인사말이나 숫자·개수처럼 짧고 확실한 표현은 오히려 직접 입으로 말하는 것이 더 빠르고 자연스럽게 통합니다. 번역 앱과 기본 회화 표현을 상황에 맞게 섞어 쓰는 균형 감각이 실전에서 가장 중요합니다.', exampleJa: 'これは何ですか', exampleKo: '이게 뭔가요?', action: '번역앱 카메라로 메뉴를 비추고, 먹고 싶은 걸 가리키며 これをください라고 말해 보세요.', missionIds: ['C5', 'C50'] },
  { id: 'g_toilet', category: '여행', tags: ['편의점', '백화점', '한자', '가나', '화장실'], label: '화장실은 깨끗하고 많아요', tipKo: '편의점·역·백화점 화장실이 깨끗해요. 비데 버튼은 おしり(엉덩이)·とめる(정지). 급하면 トイレはどこですか.', detail: '일본은 공중화장실의 청결도가 세계적으로도 높은 편으로 꼽히며, 역·백화점·편의점·공원 등 어디서나 비교적 깨끗한 화장실을 무료로 이용할 수 있어 여행 중 급한 상황에서도 큰 걱정을 덜 수 있습니다. 대부분의 화장실에는 온수 세정 비데(ウォシュレット)가 설치되어 있는데, 버튼에는 보통 おしり(엉덩이 세정)·ビデ(비데, 여성용 세정)·止める(정지) 같은 한자·가나 표기와 그림이 함께 있어 처음 보는 사람도 대략 유추할 수 있습니다. 물 내림 버튼과 세정 버튼의 위치가 헷갈릴 수 있으니 급하게 아무 버튼이나 누르기보다 잠깐 표시를 확인하는 것이 좋고, 최근엔 소리를 가려주는 물소리 재생 버튼(音姫)이 따로 있는 경우도 많습니다. 화장실을 찾을 때는 편의점이나 역이 가장 접근성이 좋고 확실한 선택지입니다.', exampleJa: 'トイレはどこですか', exampleKo: '화장실은 어디에 있나요?', action: '비데 패널에서 おしり(세정)·止める(정지) 버튼 위치를 먼저 확인하세요.' },

  // ── 회화 학습법 ──
  { id: 'g_conversation_shadowing', category: '회화법', tags: ['억양', '따라', '말하기'], label: '듣고 바로 따라 말하기', tipKo: '회화는 눈으로 아는 문장을 입으로 꺼내는 훈련이 핵심입니다. 원음을 듣고 1초 안에 같은 속도로 따라 말하세요.', detail: '섀도잉(shadowing)은 원어민 음성을 듣자마자 거의 동시에 같은 속도와 억양으로 따라 말하는 훈련법으로, 통역사 양성 과정에서도 널리 쓰일 만큼 회화 실력 향상에 효과가 검증된 방법입니다. 눈으로 문장을 읽고 "이해했다"고 느끼는 것과 실제로 그 속도로 입 밖에 소리 내어 말할 수 있는 것 사이에는 큰 차이가 있는데, 섀도잉은 바로 이 간극을 좁혀 줍니다. 화면의 글자를 보면서 따라 하면 결국 읽기 연습이 되어버리므로, 가능하면 소리만 듣고 화면은 보지 않은 채 따라 말하는 것이 진짜 듣기·말하기 근육을 단련하는 방법입니다. 처음에는 속도를 따라가기 벅차더라도, 짧은 문장부터 여러 번 반복하다 보면 리듬과 억양이 몸에 붙어 실제 대화에서도 자연스럽게 튀어나오게 됩니다.', action: '세션의 듣기 버튼을 누른 뒤 화면을 보지 않고 한 번 더 따라 말해 보세요.' },
  { id: 'g_conversation_chunk', category: '회화법', tags: ['조사', '덩어리', '외우기'], label: '단어보다 덩어리로 외우기', tipKo: '실전에서는 문법을 조립할 시간이 없습니다. 「〜お願いします」「〜ありますか」처럼 바로 붙여 쓰는 덩어리로 저장하세요.', detail: '실전 대화에서는 머릿속으로 조사를 고르고 동사를 활용하며 문법을 하나씩 조립할 시간이 없기 때문에, 단어 단위가 아니라 자주 쓰이는 표현을 하나의 덩어리(청크, chunk)로 통째로 암기하는 것이 훨씬 실용적입니다. 예를 들어 「〜お願いします」나 「〜はありますか」 같은 틀을 하나의 완성된 단위로 기억해 두면, 실제로는 앞의 명사만 상황에 맞게 바꿔 끼우는 것만으로 수십 가지 문장을 즉석에서 만들어낼 수 있습니다. 이런 방식은 문법 규칙을 순간적으로 떠올려 조합하는 것보다 훨씬 빠르고 실수도 적어, 여행처럼 즉각적인 반응이 필요한 상황에 특히 유리합니다. 하나의 틀을 익혔다면 그 틀에 다른 명사를 넣어 여러 번 소리 내어 말해 보는 연습을 통해, 문형 자체를 반사적으로 쓸 수 있는 수준까지 끌어올리는 것이 목표입니다.', exampleJa: 'Mサイズはありますか', exampleKo: 'M 사이즈 있나요?', action: '명사만 바꿔 같은 틀로 세 번 말해 보세요.' },
  { id: 'g_conversation_roleplay', category: '회화법', tags: ['역할극'], label: '혼잣말보다 역할극', tipKo: '혼자 문장을 읽는 것보다 상대 질문을 듣고 바로 답하는 연습이 회화에 더 가깝습니다.', detail: '실제 대화는 내가 하고 싶은 말을 일방적으로 늘어놓는 것이 아니라, 상대의 말을 듣고 그에 맞춰 즉각 반응하는 쌍방향 과정입니다. 그래서 내가 할 말만 외워 혼자 읽는 연습은 실전 회화력과는 다소 거리가 있으며, 정작 현장에서는 점원이나 직원이 무슨 말을 하는지 못 알아들어 멈춰버리는 경우가 많습니다. 역할극 방식으로 상대방의 질문이나 대사까지 함께 소리 내어 읽고 그 흐름 안에서 내 대답을 떠올리는 연습을 하면, 실제 대화의 리듬과 순서 감각을 자연스럽게 익힐 수 있습니다. 특히 점원의 질문 패턴은 정해진 몇 가지 유형이 반복되는 경우가 많으므로, 상대 대사를 미리 여러 번 들어 익숙해지는 것만으로도 실전에서 당황하는 빈도를 크게 줄일 수 있습니다.', commonMistake: '내가 말할 문장만 외우면 실제 질문을 못 알아듣고 멈추기 쉬워요.', action: '대화 다시보기에서 상대 일본어 질문까지 소리 내어 읽어 보세요.' },
  { id: 'g_conversation_recovery', category: '회화법', tags: ['방언', '막히면', '복구문'], label: '막히면 복구문부터', tipKo: '잘하는 사람도 못 알아듣는 순간이 있습니다. 중요한 건 멈추지 않고 다시 말하기·천천히·쉬운 일본어로 우회하는 것입니다.', detail: '아무리 일본어를 잘하는 사람이라도 방언, 빠른 말투, 낯선 단어 때문에 순간적으로 못 알아듣는 상황은 반드시 생깁니다. 진짜 실력 차이는 이런 순간에 당황해서 대화를 완전히 멈춰버리느냐, 아니면 자연스럽게 되묻고 우회해서 대화를 계속 이어가느냐에서 드러납니다. もう一度お願いします(다시 한번 부탁합니다)、ゆっくりお願いします(천천히 부탁합니다)、やさしい日本語でお願いします(쉬운 일본어로 부탁합니다) 같은 몇 가지 복구 표현만 반사적으로 나올 수 있게 익혀두면, 이해하지 못한 순간에도 대화의 주도권을 잃지 않고 필요한 정보를 다시 얻어낼 수 있습니다. 이 복구 표현들은 단순한 비상용이 아니라, 실전 회화에서 자연스러운 대화 흐름을 만드는 핵심 기술로 여겨야 합니다.', exampleJa: 'ゆっくりお願いします', exampleKo: '천천히 부탁합니다.', action: '문제 하단의 복구 액션을 눌러 표현을 확인하고 입으로 다시 말하세요.' },
  { id: 'g_conversation_my_case', category: '회화법', tags: ['호텔', '여행', '상황', '바꾸기'], label: '내 여행 상황으로 바꾸기', tipKo: '회화 실력은 내 상황을 말할 때 늘어납니다. 앱 문장을 그대로 끝내지 말고 내 호텔·역·가게 이름으로 바꿔 보세요.', detail: '앱에서 제시하는 예문을 그대로 외워 반복하는 것도 기초를 다지는 데는 도움이 되지만, 진짜 회화 실력은 그 문형을 내 실제 상황에 대입해 스스로 문장을 만들어 볼 때 눈에 띄게 늘어납니다. 예를 들어 「〜までお願いします(~까지 부탁합니다)」라는 틀을 배웠다면, 예시로 나온 지명 대신 내가 실제로 묵는 호텔 이름이나 오늘 갈 역 이름을 넣어 소리 내어 말해 보는 것입니다. 이렇게 하면 단순 암기를 넘어 그 문형이 "내 것"이 되어, 비슷한 상황을 실제로 마주쳤을 때 훨씬 자연스럽고 빠르게 튀어나오게 됩니다. 학습한 표현을 오늘 하루의 실제 일정과 연결해 한 문장이라도 스스로 만들어 보는 습관을 들이면, 여행 기간 내내 회화 실력이 꾸준히 쌓이는 것을 체감할 수 있습니다.', action: '오늘 실제로 갈 장소 하나를 넣어 「〜までお願いします」를 만들어 보세요.' },

  // ── 확장 장면 실전 팁 ──
  { id: 'g_coin_locker', category: '장면', tags: ['현금', '카드', '영수증', 'IC카드', 'Suica'], label: '코인로커는 크기별 요금', tipKo: '로커는 小(しょう)·中(ちゅう)·大(だい) 순으로 요금이 오르고, 현금 외에 IC카드(Suica·PASMO) 결제가 되는 곳도 많아요. 역 로커는 매진되기 쉬우니 개찰구 안팎을 모두 확인하세요.', detail: '역이나 관광지의 코인로커는 크기가 小(소)·中(중)·大(대) 세 단계로 나뉘며, 캐리어가 클수록 大 사이즈가 필요하고 그만큼 요금도 올라갑니다. 예전에는 동전만 넣는 방식이 많았지만 최근에는 Suica·PASMO 같은 IC카드로 결제하고, 반납할 때도 같은 카드를 태그해 여는 방식이 늘고 있어 잔돈이 없어도 이용하기 편리해졌습니다. 관광 성수기나 대형 역에서는 로커가 금방 다 차버리는 경우가 흔하므로, 개찰구 안쪽뿐 아니라 바깥쪽 로커까지 함께 살펴보면 빈 로커를 찾을 확률이 높아집니다. 일부 로커는 그날 막차 시간까지만 짐을 꺼낼 수 있도록 운영 시간이 제한되어 있으므로, 짐을 넣을 때 로커 번호와 비밀번호(또는 영수증)를 반드시 사진으로 찍어 두고 이용 가능 시간도 함께 확인해 두는 것이 안전합니다.', exampleJa: '大きいのでお願いします', exampleKo: '큰 걸로 부탁해요.', commonMistake: '막차 전까지만 꺼낼 수 있는 로커도 있어 이용 시간 확인을 놓치기 쉬워요.', action: '짐을 넣기 전에 로커 번호와 비밀번호를 메모해 두세요.', missionIds: ['C11'] },
  { id: 'g_cafe', category: '장면', tags: ['카페', '주문', '크기'], label: '카페 주문은 크기부터', tipKo: '체인 카페에서는 음료 뒤에 크기와 뜨거움·차가움을 연달아 물을 수 있어요.', detail: '스타벅스나 도토루 같은 체인 카페에서는 음료 이름을 말한 직후 점원이 사이즈(S·M·L 또는 톨·그란데 등), 온도(뜨거운지 차가운지), 시럽이나 우유 종류 같은 옵션을 연달아 빠르게 물어보는 경우가 많아, 처음 주문하는 사람은 질문 폭탄에 당황하기 쉽습니다. 이럴 때는 질문을 한 번에 다 이해하려 하지 말고, 하나씩 끊어서 짧게 はい(네)로 답하거나 잘 못 들었으면 ゆっくりお願いします(천천히 부탁합니다)라고 요청하며 페이스를 조절하는 것이 훨씬 편합니다. 매장에서 먹을지(店内) 포장할지(お持ち帰り)를 먼저 물어보는 경우도 많으므로, 이 두 단어만 미리 알아두어도 대화의 흐름을 예측하기 쉬워집니다. 메뉴판의 사진이나 번호를 손가락으로 가리키며 これを一つお願いします라고 말하는 것만으로도 충분히 주문이 가능하니 부담을 가질 필요는 없습니다.', exampleJa: 'これを一つお願いします', exampleKo: '이거 하나 부탁합니다.', action: '못 들으면 질문마다 はい 또는 ゆっくりお願いします로 끊어 답하세요.', missionIds: ['C14', 'C45'] },
  { id: 'g_bakery', category: '장면', tags: ['한자', '빵집', '트레'], label: '빵집은 트레이와 집게', tipKo: '대부분 직접 담은 뒤 계산대로 가져갑니다.', detail: '일본의 동네 빵집이나 베이커리 카페는 입구 근처에 쟁반(トレイ)과 집게(トング), 빵을 담을 봉투가 비치되어 있어, 손님이 직접 원하는 빵을 골라 담은 뒤 계산대로 가져가는 셀프 방식이 일반적입니다. 빵 이름표에 적힌 한자를 다 몰라도 괜찮은데, 눈으로 보고 마음에 드는 것을 집게로 집어 쟁반에 올리기만 하면 되는 시각적으로 직관적인 구조이기 때문입니다. 계산대에서는 쟁반째로 건네면 점원이 하나씩 개수를 세어 계산해 주며, 이때 이거와 이거를 더 달라고 하고 싶다면 これとこれをお願いします라고 가리키며 말하면 충분히 통합니다. 인기 있는 빵집은 특정 시간대에 갓 구운 빵이 나오는 경우가 많으므로, 아침 일찍 방문하면 더 다양한 종류를 고를 수 있습니다.', exampleJa: 'これとこれをお願いします', exampleKo: '이거와 이거 부탁합니다.', action: '빵 이름을 몰라도 가리키며 개수를 말하면 충분해요.', missionIds: ['C15'] },
  { id: 'g_izakaya', category: '장면', tags: ['이자카야', 'お通し'], label: '이자카야의 お通し', tipKo: '주문하지 않은 작은 안주가 나오고 자리 요금처럼 계산되는 가게가 있어요.', detail: '이자카야에 자리를 잡고 앉으면 주문하지 않았는데도 작은 안주 한 접시가 먼저 나오는 경우가 있는데, 이를 お通し(오토시) 또는 관서 지방에서는 突き出し(쓰키다시)라고 부릅니다. 이는 자릿세 개념을 겸한 관행으로, 대부분의 가게에서 이 안주에 대해 별도의 자리 요금(席料)이 계산서에 함께 청구되므로 무료 서비스로 착각하지 않는 것이 중요합니다. 금액은 보통 300~500엔 정도로 크지 않지만, 처음 겪는 여행자는 시키지 않은 음식에 비용이 청구된 것을 보고 당황하는 경우가 많아 미리 알아두면 마음이 훨씬 편합니다. 이 관행이 궁금하거나 확인하고 싶다면 직원에게 これは何ですか(이건 뭔가요)라고 물어보면 친절하게 설명해 주는 경우가 대부분입니다.', commonMistake: '무료 서비스라고 생각하기 쉬워요.', action: '궁금하면 これは何ですか라고 물어보세요.', missionIds: ['C16'] },
  { id: 'g_sushi', category: '장면', tags: ['스시', '알레르기', '발음', '먼저'], label: '스시 알레르기는 먼저', tipKo: '알레르기나 못 먹는 재료는 주문 전에 먼저 알리는 것이 안전합니다.', detail: '스시는 재료가 매우 다양하고 하나의 요리 안에 여러 해산물·소스가 결합되는 경우가 많아, 알레르기가 있거나 특정 재료를 못 먹는 경우 주문 전에 반드시 먼저 알리는 것이 안전합니다. 특히 새우·게 같은 갑각류, 계란, 참깨처럼 눈에 잘 띄지 않게 들어가는 재료도 있어, "이 메뉴에는 없겠지"라고 짐작하기보다 직접 확인하는 습관이 중요합니다. アレルギーがあります(알레르기가 있습니다)라는 표현 뒤에 구체적인 재료명(えび=새우, かに=게 등)을 붙여 말하면 훨씬 정확하게 전달되고, 발음이 걱정되면 알레르기 항목이 적힌 메모나 번역 앱 화면을 함께 보여주는 것도 효과적입니다. 오마카세처럼 셰프가 알아서 재료를 정해 내어주는 형식에서는 특히 사전에 알리는 것이 중요한데, 미리 말해두면 대부분의 가게에서 해당 재료를 빼고 다른 것으로 대체해 줍니다.', exampleJa: 'アレルギーがあります', exampleKo: '알레르기가 있습니다.', action: '재료 사진이나 번역 화면도 함께 보여주세요.', missionIds: ['C17', 'C38', 'C49'] },
  { id: 'g_tourist_info', category: '장면', tags: ['전철', '버스', '기차', '숙소', '마트'], label: '관광안내소를 활용하기', tipKo: '지도·행사·교통 정보를 한 번에 얻기 좋은 장소입니다.', detail: '기차역이나 관광지 입구에 있는 관광안내소(観光案内所)는 무료 지도, 현재 진행 중인 축제나 행사 정보, 버스·전철 환승 정보, 근처 맛집·숙소 추천까지 한 자리에서 얻을 수 있는 여행자의 첫 정거장 같은 곳입니다. 영어나 한국어가 가능한 직원이 배치된 곳도 많고, 그렇지 않더라도 지도나 팸플릿을 손으로 가리키며 소통할 수 있어 언어 장벽이 상대적으로 낮은 편입니다. 특히 스마트폰 검색으로는 놓치기 쉬운 그 지역만의 계절 행사나 임시 교통편 정보를 얻을 수 있어, 여행 계획을 짤 때 가장 먼저 들러볼 만한 장소로 꼽힙니다. 가고 싶은 장소가 있다면 스마트폰 지도 화면을 보여주며 여기는 어디인지, 어떻게 가는지 물어보면 대부분 친절하게 경로를 안내해 줍니다.', exampleJa: 'ここはどこですか', exampleKo: '여기는 어디예요?', action: '가고 싶은 장소 화면을 보여주며 길을 물어보세요.', missionIds: ['C18'] },
  { id: 'g_shrine', category: '장면', tags: ['신사', '참배', '한자', '촬영', '금지'], label: '촬영 금지 표시 확인', tipKo: '신사·절 내부 일부 공간은 촬영이 금지될 수 있습니다.', detail: '신사(神社)와 절(寺)은 종교적 공간이기 때문에 본전 내부, 불상, 특정 문화재 등 일부 구역은 촬영이 금지되어 있는 경우가 많으며, 이는 신앙적 이유뿐 아니라 문화재 보호 목적도 함께 있습니다. 촬영 가능 여부는 보통 撮影禁止(촬영 금지)라는 한자 표지판이나 카메라에 X표시가 된 그림으로 안내되어 있어, 한자를 몰라도 그림만으로 어느 정도 판단할 수 있습니다. 명확한 표지가 안 보이는 애매한 공간에서는 직원이나 스님에게 写真を撮ってもいいですか(사진 찍어도 되나요)라고 먼저 물어보는 것이 실례를 피하는 가장 확실한 방법입니다. 참배객들이 기도하는 모습을 가까이서 촬영하는 것도 예의에 어긋날 수 있으니, 사람이 붐비는 시간대에는 특히 주변을 배려하며 카메라를 드는 것이 좋습니다.', exampleJa: '写真を撮ってもいいですか', exampleKo: '사진 찍어도 되나요?', action: '撮影禁止 표지가 보이면 카메라를 넣으세요.', missionIds: ['C19'] },
  { id: 'g_onsen', category: '장면', tags: ['온천', '매너', '들어가기'], label: '온천은 씻고 들어가기', tipKo: '탕에 들어가기 전에 몸을 씻고, 수건은 탕 안에 넣지 않습니다.', detail: '일본 온천 문화에서 가장 중요한 규칙은 탕에 들어가기 전 반드시 몸을 깨끗이 씻는 것으로, 이는 공동으로 사용하는 탕의 물을 청결하게 유지하기 위한 배려에서 비롯된 관행입니다. 탈의실에서 옷을 벗고 세신 공간에서 비누·샴푸로 몸을 씻은 뒤에야 탕에 들어가는 것이 순서이며, 이를 건너뛰고 바로 탕에 들어가는 것은 큰 실례로 여겨집니다. 몸의 물기를 닦는 작은 수건은 탕 안에 담그지 않고 머리 위에 올려두거나 탕 밖에 두는 것이 일반적인 매너입니다. 시설에 따라 문신이 있으면 입장이 제한되거나 전용 스티커로 가려야 하는 곳도 있고, 남녀 혼탕이 아닌 이상 수영복 착용이 금지된 곳이 대부분이므로, 입구에 붙은 이용 규칙 안내를 미리 확인해 두는 것이 좋습니다.', action: '시설별 문신·수영복 규칙은 입구 안내를 확인하세요.', missionIds: ['C20'] },
  { id: 'g_ryokan', category: '장면', tags: ['료칸', '호텔', '체크인', '숙소', '알레르기'], label: '료칸 식사 시간 확인', tipKo: '석식·조식 시간이 정해진 숙소가 많아 체크인 때 확인해야 합니다.', detail: '전통 료칸은 대부분 가이세키 요리처럼 여러 코스로 구성된 저녁·아침 식사를 제공하는데, 이 식사는 정해진 시간대에 맞춰 주방에서 정성껏 준비되기 때문에 호텔 레스토랑처럼 아무 때나 자유롭게 이용할 수 없는 경우가 많습니다. 체크인할 때 프런트에서 석식·조식 시간을 미리 정하거나 안내받게 되므로, 이 시간을 놓치지 않도록 그날의 일정을 역산해서 짜는 것이 중요합니다. 관광지에서 늦게 돌아오게 될 것 같다면 체크인 시점에 미리 시간을 조정하거나, 늦을 것 같다고 숙소에 미리 연락해 두는 것이 매너이자 실용적인 대처법입니다. 아침 식사 시간이 궁금하다면 朝食は何時ですか(조식은 몇 시예요)라고 물어보면 되고, 알레르기나 못 먹는 음식이 있다면 이때 함께 알려두는 것이 좋습니다.', exampleJa: '朝食は何時ですか', exampleKo: '조식은 몇 시예요?', action: '도착이 늦으면 미리 숙소에 연락하세요.', missionIds: ['C21'] },
  { id: 'g_bus', category: '장면', tags: ['카드', 'IC카드', '버스', '도쿄'], label: '버스 승하차 방식 확인', tipKo: '지역에 따라 앞문·뒷문 승차와 선불·후불 방식이 다릅니다.', detail: '일본의 노선버스는 지역마다 승하차 방식과 요금 지불 방식이 서로 달라, 도쿄처럼 앞문으로 타면서 정액 요금을 먼저 내는 선불식 지역이 있는가 하면, 지방 도시에서는 뒷문으로 타면서 정리권(整理券)을 뽑고 내릴 때 거리에 따라 달라지는 요금을 계산하는 후불식 지역도 많습니다. 이 방식을 모르고 탑승하면 순서가 뒤바뀌어 당황하기 쉬우므로, 처음 타는 노선이라면 반드시 앞사람들이 어느 문으로 타고 어떻게 요금을 내는지부터 관찰하는 것이 가장 빠르고 확실한 방법입니다. IC카드를 사용할 경우에도 탑승 시와 하차 시 각각 태그해야 하는 단말기 위치가 문 앞뒤로 다르게 배치되어 있을 수 있어, 카드 리더기가 어디 있는지 미리 눈으로 확인해 두면 당황하지 않습니다. 확신이 서지 않으면 기사에게 직접 물어보거나 다른 승객의 행동을 따라 하는 것이 가장 안전합니다.', action: '앞사람의 행동과 교통카드 단말 위치를 먼저 보세요.', missionIds: ['C22'] },
  { id: 'g_shinkansen', category: '장면', tags: ['신칸센', '예약', '승차권', '특급권'], label: '신칸센 표는 두 장일 수 있어요', tipKo: '승차권과 특급권이 따로 나오는 경우가 있습니다.', detail: '신칸센을 이용할 때는 일반 열차와 달리 기본 구간 요금에 해당하는 승차권(乗車券)과, 신칸센 등 특급 열차 이용에 대한 추가 요금인 특급권(特急券)이 별도의 두 장으로 발권되는 경우가 흔합니다. 자동발매기나 창구에서 한 번에 발권해 주더라도 실물 표는 두 장으로 나오는 것이 일반적이라, 개찰구를 통과할 때 두 장을 한꺼번에 함께 투입구에 넣거나 겹쳐서 태그해야 합니다. 이 구조를 모르면 개찰구에서 표 한 장만 챙기고 나머지 한 장을 두고 나오는 실수를 하기 쉬운데, 이후 검표원이 표를 확인할 때 특급권이 없으면 문제가 될 수 있습니다. 개찰구를 통과한 뒤에는 반드시 배출되는 표를 전부 다시 확인해서 챙기는 습관을 들이는 것이 좋고, 지정석 예약을 했다면 좌석 번호가 적힌 표까지 총 세 장이 될 수도 있다는 점도 기억해 두세요.', commonMistake: '개찰구에서 표 한 장을 빼먹기 쉬워요.', action: '개찰구에서 나온 표를 모두 다시 챙기세요.', missionIds: ['C23'] },
  { id: 'g_rental', category: '장면', tags: ['현금', '카드', '영수증', '렌터카', '고속도로'], label: '렌터카 반납 전 주유', tipKo: '대부분 가득 주유해 반납하고 영수증을 확인받습니다.', detail: '일본에서 렌터카를 반납할 때는 대부분 연료를 가득 채운 상태(満タン)로 돌려주는 것이 계약 조건이며, 주유소에서 만탄으로 채웠다는 영수증을 반드시 챙겨서 반납 시 제출해야 추가 연료비를 청구받지 않습니다. 이를 깜빡하고 연료가 부족한 채로 반납하면 렌터카 회사가 시중가보다 훨씬 비싼 단가로 정산하는 경우가 많아, 반납 직전 근처 주유소에 들르는 일정을 여유 있게 잡아두는 것이 중요합니다. 출발 전에는 내비게이션 언어를 한국어나 영어로 바꿀 수 있는지, 사고나 파손 시 보험 보장 범위가 어디까지인지(면책 보상 제도 포함)를 직원에게 꼼꼼히 확인해 두는 것이 좋습니다. 고속도로 통행료 자동 결제 장치인 ETC 카드 대여 여부도 함께 확인해 두면 통행료를 매번 현금으로 낼 필요가 없어 훨씬 편리합니다.', action: '내비게이션 언어와 보험 범위를 출발 전에 확인하세요.', missionIds: ['C24'] },
  { id: 'g_hospital', category: '장면', tags: ['알레르기', '발음', '증상'], label: '병원에서는 증상을 짧게', tipKo: '아픈 위치·언제부터·알레르기 순서로 보여주면 전달이 빨라집니다.', detail: '해외에서 갑자기 몸이 아플 때는 복잡한 문장을 만들려 하기보다, 아픈 부위·언제부터 아팠는지·특정 약이나 음식에 알레르기가 있는지 세 가지 정보를 짧게 순서대로 전달하는 것이 진료를 훨씬 빠르게 받는 방법입니다. お腹が痛いです(배가 아파요)처럼 아픈 부위와 症状(증상)을 명사로 짧게 말하고, 언제부터인지는 손가락으로 숫자를 세거나 きのうから(어제부터)처럼 간단한 시간 표현을 붙이는 것만으로 충분합니다. 알레르기나 복용 중인 약이 있다면 반드시 미리 말해야 하는데, 발음이 걱정되면 번역 앱이나 메모에 적어 보여주는 것도 좋은 방법입니다. 여행자 보험에 가입되어 있다면 여권과 함께 보험 증서나 관련 앱을 미리 준비해 가면 병원비 청구나 통역 서비스 연결이 훨씬 수월해집니다.', exampleJa: 'お腹が痛いです', exampleKo: '배가 아파요.', action: '여권과 여행자 보험 정보를 준비하세요.', missionIds: ['C25'] },
  { id: 'g_police', category: '장면', tags: ['마트', '분실물', '경찰', '交番'], label: '분실물은 交番으로', tipKo: '작은 파출소인 交番에서 길 안내와 분실 신고 도움을 받을 수 있습니다.', detail: '일본 전역, 특히 역 주변이나 번화가에는 交番(고반)이라 불리는 작은 파출소가 촘촘히 배치되어 있어, 길을 잃었거나 물건을 잃어버렸을 때 가장 먼저 찾아가기 좋은 곳입니다. 큰 경찰서와 달리 동네 단위로 배치된 소규모 지구대 개념이라 접근성이 좋고, 지리에 밝은 경찰관이 상주하고 있어 길 안내나 분실물 신고 접수를 편하게 받을 수 있습니다. 실제로 일본은 분실물이 신고를 통해 주인에게 돌아오는 비율이 높은 편으로 알려져 있어, 지갑이나 휴대폰을 잃어버렸을 때도 포기하지 말고 가까운 交番에 신고해 두는 것이 좋습니다. 위급한 상황이라면 助けてください(도와주세요)라는 표현을 먼저 말하고, 분실한 장소와 대략적인 시간을 스마트폰 지도나 시계 화면으로 보여주면 훨씬 정확하게 상황을 전달할 수 있습니다.', exampleJa: '助けてください', exampleKo: '도와주세요.', action: '분실 장소와 시간을 지도에 표시해 보여주세요.', missionIds: ['C26'] },
  { id: 'g_emergency', category: '장면', tags: ['응급', '경찰', '긴급전화', '110', '119'], label: '긴급전화 110·119', tipKo: '경찰은 110, 구급·소방은 119입니다.', detail: '일본의 긴급 신고 전화번호는 용도에 따라 두 가지로 나뉘는데, 범죄 신고나 사건·사고와 관련된 경찰 출동은 110번, 화재나 응급 환자 이송이 필요한 구급·소방 상황은 119번으로 걸어야 합니다. 이 두 번호는 공중전화에서도 무료로 걸 수 있고 휴대폰으로도 바로 연결되지만, 실제로 생명이 위급하거나 범죄가 발생한 경우가 아니라면 단순한 길 문의나 불편 신고 등에는 사용하지 않는 것이 원칙입니다. 긴급하지 않은 상황에 이 번호로 전화하면 정작 필요한 사람에게 갈 대응이 늦어질 수 있어 사회적으로도 자제가 요구됩니다. 만약 전화를 걸게 된다면 먼저 자신의 현재 위치와 상황(부상 여부, 화재 여부 등)을 최대한 침착하게 말하고, 일본어가 어렵다면 통역이 필요하다는 뜻을 통역をお願いします라고 전달하면 통역 서비스로 연결해 주는 경우가 많습니다.', commonMistake: '긴급하지 않은 문의에 사용하면 대응을 방해합니다.', action: '위치와 상태를 먼저 말하고 통역을 요청하세요.', missionIds: ['C27'] },
  { id: 'g_sim', category: '장면', tags: ['공항', 'eSIM', '신사', '유심', '호환성'], label: '유심은 호환성 확인', tipKo: '구매 전에 휴대폰 잠금 해제 여부와 지원 주파수를 확인해야 합니다.', detail: '일본에서 현지 유심을 구매하기 전에는 반드시 자신의 휴대폰이 SIM 잠금 해제(SIMフリー) 상태인지, 그리고 일본 통신사가 사용하는 주파수 대역을 지원하는지 미리 확인해야 합니다. 해외에서 구매한 휴대폰이거나 통신사 약정이 남아 있는 기기는 다른 통신사의 유심을 인식하지 못하도록 잠겨 있는 경우가 있어, 매장에서 유심을 구매해도 개통이 되지 않는 낭패를 볼 수 있습니다. 매장 직원에게 도움을 받아 유심을 넣은 즉시 인터넷 연결과 통화가 정상적으로 되는지 그 자리에서 확인하는 것이 중요하며, 문제가 있다면 매장을 나서기 전에 바로 해결하는 것이 나중에 다시 찾아오는 수고를 더는 방법입니다. 최근에는 실물 유심 없이 QR코드로 등록하는 eSIM 방식도 늘고 있어, 기기가 지원한다면 공항 도착 전에 미리 온라인으로 준비해 두는 것도 좋은 선택입니다.', action: '개통 확인 후 매장을 나가세요.', missionIds: ['C28'] },
  { id: 'g_laundry', category: '장면', tags: ['세제', '자동', '투입', '확인'], label: '세제 자동 투입 확인', tipKo: '코인세탁기는 세제가 자동 투입되는 기계가 많습니다.', detail: '일본의 코인 세탁소(コインランドリー)에 있는 세탁기는 상당수가 세제와 섬유유연제를 기계가 자동으로 투입해 주는 방식(洗剤自動投入)으로 되어 있어, 이용자가 직접 세제를 넣지 않아도 되는 경우가 많습니다. 이 사실을 모르고 습관적으로 개인 세제를 추가로 넣으면 세제가 이중으로 들어가 거품이 과도하게 생기고, 심하면 세탁기 밖으로 거품이 넘쳐 고장이나 오작동의 원인이 되기도 합니다. 세탁기를 이용하기 전에 기계 표면이나 안내문에 洗剤自動投入(세제 자동 투입)이라는 문구가 있는지부터 확인하는 것이 첫 단계이며, 표시가 없는 구형 기계라면 별도로 세제 투입구가 있는지 살펴봐야 합니다. 사용법이 헷갈리면 사용법을 알려 달라는 뜻으로 使い方を教えてください라고 물어보면, 근처에 있는 다른 이용객이나 관리인이 도움을 주는 경우도 많습니다.', commonMistake: '세제를 중복으로 넣으면 거품이 과해질 수 있어요.', action: '洗剤自動投入 표시를 먼저 찾으세요.', missionIds: ['C29'] },
  { id: 'g_festival', category: '장면', tags: ['현금', '카드', 'IC카드', '동전', '마츠리'], label: '축제는 현금이 편해요', tipKo: '노점은 현금만 받는 곳이 많고 쓰레기통이 적을 수 있습니다.', detail: '일본의 마츠리(祭り)에서 늘어선 야타이(포장마차·노점)들은 개인이 운영하는 소규모 노점이 대부분이라 카드나 IC카드 결제를 지원하지 않고 현금만 받는 곳이 여전히 많습니다. 축제 특유의 활기찬 분위기 속에서 결제 수단이 없어 먹고 싶은 음식을 못 사 먹는 상황을 피하려면, 미리 동전과 천엔권을 넉넉히 준비해 가는 것이 좋습니다. 또한 축제 현장은 인파에 비해 쓰레기통이 충분히 배치되지 않은 경우가 많아, 다 먹은 꼬치나 포장지를 들고 다니다가 지정된 쓰레기통을 찾아 버려야 하는 상황이 자주 생깁니다. 작은 비닐봉지를 하나 챙겨 다니면 임시로 쓰레기를 담아두기 편하고, 축제가 끝난 뒤 주변을 정리하는 것도 현지인들이 중요하게 여기는 매너 중 하나입니다.', action: '동전과 작은 봉투를 준비하면 편해요.', missionIds: ['C30'] },
  { id: 'g_kaiten_sushi_panel', category: '장면', tags: ['초밥', '회전초밥', '패널'], label: '회전초밥은 패널부터', tipKo: '회전초밥집은 터치패널 주문, 접시 색상별 가격, 마지막 계산 버튼을 차례로 확인하면 덜 당황합니다.', detail: '요즘 회전초밥집은 레일 위를 도는 초밥을 직접 집는 방식과 함께, 테이블에 설치된 터치패널로 원하는 메뉴를 주문해 레일이나 별도 라인으로 받는 방식을 함께 운영하는 경우가 많습니다. 접시는 색상이나 무늬에 따라 가격이 다르게 책정되어 있어, 앉자마자 벽에 붙은 가격표로 접시별 금액부터 확인해 두면 계산할 때 놀라는 일을 줄일 수 있습니다. 다 먹은 뒤에는 접시를 그대로 쌓아두면 되는 곳도 있고, 접시 개수를 세는 투입구가 따로 있는 곳도 있으며, 마지막에는 터치패널의 계산 버튼을 눌러 직원을 부르거나 셀프 계산대로 이동해야 하는 경우가 많습니다. 처음 방문하는 가게라면 자리에 앉자마자 터치패널의 언어 설정(한국어 지원 여부)과 계산 버튼의 위치부터 확인해 두면, 식사 내내 훨씬 여유롭게 즐길 수 있습니다.', exampleJa: '使い方を教えてください', exampleKo: '사용법을 알려 주세요.', action: '입장하면 먼저 언어 설정과 계산 버튼 위치를 봐 두세요.', missionIds: ['C31'] },
  { id: 'g_fitting_room', category: '장면', tags: ['장마', '피팅룸', '한마디', '먼저'], label: '피팅룸은 한마디 먼저', tipKo: '일본 옷가게는 피팅룸 전용 안내가 있을 수 있어요. 입어보기 전 試着してもいいですか 한마디가 안전합니다.', detail: '일본 옷가게에서는 매장마다 피팅룸 이용 규칙이 조금씩 달라, 입장 시 개수 제한 번호표를 받아야 하거나 직원에게 먼저 말해야만 입장이 허용되는 곳도 있습니다. 이런 규칙을 모르고 마음대로 피팅룸에 들어가면 직원이 당황하거나 제지하는 경우가 있으므로, 입어보기 전에 항상 試着してもいいですか(입어 봐도 돼요)라는 한마디로 먼저 허락을 구하는 것이 안전합니다. 이 표현을 건네면 대부분의 직원이 자연스럽게 사이즈와 원하는 색상을 함께 물어봐 주므로, 이 기회에 M사이즈는 있는지, 다른 색상은 없는지도 함께 물어보면 쇼핑이 훨씬 수월해집니다. 피팅룸에 들어갈 때 신발을 벗어야 하는 매장도 있으니, 안내에 따라 입구에 놓인 슬리퍼로 갈아 신는 것도 잊지 마세요.', exampleJa: '試着してもいいですか', exampleKo: '입어 봐도 돼요?', action: '직원에게 사이즈와 색상을 함께 물어보세요.', missionIds: ['C32'] },
  { id: 'g_hotel_umbrella', category: '장면', tags: ['호텔', '체크아웃', '편의점', '우산'], label: '호텔 우산은 프런트에', tipKo: '비 오는 날 호텔 프런트에서 우산을 빌릴 수 있는 경우가 많습니다. 반납 위치와 시간만 확인하면 됩니다.', detail: '일본은 갑자기 비가 내리는 날이 잦은데, 많은 호텔이 투숙객을 위해 프런트에 대여용 우산을 비치해 두고 있어 굳이 편의점에서 새 비닐우산을 사지 않아도 되는 경우가 많습니다. 대여 방식은 무료로 빌려주고 체크아웃 전까지만 반납하면 되는 곳도 있고, 소정의 보증금을 받았다가 반납 시 돌려주는 곳도 있으므로 빌릴 때 반납 기한과 장소를 함께 확인해 두는 것이 좋습니다. 외출 전 프런트에 傘ありますか(우산 있나요)라고 물어보면 대부분 흔쾌히 빌려주며, 표현이 어렵다면 傘を借りられますか(우산을 빌릴 수 있나요)처럼 조금 더 정중한 형태로 물어봐도 좋습니다. 만약 프런트에 우산이 다 나가고 없다면, 근처 편의점에서 비닐우산을 저렴하게 구매할 수 있다는 점도 함께 기억해 두세요.', exampleJa: '傘を借りられますか', exampleKo: '우산을 빌릴 수 있나요?', action: '외출 전 프런트에서 傘ありますか라고 물어보세요.', missionIds: ['C33'] },
  { id: 'g_room_change', category: '장면', tags: ['호텔', '객실', '변경', '이유'], label: '객실 변경은 이유를 짧게', tipKo: '냄새·소음·침대 타입 문제는 길게 설명하지 말고 이유와 원하는 방을 짧게 말하면 처리하기 쉽습니다.', detail: '호텔 객실에 문제가 있어 방을 바꾸고 싶을 때는, 상황을 장황하게 설명하려 하기보다 문제의 핵심 단어와 원하는 조건을 짧고 명확하게 전달하는 것이 훨씬 빠르게 처리됩니다. 담배 냄새가 난다면 たばこのにおい, 방이 너무 좁다면 部屋が狭い, 트윈 침대로 바꾸고 싶다면 ツインベッド처럼 핵심 명사만 짚어 말해도 프런트 직원은 충분히 상황을 이해하고 대응해 줍니다. 部屋を変えられますか(방을 바꿀 수 있나요)라는 기본 문장 뒤에 이런 핵심 단어를 붙이기만 해도 요청이 명확하게 전달되며, 굳이 복잡한 문장으로 사정을 설명하려다 오히려 의사소통이 꼬이는 것을 피할 수 있습니다. 객실 변경은 호텔 사정(빈 객실 여부)에 따라 시간이 걸리거나 어려울 수도 있으므로, 문제를 발견한 즉시 프런트에 알리는 것이 해결 가능성을 높이는 방법입니다.', exampleJa: '部屋を変えられますか', exampleKo: '방을 바꿀 수 있나요?', action: '담배 냄새, 큰 방, 트윈 침대처럼 핵심 단어를 먼저 말하세요.', missionIds: ['C34'] },
  { id: 'g_narita_ticket', category: '장면', tags: ['공항', '마트', '예약', '공항역', '교환'], label: '공항역 표 교환은 창구로', tipKo: '오픈 티켓이나 교환권은 자동발매기보다 창구에서 날짜·시간·좌석을 함께 확인하는 편이 안전합니다.', detail: '나리타 익스프레스나 스카이라이너처럼 공항과 도심을 잇는 특급열차는 온라인에서 미리 구매한 오픈 티켓이나 교환권을 실물 승차권으로 바꿔야 하는 경우가 많은데, 이 교환 절차는 자동발매기보다 유인 창구(みどりの窓口 등)에서 진행하는 것이 훨씬 안전합니다. 창구 직원과 직접 대화하면 원하는 날짜·시간대의 좌석이 남아 있는지, 지정석과 자유석 중 어느 쪽이 유리한지까지 한 번에 확인하고 예약할 수 있어 자동발매기 조작 실수로 인한 문제를 예방할 수 있습니다. このチケットを使いたいです(이 티켓을 사용하고 싶어요)라고 말하며 예약 확인서나 QR코드를 함께 보여주면 절차가 훨씬 빠르게 진행되며, 원하는 목적지와 출발 희망 시간을 스마트폰 화면으로 보여주면 언어 장벽 없이도 정확하게 원하는 열차를 예약할 수 있습니다. 성수기에는 원하는 시간대가 매진될 수 있으니 공항 도착 후 여유를 두고 창구를 찾는 것이 좋습니다.', exampleJa: 'このチケットを使いたいです', exampleKo: '이 티켓을 사용하고 싶어요.', action: '목적지와 원하는 출발 시간을 화면에 보여주세요.', missionIds: ['C35'] },
  { id: 'g_baggage_weight', category: '장면', tags: ['공항', '체크인', '기념품', '수하물'], label: '수하물 초과는 무게부터', tipKo: '공항에서 무게 초과가 나오면 추가요금, 짐 재정리, 기내 반입 가능 여부를 순서대로 확인하세요.', detail: '공항 체크인 카운터에서 위탁 수하물이 항공사 규정 무게를 초과했다는 안내를 받으면, 당황하지 말고 먼저 추가요금이 얼마인지, 짐을 다른 가방으로 재정리해서 무게를 나눌 수 있는지, 초과분을 기내 반입 가방으로 옮길 수 있는지를 순서대로 침착하게 확인하는 것이 좋습니다. 많은 경우 카운터 옆에 짐을 재정리할 수 있는 별도의 공간이나 테이블이 마련되어 있어, 荷物を出してもいいですか(짐을 꺼내도 되나요)라고 먼저 물어본 뒤 그 자리에서 무게를 조정하면 추가요금을 아낄 수 있습니다. 무거운 물건(책, 화장품, 기념품 등)을 기내 캐리어 쪽으로 옮기는 것이 가장 흔한 해결책이며, 반대로 기내 수하물이 초과된 경우에는 일부를 위탁 수하물 쪽으로 옮기는 것도 방법입니다. 항공사마다 무게 규정과 초과 요금 정책이 다르므로, 여행 전에 자신이 이용하는 항공사의 수하물 규정을 미리 확인해 두면 공항에서 당황할 일이 줄어듭니다.', exampleJa: '荷物を出してもいいですか', exampleKo: '짐을 꺼내도 되나요?', action: '카운터 옆에서 정리해도 되는지 먼저 물어보세요.', missionIds: ['C36'] },
  { id: 'g_buffet_refill', category: '장면', tags: ['팁', '호텔', '뷔페', '리필', '요청'], label: '뷔페 리필 요청은 구체적으로', tipKo: '조식 뷔페에서 음식이 떨어졌을 때는 음식 이름이나 손짓으로 가리키며 ありますか라고 물으면 자연스럽습니다.', detail: '호텔 조식 뷔페에서 인기 있는 메뉴는 아침 시간대에 금방 동나는 경우가 많은데, 이럴 때는 빈 트레이나 팻말을 가리키며 これ、もうありますか(이거 더 있나요)라고 짧게 물어보는 것이 가장 자연스럽고 빠른 방법입니다. 음식 이름을 정확히 모르더라도 빈 접시나 트레이를 손으로 가리키기만 해도 직원은 대부분 무슨 뜻인지 바로 이해하고 주방에 추가 준비를 요청해 줍니다. 셀프 서비스 구역이 아니라 직원이 즉석에서 조리해 주는 오믈렛 코너 같은 곳에서는, 원하는 재료를 손가락으로 가리키며 개수나 종류를 말하는 것만으로 충분히 주문이 가능합니다. 아침 시간이 한정되어 있고 사람이 몰리는 경우가 많으므로, 인기 메뉴는 뷔페 오픈 직후 이른 시간에 찾는 것이 품절을 피하는 팁입니다.', exampleJa: 'これ、もうありますか', exampleKo: '이거 더 있나요?', action: '빈 트레이를 가리키며 직원에게 짧게 물어보세요.', missionIds: ['C37'] },
  { id: 'g_pasta_options', category: '장면', tags: ['파스타', '옵션', '하나씩', '확인'], label: '파스타 옵션은 하나씩 확인', tipKo: '소스·면 종류·세트·음료처럼 선택지가 많을 때는 한 번에 다 이해하려 하지 말고 하나씩 확인하세요.', detail: '이탈리안 레스토랑에서는 소스 종류, 면의 굵기, 세트 여부, 음료 선택까지 한 번에 여러 옵션을 연달아 물어보는 경우가 많아, 일본어에 익숙하지 않으면 정보량에 압도되기 쉽습니다. 이럴 때는 모든 질문을 한꺼번에 이해하려 하지 말고, 직원이 옵션을 하나씩 제시할 때마다 짧게 반응하며 페이스를 맞추는 것이 훨씬 편안하게 주문하는 방법입니다. 무엇을 골라야 할지 막막하다면 おすすめはどれですか(추천은 어느 건가요)라고 물어보는 것도 좋은 전략이며, 대부분의 직원은 인기 메뉴나 계절 메뉴를 친절하게 추천해 줍니다. 옵션을 놓쳤다면 부끄러워하지 말고 もう一度お願いします(다시 한번 부탁합니다)라고 요청해 끊어서 다시 들으면, 대화의 흐름을 잃지 않고 차분하게 주문을 마칠 수 있습니다.', exampleJa: 'おすすめはどれですか', exampleKo: '추천은 어느 건가요?', action: '못 들은 옵션은 もう一度お願いします로 다시 끊어 물어보세요.', missionIds: ['C39'] },
  { id: 'g_tax_free_checkout', category: '장면', tags: ['면세', '백화점', '편집샵', '계산', '조건'], label: '편집샵 계산은 면세 조건 확인', tipKo: '의류 매장 면세는 여권, 금액 조건, 개봉 금지 안내가 따라올 수 있습니다. 계산 전에 면세 가능 여부를 먼저 물어보세요.', detail: '편집샵이나 의류 매장에서도 백화점과 마찬가지로 외국인 관광객을 위한 면세 제도가 적용되지만, 매장 규모나 브랜드에 따라 면세 처리가 가능한 금액 기준이나 절차가 조금씩 다를 수 있습니다. 계산대에 가기 전에 미리 免税できますか(면세 되나요)라고 물어보면, 필요한 최소 구매 금액과 여권 제시가 필요하다는 안내를 받을 수 있어 계산 과정이 훨씬 매끄러워집니다. 면세 처리된 의류나 소품은 백화점과 마찬가지로 출국 전까지 개봉하지 말라는 안내와 함께 봉인 스티커나 전용 봉투로 포장되는 경우가 많으므로, 여행 중 바로 입고 싶은 옷이 있다면 면세 조건과 개봉 제한을 미리 확인해 두는 것이 좋습니다. 계산이 지연되지 않도록 여권은 지갑이나 가방 겉주머니처럼 바로 꺼낼 수 있는 곳에 넣어 두는 것을 추천합니다.', exampleJa: '免税できますか', exampleKo: '면세 되나요?', action: '여권을 바로 꺼낼 수 있게 준비해 두세요.', missionIds: ['C40'] },

  // ── 추가 문법 팁 ──
  { id: 'g_te_kudasai', category: '문법', tags: ['てください', '행동', '요청'], label: '〜てください (행동 요청)', tipKo: '동사 て형 + ください는 "~해 주세요". みせてください(보여 주세요), かいてください(써 주세요). 요청의 기본 틀이에요.', detail: '〜てください는 동사를 て형으로 바꾼 뒤 ください를 붙여 상대에게 구체적인 행동을 정중하게 요청하는 일본어 회화의 가장 기본적인 틀입니다. て형은 동사 종류에 따라 활용 규칙이 조금씩 다르지만(はなす→はなして, みる→みて, かく→かいて), 이 형태 하나만 익혀두면 보여달라, 써달라, 천천히 말해달라 같은 거의 모든 요청 문장을 만들 수 있습니다. 명사 뒤에 바로 ください를 붙이는 것과 달리, 동사의 て형을 거쳐야만 문법적으로 자연스러운 요청문이 되므로 동사 기본형이나 ます형에 곧바로 ください를 붙이지 않도록 주의해야 합니다. ゆっくりはなしてください(천천히 말해 주세요)처럼 부사와 함께 쓰면 대화 속도를 조절해 달라는 요청으로도 아주 유용하게 활용할 수 있습니다.', exampleJa: 'ゆっくりはなしてください', exampleKo: '천천히 말해 주세요.', commonMistake: '동사 기본형(ます형이 아닌)에 바로 ください를 붙이지 않아요.', action: '동사 て형 + ください 패턴으로 세 가지 요청을 만들어 보세요.' },
  { id: 'g_mo_ii', category: '문법', tags: ['억양', 'てもいいですか', '요청'], label: '〜てもいいですか (허가 요청)', tipKo: '동사 て형 + もいいですか로 "~해도 돼요?". 사진 촬영·착석·시식 등 허가를 구할 때 쓰는 핵심 표현입니다.', detail: '〜てもいいですか는 동사의 て형 뒤에 "~해도 좋습니까"라는 뜻의 もいいですか를 붙여, 어떤 행동을 해도 되는지 상대방에게 허락을 구하는 표현입니다. 직역하면 "~해도 좋습니까"가 되는데, 사진을 찍어도 되는지, 자리에 앉아도 되는지, 시식을 해봐도 되는지처럼 여행 중 허가가 필요한 거의 모든 순간에 이 하나의 문형으로 대응할 수 있습니다. 문장 구조상 끝이 ですか로 끝나는 의문문이지만, 억양을 낮춰 말하면 오히려 진술문처럼 들려 상대가 질문인지 인지하지 못할 수 있으므로 반드시 문장 끝의 억양을 분명하게 올리는 것이 중요합니다. 사진 촬영 허가가 필요한 상황이 여행 중 정말 자주 발생하므로, 写真を撮ってもいいですか(사진 찍어도 되나요) 이 한 문장만큼은 확실하게 외워두는 것이 좋습니다.', exampleJa: 'すわってもいいですか', exampleKo: '앉아도 될까요?', commonMistake: '끝 억양이 낮으면 질문이 아니라 진술처럼 들려요. 반드시 억양을 올리세요.', action: '사진 찍어도 되나요? = 写真を撮ってもいいですか를 소리 내어 말해 보세요.' },
  { id: 'g_ga_arimasu', category: '문법', tags: ['와이파이', 'がありますか', '있는지', '묻기'], label: '〜がありますか (있는지 묻기)', tipKo: '명사 + がありますか로 "~가 있나요?". ATMはありますか, Wi-Fiはありますか처럼 여행 중 어디서든 쓸 수 있는 만능 패턴입니다.', detail: '〜がありますか(또는 회화에서 자주 쓰는 〜はありますか)는 무생물 명사가 그 장소에 존재하는지를 묻는 표현으로, 여행 중 필요한 시설이나 물건을 찾을 때 가장 많이 쓰이는 패턴 중 하나입니다. ATM은どこですか(ATM은 어디예요)처럼 위치를 직접 묻는 것보다, 먼저 ATMはありますか(ATM이 있나요)로 존재 여부를 확인한 뒤 위치를 물어보는 흐름이 훨씬 자연스러운 대화가 됩니다. Wi-Fiはありますか(와이파이 있나요), えいごのメニューはありますか(영어 메뉴가 있나요)처럼 명사 자리만 바꿔 끼우면 되는 구조라, 여행 중 필요한 것을 떠올릴 때마다 이 틀에 대입해 문장을 즉석에서 만들어낼 수 있습니다. 사람이나 동물의 존재를 물을 때는 あります 대신 います를 쓴다는 점도 함께 알아두면 문법적으로 더 정확한 문장을 구사할 수 있습니다.', exampleJa: 'えいごのメニューはありますか', exampleKo: '영어 메뉴가 있나요?', action: '필요한 것을 생각하고 〜はありますか 문장을 두 개 만들어 보세요.' },
  { id: 'g_dono_kurai', category: '문법', tags: ['신칸센', 'どのくらい'], label: 'どのくらい (얼마나)', tipKo: '시간·거리·기간을 물을 때 どのくらいですか 한 문장으로 해결됩니다. どのくらいかかりますか(얼마나 걸려요?)처럼 かかります와 짝을 이루면 더 자연스러워요.', detail: 'どのくらい는 "어느 정도", "얼마나"라는 뜻으로 시간·거리·기간·양 등 정도를 폭넓게 물을 수 있는 편리한 의문 표현입니다. 단독으로 どのくらいですか라고만 물어도 문맥상 통하지만, 걸리는 시간을 물을 때는 동사 かかります(걸리다)와 짝을 이뤄 どのくらいかかりますか(얼마나 걸려요)라고 하면 훨씬 자연스럽고 명확한 질문이 됩니다. 걸어서 얼마나 걸리는지, 대기 시간이 얼마나 되는지, 신칸센으로 몇 분이 걸리는지처럼 여행 중 이동 계획을 세울 때 정말 자주 쓰이는 표현이라 이 하나의 문형을 잘 익혀두면 하루 일정을 짜는 데 큰 도움이 됩니다. 거리를 물을 때는 どのくらい遠いですか(얼마나 먼가요)처럼 형용사와 결합해 쓸 수도 있어 활용 범위가 넓은 편입니다.', exampleJa: 'どのくらいかかりますか', exampleKo: '얼마나 걸려요?', action: '걷는 시간, 이동 거리를 물을 때 どのくらい를 활용해 보세요.' },
  { id: 'g_nai_desu', category: '문법', tags: ['신사', 'ないでください', '요청'], label: '〜ないでください (삼가 요청)', tipKo: '동사 ない형 + でください는 "~하지 말아 주세요". 触らないでください(만지지 마세요), 写真は撮らないでください(사진 촬영 금지)처럼 안내 표시에도 많이 나옵니다.', detail: '〜ないでください는 동사를 부정형(ない형)으로 바꾼 뒤 でください를 붙여 "~하지 말아 주세요"라는 금지·삼가 요청을 나타내는 표현으로, 관광지나 시설 안내문에서 매우 자주 마주치게 됩니다. 触らないでください(만지지 마세요), 写真は撮らないでください(사진은 찍지 마세요)처럼 박물관·신사·전시관에서 문화재나 전시물을 보호하기 위한 안내 표시에 빈번하게 등장하므로, 이 문형을 알아두면 표지판만 보고도 무엇을 조심해야 하는지 스스로 파악할 수 있습니다. 문장 구조는 앞서 배운 〜てください의 부정형 버전이라고 생각하면 이해하기 쉬운데, て형이 아니라 ない형에 결합한다는 점이 다릅니다. 여행 중 표지판을 볼 때마다 〜ないでください가 붙은 동사가 무엇인지 유심히 살펴보는 습관을 들이면, 실전에서 자주 쓰이는 동사의 ない형도 자연스럽게 익힐 수 있습니다.', exampleJa: 'さわらないでください', exampleKo: '만지지 마세요.', action: '신사나 미술관 안내 표지에서 〜ないでください 표현을 찾아보세요.' },
  { id: 'g_to_omoimasu', category: '문법', tags: ['と思います', '생각', '의견'], label: '〜と思います (생각·의견)', tipKo: '문장 + と思います로 "~라고 생각합니다". 단정하지 않고 완곡하게 의견을 말할 때 쓰며, 회화에서 부드러운 인상을 줍니다.', detail: '〜と思います는 완결된 문장 뒤에 붙어 "~라고 생각합니다"라는 뜻을 더하는 표현으로, 자신의 의견이나 추측을 단정적이지 않고 부드럽게 전달할 때 사용합니다. おいしいです(맛있습니다)라고 딱 잘라 말하는 대신 おいしいと思います(맛있을 것 같아요, 맛있다고 생각해요)라고 하면 더 완곡하고 겸손한 인상을 주는데, 이런 완곡한 화법은 일본어 회화 전반에서 예의 바르고 세련된 느낌을 주는 데 중요한 역할을 합니다. 음식에 대한 감상, 날씨 예상, 길 안내에 대한 확신이 없는 정보를 전달할 때 이 표현을 붙이면 단정을 피하면서도 자신의 생각을 자연스럽게 표현할 수 있습니다. 여행 중 상대의 질문에 100% 확신이 없는 대답을 해야 할 때 と思います를 붙이는 습관을 들이면, 훨씬 자연스럽고 예의 바른 일본어를 구사할 수 있습니다.', exampleJa: 'おいしいと思います', exampleKo: '맛있을 것 같아요.', action: '음식 감상이나 날씨 예상을 と思います로 표현해 보세요.' },

  // ── 추가 문화 팁 ──
  { id: 'g_omotenashi', category: '문화', tags: ['호텔', '식당', '도쿄', '오모테나시', '일본'], label: '오모테나시 — 일본의 환대', tipKo: '일본 서비스는 손님이 요구하기 전에 미리 배려하는 おもてなし 정신을 기반으로 합니다. 불편을 말하면 최대한 해결하려 노력하니, 불편함은 망설이지 말고 전달하세요.', detail: 'おもてなし(오모테나시)는 손님을 접대한다는 뜻을 넘어, 상대가 요청하기도 전에 필요한 것을 미리 헤아려 배려하는 일본 특유의 환대 정신을 가리키는 말로, 도쿄 올림픽 유치 연설에서 세계적으로 널리 알려지기도 했습니다. 이 정신은 식당·호텔·상점 어디서나 세심한 서비스로 나타나는데, 예를 들어 손님이 말하기 전에 물수건이나 물을 먼저 챙겨주거나, 짐이 많아 보이면 먼저 도움을 제안하는 식입니다. 반대로 이 문화 덕분에 여행자가 겪는 불편함을 솔직하게 이야기하면, 직원들이 최대한 성심성의껏 해결하려고 노력하는 경우가 많으니 문제가 생겼을 때 참지 말고 알리는 것이 오히려 서로에게 좋은 결과로 이어집니다. 직원을 부르고 싶을 때는 すみません、ちょっとよろしいですか(저기요, 잠깐 괜찮으신가요)처럼 정중하게 말을 거는 것이 자연스러운 시작입니다.', exampleJa: 'すみません、ちょっとよろしいですか', exampleKo: '저기요, 잠깐 괜찮으신가요?', action: '불편한 점이 있으면 すみません 한마디로 직원을 부르세요.' },
  { id: 'g_garbage', category: '문화', tags: ['지하철', '숙소', '편의점', '매너', '쓰레기'], label: '일본 쓰레기 분리수거', tipKo: '일본은 쓰레기 분리가 엄격합니다. 도시에서 쓰레기통이 거의 없으니 편의점 쓰레기통을 이용하거나, 숙소로 가져가는 것이 예의입니다.', detail: '일본은 지자체별로 쓰레기 분리 규정이 매우 세세하게 정해져 있어, 타는 쓰레기(燃えるゴミ)·타지 않는 쓰레기(燃えないゴミ)·플라스틱·병과 캔·페트병 등을 정해진 요일과 방식에 맞춰 배출해야 하는 엄격한 시스템을 갖추고 있습니다. 그런데 아이러니하게도 지하철 테러 사건 이후 보안상의 이유로 거리의 공공 쓰레기통이 크게 줄어들어, 정작 길을 걷다가 쓰레기를 버릴 곳을 찾기가 매우 어려운 것이 여행자들이 자주 겪는 혼란입니다. 이 때문에 현지인들은 쓰레기를 당장 버리지 않고 가방에 넣어 다니다가 편의점 앞에 있는 전용 쓰레기통(주로 음료 구매객을 위한 것이지만 소량은 대부분 허용)을 이용하거나, 아예 숙소로 가져가 정리하는 것을 당연한 매너로 여깁니다. 음식물이 들어간 쓰레기를 아무 데나 버리거나 분리되지 않은 채로 편의점 쓰레기통에 넣으면 눈총을 받을 수 있으니, 페트병은 라벨과 뚜껑을 분리하는 등 최소한의 분리표시를 지키는 습관을 들이는 것이 좋습니다.', commonMistake: '음식 쓰레기를 길거리에 버리거나 전용 수거함에 넣지 않으면 문제가 될 수 있어요.', action: '편의점 봉지는 편의점 쓰레기통에 버릴 수 있어요. 분리 표시를 확인하세요.' },
  { id: 'g_chopstick_manners', category: '문화', tags: ['매너', '젓가락'], label: '젓가락 매너', tipKo: '젓가락을 밥에 꽂거나, 음식을 젓가락에서 젓가락으로 건네는 것은 장례 문화와 연관되어 금기로 여겨집니다. 음식을 나눌 때는 접시를 사용하세요.', detail: '일본에서 젓가락을 밥그릇에 수직으로 꽂아두는 행동(立て箸)과 음식을 젓가락에서 다른 사람의 젓가락으로 직접 건네는 행동(箸渡し)은 모두 불교식 장례 의식을 연상시킨다는 이유로 강하게 금기시됩니다. 장례식에서 고인의 유골을 젓가락으로 옮겨 담는 의식과, 밥에 젓가락을 세워 향처럼 꽂아두는 관습에서 비롯된 금기라, 식사 중 무심코 이런 행동을 하면 주변 사람들에게 불길하거나 무례한 인상을 줄 수 있습니다. 음식을 나눠 먹고 싶을 때는 젓가락과 젓가락으로 직접 전달하지 말고, 반드시 작은 접시(取り皿)에 옮겨 담은 뒤 상대가 자신의 젓가락으로 가져가도록 하는 것이 올바른 매너입니다. 나무젓가락(割り箸)을 다 쓴 뒤에는 원래 담겨 있던 종이 봉투에 다시 넣어 두면 "식사를 마쳤다"는 신호로 여겨져 깔끔한 인상을 줄 수 있습니다.', commonMistake: '젓가락을 밥에 세워 꽂는 행동은 절대 하지 않도록 조심하세요.', action: '젓가락 위에 사용 후 割り箸(와리바시) 봉투를 올려두면 사용 완료 신호예요.' },
  { id: 'g_sound_bath', category: '문화', tags: ['전철', '라멘', '식당', '에티켓'], label: '소음에 민감한 일본 문화', tipKo: '일본에서는 공공장소에서의 소음 억제가 강한 사회 규범입니다. 음식을 먹을 때 라면 국물 소리 정도는 허용되지만, 전화·음악은 이어폰 없이 틀지 않아요.', detail: '일본 사회는 공공장소에서 타인에게 소리로 폐를 끼치지 않는 것을 매우 중요한 규범으로 여기는데, 흥미롭게도 국수나 라멘을 후루룩 소리 내어 먹는 것만큼은 예외적으로 허용되고 오히려 맛있게 먹는다는 신호로 받아들여지는 경우가 많습니다. 반면 전화 통화, 스피커로 재생하는 음악이나 영상 소리는 아주 작은 소리라도 주변 사람들의 신경을 거스르는 행동으로 여겨져 이어폰 없이 트는 일은 거의 찾아보기 어렵습니다. 이런 소음 억제 문화는 전철·카페·식당뿐 아니라 길거리에서도 이어져, 큰 소리로 대화하거나 웃는 것도 은근히 시선을 끄는 행동이 될 수 있습니다. 여행자로서는 이어폰을 항상 소지하고, 통화가 필요하면 자리를 옮기거나 목소리를 낮추는 습관만 들여도 현지 에티켓에 훨씬 자연스럽게 녹아들 수 있습니다.', commonMistake: '스피커로 음악을 크게 틀거나 통화를 하면 주위의 시선이 집중됩니다.', action: '전철이나 식당에서 이어폰을 착용하는 습관이 현지 에티켓에 맞아요.' },
  { id: 'g_department_store', category: '문화', tags: ['매너', '백화점', '계단', '엘리베이터', '예절'], label: '백화점 계단·엘리베이터 예절', tipKo: '고급 백화점에서는 직원이 엘리베이터 안에서 층별 안내를 하는 경우가 있습니다. 들어갈 때와 나갈 때 가벼운 목례만 해도 충분해요.', detail: '전통 있는 고급 백화점에서는 흰 장갑을 낀 안내 직원이 엘리베이터 안에 상주하며 각 층에 무엇이 있는지 정중한 말투로 안내해 주는 서비스를 지금도 유지하고 있는 곳이 있습니다. 이는 앞서 소개한 오모테나시 정신이 구체적으로 구현된 사례 중 하나로, 손님은 특별히 말을 걸거나 대답할 필요 없이 타고 내릴 때 가벼운 목례 정도만 해도 충분히 예의를 갖춘 것이 됩니다. 일본 백화점 지하 1층은 흔히 デパ地下(데파치카)라고 불리는 식품 매장층으로, 고급 도시락·디저트·특산품을 파는 코너가 밀집해 있고 시식 코너도 많이 운영되어 구매 부담 없이 다양한 맛을 체험해볼 수 있는 명소로 여행자들에게도 인기가 높습니다. 시식은 대개 한두 개 정도로 예의 있게 맛보는 것이 관례이며, 마음에 들면 자연스럽게 구매로 이어가는 것이 좋은 매너입니다.', action: '지하 식품관(デパ地下)은 시식이 가능한 경우가 많아요 — 구매 부담 없이 맛볼 수 있어요.', missionIds: ['C41', 'C47'] },

  // ── 추가 발음 팁 ──
  { id: 'g_pitch_accent', category: '발음', tags: ['억양', '발음', '사투리', '도쿄'], label: '음고(피치) 악센트', tipKo: '일본어는 음의 높낮이로 뜻이 달라집니다. 예를 들어 はし는 억양에 따라 箸(젓가락)·橋(다리)·端(끝)이 될 수 있어요. 회화에서 문맥이 도와주지만, 음고 의식을 갖는 것이 좋습니다.', detail: '일본어는 영어처럼 강세(악센트)로 단어를 구분하는 언어가 아니라, 음의 높낮이 패턴(피치 악센트)으로 단어를 구분하는 언어입니다. 같은 표기 はし라도 첫 음절을 높게 읽으면 箸(젓가락), 둘째 음절을 높게 읽으면 橋(다리)가 되는 식으로, 억양 패턴 하나가 완전히 다른 단어를 만들어냅니다. 다행히 실제 회화에서는 문맥이 충분한 힌트를 주기 때문에 억양을 조금 틀리게 말해도 대부분 의사소통에 큰 지장은 없지만, 새로운 단어를 외울 때부터 발음과 함께 오르내리는 억양 패턴까지 귀로 함께 익혀두면 듣기 실력과 자연스러운 말투 모두에 큰 도움이 됩니다. 지역별로도 표준어(도쿄식)와 관서 사투리의 피치 패턴이 다른 경우가 있어, 같은 단어라도 지역에 따라 억양이 다르게 들릴 수 있다는 점도 흥미로운 부분입니다.', exampleJa: 'はし', exampleKo: '젓가락 / 다리 / 끝 (억양에 따라 달라짐)', action: '단어를 외울 때 발음과 함께 억양 패턴도 함께 들어두세요.' },
  { id: 'g_small_tsu', category: '발음', tags: ['발음', '촉음', '박자'], label: '작은 つ(촉음)와 박자', tipKo: '일본어는 박자 언어입니다. っ 하나가 한 박의 무음(정지)입니다. きって(우표)를 き·(정지)·て·로 세 박으로 발음하는 것이 핵심입니다.', detail: '일본어는 모든 글자가 거의 균등한 길이의 박자(모라)를 차지하는 박자 언어이며, 작게 쓰는 っ(촉음)는 소리 없이 한 박만큼 숨을 멈추는 독특한 역할을 합니다. ざっし(잡지)라는 단어는 ざ·っ·し 세 박으로 이루어져 있는데, 가운데 っ에서 짧게 숨을 참았다가 し를 발음해야 정확한 리듬이 만들어집니다. 이 무음의 정지 구간을 생략하고 그냥 빠르게 이어 읽으면 박자 수가 줄어들어 원어민에게는 전혀 다른, 혹은 존재하지 않는 단어처럼 들릴 수 있습니다. 촉음이 있는 단어를 만날 때마다 손가락으로 하나, 둘, 셋 박자를 짚어가며 정지 구간을 몸으로 느끼는 연습을 반복하면, 자연스럽게 촉음의 리듬감을 체득할 수 있습니다.', exampleJa: 'ざっし', exampleKo: '잡지 (雑誌)', commonMistake: '촉음을 건너뛰면 전혀 다른 단어로 들릴 수 있어요.', action: 'き·(멈춤)·て를 손가락으로 박자를 세며 말해 보세요.' },
  { id: 'g_n_sound', category: '발음', tags: ['발음', '독립', '비음'], label: 'ん (독립 비음)', tipKo: 'ん은 혼자 한 박을 차지하는 독립 음절입니다. さんえん(3엔)은 さ·ん·え·ん — 네 박입니다. 한국어 ㄴ보다 길게, 코 울림을 의식하세요.', detail: '일본어의 ん은 다른 글자에 받침처럼 붙는 소리가 아니라, 그 자체로 독립적인 한 박을 차지하는 특별한 음절입니다. さんえん(3엔)이라는 단어는 さ·ん·え·ん으로 총 네 박이 되며, 이때 ん 하나하나가 각각 온전한 한 박자의 길이를 가져야 정확한 발음이 됩니다. 한국어의 받침 ㄴ은 앞 글자에 짧게 붙어 끝나는 소리인 반면, 일본어의 ん은 코로 공기를 내보내며 소리를 그보다 길게 유지해야 하는 비음(鼻音)이라는 점이 다릅니다. さんえん와 さんべん처럼 뒤에 오는 소리에 따라 ん의 실제 발음(ㄴ에 가까운지, ㅁ에 가까운지)이 미묘하게 달라지기도 하는데, 이런 세부 변화보다는 우선 ん을 짧게 뭉개지 않고 한 박만큼 충분히 길게 유지하는 습관을 들이는 것이 더 중요합니다.', exampleJa: 'さんえん', exampleKo: '3엔', action: 'さんえん와 さんべん을 비교하며 ん 발음을 연습해 보세요.' },
  { id: 'g_vowel_length', category: '발음', tags: ['발음', '장음', '모음', '의미'], label: '모음 길이로 의미가 바뀐다', tipKo: 'おじさん(아저씨)과 おじいさん(할아버지), ビル(빌딩)과 ビール(맥주)처럼 모음 하나의 길이가 의미를 바꿉니다. 각 박을 균등하게 유지하는 것이 핵심입니다.', detail: '앞서 다룬 장음 규칙이 실제 단어에서 얼마나 큰 의미 차이를 만드는지 보여주는 대표적인 예가 바로 おじさん(아저씨)과 おじいさん(할아버지)의 차이입니다. じ 뒤에 모음 하나가 더 들어가느냐 아니냐에 따라 완전히 다른 두 사람을 가리키게 되므로, 실수로 할아버지를 아저씨라고 부르거나 그 반대로 부르는 일이 생기지 않도록 주의가 필요합니다. ビル(빌딩)과 ビール(맥주)의 관계도 마찬가지로, 하나의 모음 길이 차이가 건물과 술이라는 전혀 다른 대상을 가리키게 만듭니다. 이런 단어들을 연습할 때는 짧은 쪽과 긴 쪽을 번갈아 소리 내어 비교하면서, 긴 쪽은 박자를 하나 더 세면서 발음하는 습관을 들이면 두 소리의 차이를 몸으로 확실하게 구분할 수 있게 됩니다.', exampleJa: 'おじさん / おじいさん', exampleKo: '아저씨 / 할아버지', action: 'ビル과 ビール을 각각 2박·3박으로 세면서 말해 보세요.' },

  // ── 추가 여행 팁 ──
  { id: 'g_shinkansen_seat', category: '여행', tags: ['신칸센', '예약', '자유석', '지정석', '구분'], label: '신칸센 자유석·지정석 구분', tipKo: '신칸센 자유석(自由席)은 좌석 번호 없이 비어 있는 자리에 앉아요. 지정석(指定席)은 표에 적힌 칸·좌석에만 앉아야 합니다. 자유석 칸 번호는 탑승 전 확인하세요.', detail: '신칸센 좌석은 크게 자유석(自由席)과 지정석(指定席)으로 나뉘는데, 자유석은 정해진 몇 개 칸 안에서 먼저 온 순서대로 빈자리에 앉는 방식이라 요금이 저렴한 대신 성수기에는 서서 가야 할 수도 있습니다. 반대로 지정석은 표에 적힌 칸 번호와 좌석 번호에만 앉을 수 있어 앉을 자리가 보장되지만 추가 요금이 붙으며, 다른 승객이 이미 그 자리를 예약해 뒀다면 자유석 승객이 실수로 앉지 않도록 주의해야 합니다. 열차마다 자유석으로 지정된 칸의 번호가 다르므로, 탑승 전 플랫폼의 전광판이나 안내판에서 이번 열차의 자유석 구간이 몇 호차인지 반드시 확인하고 그 위치에 맞춰 줄을 서는 것이 좋습니다. 자유석 위치가 헷갈리면 역무원에게 じゆうせきはどこですか(자유석은 어디예요)라고 물어보면 정확한 위치와 줄 서는 곳까지 안내받을 수 있습니다.', exampleJa: 'じゆうせきはどこですか', exampleKo: '자유석은 어디예요?', action: '플랫폼 안내판에서 自由席 구간 번호를 찾아 그 위치에 줄을 서세요.', missionIds: ['C23'] },
  { id: 'g_taximeter', category: '여행', tags: ['택시', '고속도로', '숙소', '발음'], label: '택시 미터와 가산 요금', tipKo: '일본 택시는 야간(심야)과 고속도로 이용 시 가산 요금이 붙습니다. 목적지를 지도나 메모로 보여주면 의사소통이 훨씬 쉬워요.', detail: '일본 택시 요금은 기본적으로 미터기(タクシーメーター)에 표시되는 거리·시간 기준 요금이지만, 여기에 몇 가지 가산 요금이 추가로 붙을 수 있어 미리 알아두면 요금이 갑자기 오른 것 같아 당황하는 일을 줄일 수 있습니다. 가장 대표적인 것이 심야 할증으로, 보통 밤 10시에서 새벽 5시 사이에는 기본요금에 20~30% 정도의 할증이 붙는 것이 일반적이며, 고속도로를 이용하면 미터 요금과 별개로 통행료가 그대로 승객에게 청구됩니다. 또한 정체가 심한 도로에서는 시간 경과에 따른 요금이 추가로 누적되기 때문에, 같은 거리라도 시간대와 도로 상황에 따라 요금 차이가 꽤 클 수 있습니다. 목적지를 일본어로 정확히 발음하기 어렵다면 このじゅうしょまでおねがいします(이 주소로 부탁합니다)라고 말하며 지도 앱의 목적지 화면이나 숙소 명함을 함께 보여주는 것이 기사와의 의사소통 오류를 막는 가장 확실한 방법입니다.', exampleJa: 'このじゅうしょまでおねがいします', exampleKo: '이 주소로 부탁합니다.', action: '지도 앱 목적지 화면을 택시 기사에게 보여주는 것이 가장 확실한 방법이에요.', missionIds: ['C8'] },
  { id: 'g_passport_carry', category: '여행', tags: ['현금', '카드', '면세', '호텔', '체크인'], label: '여권은 상시 휴대', tipKo: '일본에서 외국인은 여권이나 그에 준하는 신분증을 상시 소지해야 하는 법적 의무가 있습니다. 면세 쇼핑·호텔 체크인·ATM 이용에도 여권이 필요한 경우가 많아요.', detail: '일본 출입국관리법상 외국인 여행자는 여권 원본(또는 그에 준하는 재류카드 등)을 항상 몸에 지니고 있어야 하는 법적 의무가 있으며, 이는 단순 권고가 아니라 실제로 관공서나 경찰의 요청 시 제시해야 하는 규정입니다. 실생활에서도 여권이 필요한 순간이 생각보다 많은데, 앞서 설명한 면세 쇼핑은 물론이고 일부 호텔 체크인, 해외카드로 ATM에서 현금을 인출할 때도 신분 확인용으로 여권을 요구하는 경우가 흔합니다. 이런 이유로 여권을 숙소 금고에 넣어두고 몸만 나왔다가 면세 혜택을 놓치거나 필요한 순간에 신분 확인이 안 돼 곤란해지는 경우가 실제로 자주 발생합니다. 분실이나 도난에 대비해 여권의 사진이 있는 페이지를 미리 스마트폰으로 찍어두고, 종이 복사본도 한 부 만들어 숙소에 따로 보관해 두면 만약의 상황에서도 훨씬 안심할 수 있습니다.', commonMistake: '여권을 숙소에 두고 나오면 면세 혜택을 받지 못하거나 신분 확인에 문제가 생길 수 있어요.', action: '여권은 여행 내내 몸에 지니고, 복사본을 숙소에도 한 부 남겨두세요.', missionIds: ['C9'] },
  { id: 'g_train_door', category: '여행', tags: ['전철', '매너', '에티켓', '승강', '예절'], label: '전철 문과 승강 예절', tipKo: '전철 문은 자동이지만 승강장 표시선 안에 서서 내리는 사람 먼저 기다렸다 타야 합니다. 문이 닫히기 시작하면 무리하게 타지 않는 것이 안전 에티켓입니다.', detail: '일본 전철의 문은 기관사나 자동 시스템이 여닫는 자동문이지만, 승객들이 지켜야 할 승하차 순서와 대기 위치에 대한 규범은 매우 세밀하게 자리잡혀 있습니다. 플랫폼 바닥에는 문이 열릴 위치와 줄을 서야 할 지점이 표시되어 있고, 그 표시선 안쪽에 서서 기다리다가 내리는 승객이 완전히 다 내린 뒤에 타는 것이 기본 원칙입니다. 문이 닫히기 시작했는데 무리하게 몸을 들이밀어 타려는 행동은 안전사고의 위험이 있을 뿐 아니라 다른 승객에게도 불편을 주는 행동으로 여겨지므로, 문이 닫히는 신호음이 들리면 다음 열차를 기다리는 것이 안전하고 매너 있는 선택입니다. 플랫폼에 적힌 乗車(승차)·降車(하차) 표시나 문의 위치를 나타내는 바닥의 줄 색깔을 미리 확인해 두면, 열차가 들어올 때 당황하지 않고 정확한 위치에서 여유 있게 대기할 수 있습니다.', action: '乗車(승차)·降車(하차) 표시와 문 색깔(줄)을 확인하고 지시선 안에 대기하세요.' },
  { id: 'g_vending_machine', category: '여행', tags: ['카드', 'IC카드', 'Suica', '동전', '잔돈'], label: '자판기는 편의점만큼 다양', tipKo: '일본 자판기는 음료부터 우산·과자·라멘·어묵까지 팔아요. 동전과 천엔권을 넣으면 대부분 작동하고, IC카드 결제가 되는 기기도 많습니다.', detail: '일본은 인구 대비 자판기 밀도가 세계에서 손꼽힐 정도로 높아, 골목 구석구석까지 자판기를 쉽게 찾을 수 있고 파는 품목도 음료를 넘어 우산·과자·컵라면·심지어 즉석 어묵(おでん)까지 다룰 만큼 다양합니다. 대부분의 자판기는 동전과 천엔권을 넣으면 바로 작동하며, 최근에는 Suica 같은 교통 IC카드나 QR코드 결제를 지원하는 기기도 빠르게 늘고 있어 잔돈이 없어도 이용할 수 있는 경우가 많습니다. 자판기 표면에는 각 음료의 가격이 명확히 표시되어 있고, 품절된 상품은 버튼에 불이 꺼지거나 램프가 표시되지 않는 방식으로 안내되므로 그림만 보고도 구매 가능 여부를 쉽게 판단할 수 있습니다. 가격이 헷갈리거나 궁금한 상품이 있다면 これはいくらですか(이건 얼마예요)라고 물어볼 수도 있지만, 대부분은 표시만으로 충분히 혼자 이용할 수 있는 시스템입니다.', exampleJa: 'これはいくらですか', exampleKo: '이건 얼마예요?', action: '가격 표시를 보고 IC카드 마크가 있으면 탭 결제를 시도해 보세요.', missionIds: ['C42'] },

  // ── 추가 회화법 팁 ──
  { id: 'g_echo_technique', category: '회화법', tags: ['에코', '기법', '상대', '되풀'], label: '에코 기법 — 상대 말 되풀이', tipKo: '상대의 말 끝부분을 반문하듯 따라 말하면 이해를 확인하고 대화를 이어가는 데 효과적입니다. 「〜ですか？」처럼 끝을 올리면 자연스러운 되물음이 돼요.', detail: '에코(echo) 기법은 상대가 방금 한 말의 핵심 단어를 그대로 따라 말하며 끝을 올려 되묻는 방식으로, 짧은 어휘력으로도 대화의 정확도를 확인하고 흐름을 이어갈 수 있는 실용적인 회화 기술입니다. 예를 들어 길을 물었을 때 상대가 みぎ(오른쪽)라고 답했다면, 그 단어를 그대로 따라 みぎ、ですか？(오른쪽이요?)라고 되물으며 확인하는 것만으로도 자연스러운 대화가 이어지고 내가 제대로 이해했는지도 검증할 수 있습니다. 이 방법의 장점은 새로운 문장을 스스로 만들어낼 필요 없이 상대의 말을 재활용하기만 하면 되므로, 초급 학습자도 부담 없이 활용할 수 있다는 점입니다. 길 안내나 복잡한 설명을 들을 때 핵심 단어 하나하나를 이렇게 확인해 가면, 놓치는 정보 없이 대화를 끝까지 따라갈 수 있습니다.', exampleJa: 'みぎ、ですか？', exampleKo: '오른쪽이요?', action: '길 안내를 들을 때 핵심 단어를 끝에 의문형으로 따라 말해 보세요.' },
  { id: 'g_simple_japanese', category: '회화법', tags: ['한자', '쉬운', '일본어', '요청', '전략'], label: '쉬운 일본어 요청 전략', tipKo: 'やさしいにほんごでおねがいします — 어려운 한자어를 피하고 쉬운 말로 바꿔 말해 달라고 요청하는 표현입니다. 「もっとかんたんに」도 같은 의미로 쓸 수 있어요.', detail: '일본에는 외국인 학습자를 배려해 어려운 한자어나 복잡한 표현을 쉬운 말로 바꿔주는 やさしい日本語(쉬운 일본어)라는 개념이 사회적으로 자리잡고 있어, 이를 직접 요청하는 표현을 알아두면 대화가 훨씬 수월해집니다. やさしいにほんごでおねがいします(쉬운 일본어로 부탁합니다)라고 말하면, 상대는 자연스럽게 어려운 한자어 대신 기초 어휘와 짧은 문장으로 바꿔 설명해 주려고 노력하는 경우가 많습니다. 비슷한 뜻으로 もっとかんたんに(더 간단하게)라는 표현을 쓸 수도 있는데, 상황에 따라 둘 중 편한 것을 골라 사용하면 됩니다. 이 표현 하나만 확실히 외워두면, 상대의 설명이 너무 복잡하고 빨라서 대화가 막힐 것 같은 순간에 자연스럽게 대화의 난이도를 낮춰 이어갈 수 있는 든든한 안전장치가 됩니다.', exampleJa: 'やさしいにほんごでおねがいします', exampleKo: '쉬운 일본어로 부탁합니다.', action: '알아듣기 어려울 때 이 표현 하나면 대화를 이어갈 수 있어요. 소리 내어 외워 두세요.' },
  { id: 'g_body_language', category: '회화법', tags: ['번역앱', '마트', '발음', '몸짓'], label: '몸짓이 반, 말이 반', tipKo: '여행 일본어는 100% 말로 해결할 필요가 없어요. 가리키기·손짓·지도 보여주기·번역앱을 조합하면 말이 짧아도 충분히 소통됩니다. 몸짓 언어를 적극 활용하세요.', detail: '여행 중 의사소통은 말로만 이루어지는 것이 아니라, 손가락으로 가리키기·고개 끄덕임·지도나 화면 보여주기 같은 비언어적 수단을 얼마나 잘 조합하느냐에 따라 성패가 크게 갈립니다. 메뉴판의 사진을 가리키며 これください라고 말하는 것만으로 주문이 끝나는 것처럼, 짧은 일본어 한마디와 정확한 손짓 하나가 완벽한 문장보다 훨씬 효과적으로 뜻을 전달하는 경우가 많습니다. 특히 지도 앱으로 목적지를 보여주거나 번역 앱 화면을 함께 내밀면, 발음에 자신이 없어도 정보 전달의 정확도를 크게 높일 수 있습니다. 여행 전 지도 앱·번역 앱·메모 앱 이 세 가지를 스마트폰에 미리 준비해 두면, 말문이 막히는 순간에도 당황하지 않고 다른 수단으로 대화를 이어갈 수 있다는 심리적 안정감까지 얻을 수 있습니다.', action: '지도 앱, 번역앱, 메모 앱 세 가지를 여행 전에 준비해 두면 말문이 막혀도 안심이에요.', missionIds: ['C5', 'C50'] },
  { id: 'g_sumimasen_uses', category: '회화법', tags: ['지하철', 'すみません', '용법'], label: 'すみません의 세 가지 용법', tipKo: 'すみません은 "저기요(주의 끌기)", "죄송합니다(사과)", "감사합니다(감사)"의 세 가지로 쓰입니다. 길을 묻거나 지나갈 때, 서비스를 받고 감사할 때 모두 사용할 수 있는 핵심 만능 표현입니다.', detail: 'すみません은 일본어 회화에서 가장 많이 쓰이는 표현 중 하나로, 문맥에 따라 세 가지 전혀 다른 의미로 기능하는 독특한 만능 표현입니다. 첫째로 낯선 사람의 주의를 끌고 싶을 때(저기요), 둘째로 실수하거나 불편을 끼쳤을 때 사과할 때(죄송합니다), 셋째로 누군가 나를 위해 수고해 주었을 때 감사를 표현할 때(감사합니다, ありがとう보다는 약간 미안함이 섞인 감사)까지 폭넓게 쓰입니다. 길을 물을 때 すみません、ちかてつはどこですか(저기요, 지하철은 어디예요)처럼 문장 맨 앞에 붙이면 자연스럽게 대화를 시작하는 신호가 되고, 좁은 통로를 지나가야 할 때도 짧게 すみません 한마디면 충분히 양해를 구할 수 있습니다. 이 한 단어의 세 가지 쓰임을 상황별로 구분해 연습해 두면, 여행 중 마주치는 대부분의 사회적 상호작용에서 자연스럽게 대응할 수 있는 만능 열쇠를 갖게 되는 셈입니다.', exampleJa: 'すみません、ちかてつはどこですか', exampleKo: '저기요, 지하철은 어디예요?', action: 'すみません을 상황 세 가지에 각각 사용하는 연습을 해 보세요.' },

  // ── 추가 장면 팁 ──
  { id: 'g_food_court', category: '장면', tags: ['현금', '카드', '동전', '잔돈', '라멘'], label: '푸드코트 식권기 순서', tipKo: '푸드코트·라멘 가게는 입구 식권기(食券機)에서 먼저 표를 사고 자리에 앉는 방식이 많아요. 현금이 필요한 곳이 많으니 동전을 준비하세요.', detail: '라멘 가게나 푸드코트에서는 자리에 앉기 전에 입구에 놓인 자동 식권기(食券機)에서 먼저 원하는 메뉴의 버튼을 눌러 돈을 넣고 식권을 뽑는 방식이 매우 흔합니다. 이 순서를 모르고 그냥 자리에 앉아 직원을 기다리면 오히려 어리둥절한 상황이 될 수 있으므로, 가게에 들어서면 우선 식권기가 있는지부터 확인하는 것이 첫 단계입니다. 식권기는 구형 기계일수록 카드 결제가 안 되고 현금(특히 동전과 천엔권)만 받는 경우가 많아, 지폐를 넣었는데 잔돈이 부족해 거스름돈이 안 나오는 상황을 피하려면 미리 잔돈을 준비해 두는 것이 좋습니다. 버튼에 사진이 붙어 있는 기계라면 메뉴를 몰라도 사진을 보고 고르면 되고, 사용법이 헷갈릴 때는 근처 직원에게 つかいかたをおしえてください(사용법을 알려 주세요)라고 요청하면 친절하게 도와줍니다.', exampleJa: 'つかいかたをおしえてください', exampleKo: '사용법을 알려 주세요.', action: '식권기에서 원하는 메뉴 버튼을 누르고 돈을 넣은 뒤 표를 받아 직원에게 주세요.', missionIds: ['C47'] },
  { id: 'g_izakaya_order', category: '장면', tags: ['이자카야'], label: '이자카야 첫 음료는 빠르게', tipKo: '이자카야에서는 자리에 앉자마자 음료 주문을 먼저 받으러 옵니다. とりあえずビール(일단 맥주)가 대표 첫 주문이며, 못 마시면 ノンアルコールでお願いします라고 하면 무알콜을 주문할 수 있어요.', detail: '이자카야에 들어가 자리에 앉으면 메뉴를 살펴볼 틈도 없이 점원이 가장 먼저 음료 주문부터 받으러 오는 경우가 대부분인데, 이는 일본 술자리 문화에서 건배할 첫 잔을 최대한 빨리 준비해 주려는 관습에서 비롯된 것입니다. 그래서 일본인들 사이에서도 일단 정해진 메뉴 없이 とりあえずビール(일단 맥주부터)라고 습관적으로 말하는 경우가 매우 흔하며, 이는 거의 관용구처럼 자리잡은 첫 주문 표현입니다. 술을 마시지 못하거나 마시고 싶지 않은 경우에는 부담 없이 ノンアルコールでおねがいします(무알콜로 부탁합니다)라고 말하면 되는데, 최근에는 무알콜 맥주나 칵테일 메뉴를 갖춘 이자카야가 많아 술을 못 마셔도 자연스럽게 분위기에 어울릴 수 있습니다. 이 표현 하나만 미리 알아두면 급작스러운 첫 주문 타이밍에도 당황하지 않고 여유 있게 대응할 수 있습니다.', exampleJa: 'ノンアルコールでおねがいします', exampleKo: '무알콜로 부탁합니다.', action: '음료를 못 마신다면 ノンアルコール이라는 단어를 미리 외워두세요.', missionIds: ['C16'] },
  { id: 'g_cherry_blossom', category: '장면', tags: ['축제', '벚꽃', '매너', '쓰레기'], label: '벚꽃 명소는 자리 경쟁', tipKo: '봄 벚꽃 시즌(오다이)(3~4월)에는 인기 공원에 이른 아침부터 돗자리로 자리를 맡아 두는 문화(場所取り)가 있습니다. 늦게 도착하면 좋은 자리를 구하기 어렵고 쓰레기는 직접 가져가세요.', detail: '봄철 벚꽃 시즌(3~4월)이 되면 유명한 공원이나 벚꽃 명소에서는 꽃놀이 자리를 미리 차지해 두는 場所取り(바쇼도리)라는 독특한 문화가 펼쳐지는데, 인기 있는 나무 아래 자리는 이른 아침부터 돗자리나 비닐 시트로 표시해 두고 저녁에 본격적으로 자리를 잡는 경우가 흔합니다. 특히 회사 동료나 친구들이 순서를 정해 아침부터 자리를 지키는 모습은 일본 벚꽃놀이(花見)의 상징적인 풍경 중 하나로 꼽힙니다. 여행자 입장에서는 늦게 도착하면 나무 바로 아래 명당 자리는 이미 다 찬 경우가 많으므로, 좋은 자리를 원한다면 이른 시간에 움직이는 것이 유리합니다. 축제와 마찬가지로 벚꽃 명소 주변도 쓰레기통이 부족한 경우가 많아, 돗자리와 함께 여분의 봉투를 챙겨가 다 쓴 쓰레기를 직접 수거해 가는 것이 현지에서 중요하게 여겨지는 매너입니다.', action: '벚꽃 명소 방문 시 봉투와 비닐 시트를 준비하고 쓰레기는 직접 수거하세요.', missionIds: ['C30'] },
  { id: 'g_pharmacy_otc', category: '장면', tags: ['번역앱', '편의점', '드럭스토어', '약국', '일반의약품'], label: '약국 일반의약품 구매', tipKo: '편의점에도 기본 상비약이 있지만 종류는 적어요. 드럭스토어(薬局·ドラッグストア)에서 감기약·진통제·위장약·반창고 등을 구매할 수 있습니다.', detail: '편의점에서도 두통약이나 감기약 같은 아주 기본적인 상비약을 살 수 있지만 종류와 재고가 제한적이라, 좀 더 다양한 일반의약품이 필요하다면 마츠모토키요시 같은 드럭스토어(薬局·ドラッグストア)를 찾는 것이 훨씬 폭넓은 선택지를 제공합니다. 드럭스토어에서는 감기약·진통제·위장약·파스·반창고는 물론, 한국에서 인기 있는 각종 뷰티·건강 제품까지 함께 취급하는 경우가 많아 여행 중 종합 쇼핑 장소로도 활용됩니다. 원하는 증상을 말하면 직원이 적합한 약을 추천해 주기도 하는데, かぜぐすりはありますか(감기약 있나요)처럼 증상이나 약 이름을 짚어 물어보면 도움을 받기 쉽습니다. 구매한 약의 포장에 적힌 用法用量(용법용량, 복용 방법과 용량)은 반드시 번역 앱 카메라로 찍어 정확히 확인한 뒤 복용하는 것이 안전합니다.', exampleJa: 'かぜぐすりはありますか', exampleKo: '감기약 있나요?', action: '약 봉투의 用法用量(용법용량)을 번역앱으로 찍어 확인하세요.', missionIds: ['C6', 'C48'] },

  // ── N5 공백 보강 (report:n5 미커버분) ──
  { id: 'g_mashita', category: '문법', tags: ['ました', '과거'], label: '〜ました (과거)', tipKo: 'ます의 과거형. "~했습니다". わかりました(알겠습니다)는 여행 회화 최다 빈출 — 이해했다는 과거형 대답이에요.', detail: '〜ました는 정중체 동사 ます를 과거형으로 바꾼 형태로, "~했습니다"라는 뜻을 나타냅니다. 활용 규칙은 아주 단순해서 ます를 ました로 바꾸기만 하면 되므로(いきます→いきました), 정중체를 익힌 학습자라면 추가 부담 없이 바로 활용할 수 있습니다. 특히 わかりました(알겠습니다, 이해했습니다)는 점원의 설명을 이해했다는 응답으로 여행 회화에서 가장 자주 쓰이는 표현 중 하나로 꼽힐 만큼 실전 활용도가 매우 높습니다. 어제 갔다 온 곳이나 이미 끝난 일을 이야기할 때 きのう(어제) 같은 과거 시간 표현과 함께 쓰는 경우가 많은데, 이때 동사를 ます 그대로 두고 시간 표현만 과거로 바꾸면 시제가 어긋나 어색한 문장이 되므로 동사 자체를 반드시 ました로 바꿔야 한다는 점을 기억해야 합니다.', exampleJa: 'きのう、きょうとにいきました', exampleKo: '어제 교토에 갔습니다.', commonMistake: 'ます 그대로 두고 きのう만 붙이면 시제가 어긋나요.', action: 'いきます→いきました처럼 ます를 ました로 바꾸는 연습을 해 보세요.', n5Refs: ['n5_g_mashita'] },
  { id: 'g_masenka', category: '문법', tags: ['ませんか', '권유'], label: '〜ませんか (권유)', tipKo: '부정 의문형이지만 뜻은 "같이 ~하지 않을래요?"라는 부드러운 권유. 거절할 여지를 주는 정중한 초대예요.', detail: '〜ませんか는 형태상 ます의 부정 의문형(~하지 않습니까)이지만, 실제 회화에서는 "같이 ~하지 않을래요?"라는 부드러운 권유·초대의 뜻으로 쓰이는 것이 핵심입니다. いっしょにたべませんか(같이 먹지 않을래요)라고 물으면 이는 추궁이 아니라 상대에게 부담 없이 거절할 여지를 남겨두는 정중한 제안으로 받아들여집니다. 이 형태를 문자 그대로 "안 먹습니까?"라는 확인 질문으로 오해하면 상대의 의도를 놓칠 수 있으므로, 부정 의문형이 권유의 의미로 쓰인다는 일본어 특유의 화법을 알아두는 것이 중요합니다. 비슷한 뜻의 〜ましょう(합시다)보다 ませんか가 한 단계 더 정중하고 상대의 의사를 존중하는 뉘앙스를 갖고 있어, 처음 만난 사람이나 격식이 필요한 자리에서는 ませんか 쪽을 선택하는 것이 더 안전합니다.', exampleJa: 'いっしょにたべませんか', exampleKo: '같이 먹지 않을래요?', commonMistake: '"안 먹습니까?"라는 추궁으로 오해하기 쉬워요 — 권유입니다.', action: '~ましょう(합시다)와 ~ませんか(할래요?)의 어감 차이를 비교해 보세요.', n5Refs: ['n5_g_masenka'] },
  { id: 'g_mashou', category: '문법', tags: ['ましょう'], label: '〜ましょう (합시다)', tipKo: '"같이 ~합시다"라는 적극 제안. 상대 대답에 いいですね(좋네요)로 호응하면 자연스러워요.', detail: '〜ましょう는 ます를 의지형으로 바꾼 형태로 "같이 ~합시다"라는 뜻의 적극적인 제안을 나타내며, 앞서 배운 ませんか보다 조금 더 확신을 갖고 행동을 제안할 때 사용합니다. えきまであるきましょう(역까지 걸어갑시다)처럼 이미 어느 정도 의견 일치가 된 상황이나, 내가 먼저 방향을 제시하고 싶을 때 자연스럽게 쓸 수 있는 표현입니다. 상대가 이 제안에 동의할 때는 いいですね(좋네요)로 호응해 주는 것이 자연스러운 대화 흐름이며, 이렇게 제안과 호응이 짝을 이루는 패턴을 함께 익혀두면 실전 대화가 훨씬 매끄러워집니다. 다만 윗사람이나 격식이 필요한 상대에게 ましょう를 쓰면 마치 지시하는 듯한 인상을 줄 수 있어 다소 무례하게 들릴 수 있으므로, 그런 상황에서는 좀 더 완곡한 ませんか를 선택하는 것이 안전합니다.', exampleJa: 'えきまであるきましょう', exampleKo: '역까지 걸어갑시다.', commonMistake: '윗사람에게 지시하듯 쓰면 무례할 수 있어요 — ませんか가 더 정중해요.', action: 'ましょう(제안)와 ませんか(권유)를 상황 바꿔 말해 보세요.', n5Refs: ['n5_g_mashou'] },
  { id: 'g_ja_arimasen', category: '문법', tags: ['분실물', 'じゃありません'], label: '〜じゃありません (아닙니다)', tipKo: '명사·な형용사의 정중 부정. "~이/가 아닙니다". 더 격식 있게는 ではありません.', detail: '〜じゃありません은 명사나 な형용사를 정중하게 부정할 때 쓰는 표현으로, "~이/가 아닙니다"라는 뜻을 나타냅니다. これはわたしのじゃありません(이건 제 것이 아니에요)처럼 분실물이나 소유를 확인하는 상황, 또는 잘못 배달된 물건을 정정할 때 자주 쓰이는 실용적인 표현입니다. 더 격식 있는 자리나 글에서는 じゃ 대신 では를 써서 ではありません이라고 하는데, じゃ는 では가 구어체에서 줄어든 형태이므로 뜻은 완전히 같습니다. ないです라는 더 캐주얼한 부정 표현도 있지만, 점원이나 처음 만난 사람 앞에서는 じゃありません 쪽이 훨씬 안전하고 예의 바른 인상을 줍니다. 분실물 센터나 매장에서 내 물건이 아닌 것을 가리키며 이 표현을 연습해 두면, 실제 상황에서 오해 없이 명확하게 의사를 전달할 수 있습니다.', exampleJa: 'これはわたしのじゃありません', exampleKo: '이건 제 것이 아니에요.', commonMistake: 'ないです만 쓰면 캐주얼 — 점원·직원에게는 じゃありません이 안전해요.', action: '내 것이 아닌 물건을 가리키며 わたしのじゃありません을 말해 보세요.', n5Refs: ['n5_g_ja_arimasen'] },
  { id: 'g_te_imasu', category: '문법', tags: ['ています', '진행', '상태'], label: '〜ています (진행·상태)', tipKo: '"~하고 있어요(진행)" 또는 "~해 있어요(상태)". 가게가 열려 있다(あいています), 줄 서 있다(ならんでいます) 등 여행에서 상태 표현으로 자주 만나요.', detail: '〜ています는 동사의 て형에 います를 붙인 형태로, 문맥에 따라 "지금 ~하고 있다"는 진행의 의미나 "~한 상태이다"라는 상태 지속의 의미 두 가지로 쓰입니다. 여행 중에는 특히 상태를 나타내는 쓰임이 자주 등장하는데, 가게가 지금 열려 있는지 물을 때 みせはあいていますか(가게 열려 있나요)라고 하거나, 줄이 서 있는 상황을 ならんでいます(줄 서 있습니다)라고 표현하는 식입니다. 단순히 ます형만 쓰면 "앞으로 연다"는 미래·습관의 뜻으로 오해될 수 있어, 지금 이 순간의 상태를 묻고 싶을 때는 반드시 ています 형태를 써야 정확한 의미가 전달됩니다. あいていますか라는 문장 자체를 하나의 덩어리로 통째로 외워두면, 영업 여부를 확인해야 하는 다양한 상황에서 즉시 활용할 수 있습니다.', exampleJa: 'みせはあいていますか', exampleKo: '가게 열려 있나요?', commonMistake: 'ます만 쓰면 "(앞으로) 연다"는 뜻이 되기 쉬워요 — 지금 상태는 ています.', action: 'あいていますか(열려 있나요?)를 통째로 외워 두세요.', n5Refs: ['n5_g_te_imasu'] },
  { id: 'g_he', category: '문법', tags: ['조사', '발음', '도쿄', '방향'], label: '조사 へ (방향)', tipKo: '"~(쪽)으로". 방향을 나타낼 때 쓰고 「え」로 발음합니다. に와 비슷하지만 へ는 방향감이 강조돼요.', detail: '조사 へ는 이동의 방향을 나타내는 조사로 "~(쪽)으로"라는 뜻이며, を와 마찬가지로 표기와 실제 발음이 다른 대표적인 조사입니다. 표기는 へ지만 조사로 쓰일 때는 반드시 え로 발음해야 하며, 표기 그대로 헤로 읽으면 자연스럽지 않은 발음이 되므로 주의가 필요합니다. 목적지 도착을 강조하는 조사 に와 의미가 겹치는 경우가 많지만, へ는 "그 방향으로 향해 간다"는 이동의 방향성 자체에 초점이 있는 반면 に는 최종 도착점을 더 명확히 짚는다는 미묘한 차이가 있습니다. とうきょうへいきます(도쿄로 갑니다)처럼 여행 계획이나 이동 경로를 말할 때 오늘 갈 행선지를 넣어 반복해서 말해보면, 이 조사의 발음과 쓰임을 자연스럽게 체화할 수 있습니다.', exampleJa: 'とうきょうへいきます', exampleKo: '도쿄로 갑니다.', commonMistake: '표기 그대로 「헤」로 읽어요 — 조사일 때는 반드시 「에」.', action: '행선지를 넣어 〜へいきます를 말해 보세요.', n5Refs: ['n5_g_he'] },
  { id: 'g_kara_made', category: '문법', tags: ['호텔', '한자', 'から', 'まで', '부터'], label: 'から〜まで (부터~까지)', tipKo: 'から는 시작점, まで는 끝점. 시간(9じから5じまで)과 장소(えきからホテルまで) 모두에 씁니다. 영업시간 안내에서 매일 만나는 짝이에요.', detail: 'から〜まで는 시작점을 나타내는 から와 끝점을 나타내는 まで가 짝을 이루는 표현으로, 시간 범위(9시부터 5시까지)든 장소 범위(역에서 호텔까지)든 구분 없이 폭넓게 쓸 수 있는 매우 실용적인 문형입니다. 상점이나 관광시설의 영업시간 안내판에는 거의 예외 없이 이 짝이 등장하기 때문에, 이 표현을 알아두면 한자를 다 몰라도 숫자와 から・まで 위치만으로 영업 시작·종료 시간을 유추할 수 있습니다. から는 "~니까"라는 이유를 나타내는 쓰임도 있어 헷갈리기 쉬운데, 여행 회화에서 만나는 から는 대부분 시작점이라는 기본 의미로 쓰인다는 점을 먼저 확실히 해두는 것이 좋습니다. えきからホテルまであるきます(역에서 호텔까지 걷습니다)처럼 오늘의 실제 이동 경로를 넣어 문장을 만들어보면, 이 구조가 훨씬 빠르게 몸에 익습니다.', exampleJa: 'えきからホテルまであるきます', exampleKo: '역에서 호텔까지 걷습니다.', commonMistake: 'から를 "~니까(이유)"로만 알면 시간표를 못 읽어요 — 출발점 뜻이 기본.', action: '오늘 일정을 〜から〜まで로 한 문장 만들어 보세요.', n5Refs: ['n5_g_kara', 'n5_g_made'] },
  { id: 'g_nani', category: '문법', tags: ['발음', 'なに/なん'], label: 'なに/なん (무엇)', tipKo: '"무엇". 뒤에 오는 소리에 따라 なん으로 변해요 — なんですか(뭐예요?), なんじ(몇 시), なんめいさま(몇 분). 점원의 질문에도 자주 들어 있어요.', detail: '무엇을 뜻하는 의문사는 기본형이 なに이지만, 뒤에 오는 소리에 따라 발음이 なん으로 자연스럽게 바뀌는 특징이 있습니다. 특히 です・だ 앞이나 じ・ど 같은 특정 자음 앞에서는 거의 항상 なん으로 바뀌어, なんですか(뭐예요), なんじ(몇 시), なんめいさま(몇 분이세요, 인원수를 묻는 점원 표현)처럼 실전에서 정말 자주 마주치게 됩니다. なにですか라고 표기 그대로 말하면 다소 부자연스럽게 들리므로, です 바로 앞에서는 반드시 なん으로 바뀐다는 규칙을 기억해 두는 것이 좋습니다. 메뉴판이나 안내판에서 뜻을 모르는 글자를 만났을 때 これはなんですか(이건 뭐예요)라고 가리키며 물어보면, 대부분의 상황에서 유용하게 활용할 수 있는 만능 질문이 됩니다.', exampleJa: 'これはなんですか', exampleKo: '이건 뭐예요?', commonMistake: 'なにですか라고 하면 어색해요 — です 앞에서는 なん.', action: '메뉴판을 가리키며 これはなんですか를 말해 보세요.', n5Refs: ['n5_g_nani'] },
  { id: 'g_itsu', category: '문법', tags: ['체크인', '예약', 'いつ', '언제'], label: 'いつ (언제)', tipKo: '"언제". いつですか 하나로 출발 시간·체크인·영업 시작을 모두 물을 수 있어요.', detail: 'いつ는 "언제"라는 뜻으로 날짜·요일·시기 등 시점 전반을 폭넓게 묻는 의문사이며, いつですか라는 짧은 한 문장만으로도 체크인 시간, 예약일, 영업 시작일처럼 다양한 상황에 대응할 수 있는 활용도 높은 표현입니다. 헷갈리기 쉬운 짝으로 なんじ(몇 시)가 있는데, いつ는 "어느 날, 어느 시점"이라는 좀 더 넓은 범위를, なんじ는 "몇 시 몇 분"이라는 구체적인 시각을 묻는다는 차이가 있어 상황에 맞게 구분해서 써야 합니다. 예를 들어 체크인 날짜나 가능 시기를 물을 때는 いつ가 자연스럽고, 정확한 시각을 알고 싶을 때는 なんじ를 쓰는 것이 더 적절합니다. チェックインはいつですか(체크인은 언제예요)처럼 예약 확인이 필요한 순간에 이 표현을 붙여 물어보는 연습을 해두면 실전에서 유용하게 쓸 수 있습니다.', exampleJa: 'チェックインはいつですか', exampleKo: '체크인은 언제예요?', commonMistake: 'なんじ(몇 시)와 혼동 — いつ는 날짜·시점 전반, なんじ는 시각.', action: '예약 확인할 때 いつですか를 붙여 물어보세요.', n5Refs: ['n5_g_itsu'] },
  { id: 'g_dare', category: '문법', tags: ['예약', '분실물', '우산', 'だれ'], label: 'だれ (누구)', tipKo: '"누구". 정중하게는 どなた. 분실물 확인이나 예약자 확인에서 だれの〜(누구의 ~)로 자주 등장해요.', detail: 'だれ는 "누구"를 뜻하는 의문사로, 소유를 물을 때 だれの〜(누구의 ~)라는 형태로 특히 자주 쓰입니다. これはだれのかばんですか(이건 누구 가방이에요)처럼 분실물을 확인하거나, 예약자·소지품의 주인을 확인하는 상황에서 실용적으로 활용됩니다. 격식 있는 자리나 점원이 손님을 상대로 물을 때는 더 정중한 표현인 どなた를 쓰는데, 예를 들어 예약자 성함을 물을 때 どなたさまでしょうか(어느 분이신가요) 같은 형태로 자주 등장합니다. 여행자 입장에서는 だれ와 どなた가 같은 뜻이라는 것만 알아두면, 점원이 どなた를 쓰더라도 당황하지 않고 자연스럽게 알아들을 수 있습니다. だれの〜ですか 패턴에 가방·우산·짐 같은 명사를 바꿔 넣으며 소지품을 확인하는 연습을 해두면 실전에서 요긴하게 쓸 수 있습니다.', exampleJa: 'これはだれのかばんですか', exampleKo: '이건 누구 가방이에요?', commonMistake: '점원이 손님에게는 どなた를 써요 — 들었을 때 같은 뜻으로 이해하세요.', action: 'だれの〜ですか 패턴으로 소지품을 물어보는 연습을 해 보세요.', n5Refs: ['n5_g_dare'] },
  { id: 'g_dou', category: '문법', tags: ['どう', '어때요'], label: 'どう (어떻게·어때요)', tipKo: '"어떻게/어때요". どうですか(어때요?), どうやって(어떻게 해서)로 확장됩니다. 점원의 いかがですか는 どうですか의 정중 버전이에요.', detail: 'どう는 "어떻게" 또는 "어때요"라는 뜻의 의문사로, どうですか(어때요, 상태나 감상을 물음)와 どうやって(어떻게 해서, 방법을 물음)처럼 뒤에 붙는 말에 따라 쓰임이 확장되는 기초 어휘입니다. 음식점에서 맛이 어떤지, 물건이 마음에 드는지 물을 때 あじはどうですか(맛은 어때요)처럼 자주 쓰이며, 이에 대한 대답은 いいです(좋아요)나 완곡하게 거절할 때는 ちょっと…(좀…)라고 말끝을 흐리는 것이 일본어다운 자연스러운 응답입니다. 점원이나 격식 있는 자리에서는 どうですか 대신 いかがですか라는 더 정중한 버전을 쓰는데, 이 두 표현이 같은 뜻이라는 것을 모르면 마치 전혀 다른 새 단어처럼 느껴져 순간적으로 못 알아듣는 경우가 많습니다. どうですか와 いかがですか를 같은 뜻으로 미리 연결지어 기억해 두면, 어느 쪽을 들어도 자연스럽게 응답할 수 있습니다.', exampleJa: 'あじはどうですか', exampleKo: '맛은 어때요?', commonMistake: 'いかがですか를 다른 단어로 알아 못 알아듣는 경우가 많아요 — 같은 뜻.', action: 'どうですか에 いいです/ちょっと…로 답하는 연습을 해 보세요.', n5Refs: ['n5_g_dou'] },
  { id: 'g_josuushi', category: '문법', tags: ['식당', '우산', '조수사', '개수', '단위'], label: '조수사 〜枚・〜本・〜人', tipKo: '세는 말이 물건마다 달라요 — 표·티켓은 〜まい(枚), 병·우산은 〜ほん(本), 사람은 〜にん(人, 단 1명 ひとり·2명 ふたり). 매표소·식당에서 바로 쓰입니다.', detail: '일본어는 물건을 셀 때 그 물건의 모양이나 성질에 따라 다른 조수사(단위)를 붙이는 것이 특징으로, 종이처럼 납작한 표·티켓·접시는 〜まい(枚), 병이나 우산처럼 길쭉한 물건은 〜ほん(本), 사람을 셀 때는 〜にん(人)을 쓰되 1명과 2명만 예외적으로 ひとり・ふたり라는 고유어 형태를 씁니다. 앞서 배운 ひとつ・ふたつ 시리즈로 전부 뭉뚱그려 세도 의사소통 자체는 대부분 통하지만, 매표소에서 표를 ふたつ라고 하거나 사람 수를 ふたつ라고 하면 원어민에게는 다소 어색하게 들릴 수 있습니다. 매표소에서 표를 살 때는 きっぷをにまいください(표를 두 장 주세요), 술을 주문할 때는 ビールをいっぽんください(맥주를 한 병 주세요)처럼 물건과 어울리는 조수사를 붙이는 연습을 해두면 훨씬 자연스러운 일본어를 구사할 수 있습니다.', exampleJa: 'きっぷをにまいください', exampleKo: '표를 두 장 주세요.', commonMistake: '전부 〜つ로 세도 통하긴 하지만, 티켓을 ふたつ라고 하면 어색해요.', action: 'きっぷをにまい, ビールをいっぽん처럼 물건+조수사로 주문해 보세요.', n5Refs: ['n5_g_josuushi', 'n5_g_counter_tsu'] },

  // ── 학습법(효율적 공부 요령) ──
  { id: 'g_study_srs', category: '학습법', tags: ['망각', '직전', '다시', '보기', '간격'], label: '망각 직전에 다시 보기(간격 반복)', tipKo: '외운 직후보다 "까먹기 직전"에 다시 보는 게 훨씬 오래 남아요. 이 앱의 복습 큐도 그 원리예요.', detail: '사람의 기억은 시간이 지날수록 지수적으로 흐려지는데, 완전히 잊기 직전에 한 번 더 떠올리면 그 기억이 훨씬 오래, 훨씬 튼튼하게 남는다는 것이 간격 반복(spaced repetition)의 핵심 원리입니다. 배운 직후에 열 번 반복하는 것보다, 하루 뒤·사흘 뒤·일주일 뒤처럼 점점 간격을 늘려가며 짧게 다시 보는 쪽이 장기 기억에는 훨씬 효율적입니다. "복습 큐"나 "약점 재도전" 배너가 뜨면 미루지 말고 그 자리에서 바로 풀어보는 것이 이 원리를 가장 잘 활용하는 방법입니다.', action: '오늘 뜬 복습 배너를 미루지 말고 바로 눌러 풀어보세요.' },
  { id: 'g_study_output', category: '학습법', tags: ['소리', '내어', '답하기'], label: '읽기보다 소리 내어 답하기', tipKo: '눈으로만 보면 "아는 것 같은" 착각에 빠지기 쉬워요. 실제로 소리 내어 답해봐야 진짜 아는지 드러나요.', detail: '외국어 학습에서 가장 흔한 착각은 문장을 눈으로 읽고 "이해했다"고 느끼는 것과, 실제로 그 문장을 스스로 만들어 말할 수 있는 것 사이의 간극입니다. 읽을 때는 답이 이미 눈앞에 있어 쉽게 느껴지지만, 막상 소리 내어 답하려고 하면 단어가 바로 안 나오는 경우가 훨씬 많습니다. 그래서 이 앱의 퀴즈·미션이 항상 "듣고 고르기"나 "말하기"로 끝나는 것인데, 조용히 훑어보고 넘어가기보다 매번 소리 내어 답해보는 습관이 실력 향상에 훨씬 직접적으로 연결됩니다.', action: '다음 세션에서는 답을 고르기 전에 소리 내어 먼저 말해보세요.' },
  { id: 'g_study_mistake_log', category: '학습법', tags: ['카드', '발음', '한자', '틀린', '리스트'], label: '틀린 것만 모은 나만의 리스트', tipKo: '한 번 틀린 카드는 또 틀릴 확률이 높아요. "약점" 탭에 자동으로 모이니, 주기적으로 들여다보는 습관을 들이면 좋아요.', detail: '한 번 틀린 표현이나 글자는 그 이유(비슷한 발음, 헷갈리는 한자, 어순 실수 등)가 있는 경우가 많아, 다시 틀릴 확률도 평균보다 높습니다. 이 앱은 오답을 자동으로 "약점" 탭에 모아두므로, 따로 노트를 만들 필요 없이 그 탭만 주기적으로 훑어봐도 나의 취약점이 무엇인지 한눈에 파악할 수 있습니다. 여행을 앞두고 있다면 출발 며칠 전에는 새로운 내용보다 이 약점 목록부터 한 번 훑는 것이 실전에서 더 도움이 됩니다.', action: '이번 주말엔 새 내용 대신 "약점" 탭만 한 번 훑어보세요.' },
  { id: 'g_study_daily_short', category: '학습법', tags: ['매일', '10분'], label: '몰아서 1시간보다 매일 10분', tipKo: '주말에 몰아서 하는 것보다 매일 짧게 하는 쪽이 기억에 훨씬 오래 남습니다. 뇌는 자는 동안 기억을 정리해요.', detail: '같은 총 학습 시간이라도 하루에 몰아서 공부하는 것보다 매일 조금씩 나눠서 하는 쪽이 장기 기억에 훨씬 유리하다는 것은 여러 학습 연구에서 반복적으로 확인된 사실입니다. 이는 수면 중에 뇌가 낮 동안 입력된 정보를 정리하고 강화하는 과정을 거치기 때문인데, 매일 학습하면 이 "수면 강화" 효과를 매번 누릴 수 있지만 몰아서 하면 그 기회가 한 번뿐입니다. 여행 준비 기간이 짧더라도 하루 30분씩 2주가, 주말에 몰아서 하는 7시간보다 실전에서 더 잘 통합니다.', action: '오늘 딱 10분만, 부담 없이 한 세션만 해보세요.' },
  { id: 'g_study_sound_first', category: '학습법', tags: ['카드', '한자', '가나', '소리', '먼저'], label: '글자보다 소리를 먼저', tipKo: '아기가 말부터 배우고 글자는 나중에 배우듯, 일본어도 소리로 먼저 익히면 읽기가 훨씬 쉬워져요.', detail: '모국어를 배울 때 우리는 글자보다 소리를 먼저 익히고, 그 소리에 대응하는 글자는 한참 뒤에 배웁니다. 외국어 학습에서도 이 순서를 존중하면 훨씬 유리한데, 어떤 단어의 소리와 뜻을 먼저 확실히 알아둔 뒤에 그 표기(가나·한자)를 보면 훨씬 빠르게 외워지고 오래 남습니다. 이 앱의 카드들이 항상 음성을 먼저 들려주고 그다음에 글자를 보여주는 순서로 되어 있는 것도 같은 이유이니, 답을 보기 전에 먼저 들어보는 습관을 들이면 좋습니다.', action: '카드가 나오면 글자를 보기 전에 먼저 소리부터 들어보세요.' },
  { id: 'g_study_context_word', category: '학습법', tags: ['카드', '단어', '문장'], label: '단어 하나보다 문장 하나', tipKo: '단어만 따로 외우면 실전에서 안 나와요. 짧은 문장째로 외우면 상황이 오면 바로 튀어나옵니다.', detail: '단어를 사전 순서로 하나씩 외우면 뜻은 알아도 실제 대화에서 그 단어가 언제, 어떤 문장 구조로 쓰이는지 감이 잡히지 않아 막상 필요한 순간에 입이 떨어지지 않는 경우가 많습니다. 반대로 "これ、ひとつください(이거 하나 주세요)"처럼 짧은 문장 통째로 익혀두면, 실제로 그 상황이 닥쳤을 때 문장 전체가 하나의 덩어리로 튀어나옵니다. 이 앱이 단어 카드보다 짧은 실전 문장 카드를 중심으로 구성된 것도 이런 "덩어리 학습"이 여행 회화에 훨씬 효과적이기 때문입니다.', action: '오늘 외운 표현을 실제 문장째로 소리 내어 세 번 말해보세요.' },
  { id: 'g_study_error_ok', category: '학습법', tags: ['카드', '학습', '일부'], label: '틀리는 게 학습의 일부', tipKo: '틀린 문제를 부끄러워하지 마세요. 틀려야 그 카드가 복습 목록에 들어가서 결국 더 잘 외워집니다.', detail: '많은 학습자가 오답을 "실패"로 여기고 위축되지만, 실제로는 오답이야말로 그 카드를 복습 대상으로 표시해주는 신호로 작용해 장기적으로는 더 확실히 기억하게 도와주는 역할을 합니다. 한 번도 안 틀리고 다 맞히는 세션은 오히려 난이도가 너무 쉬웠다는 뜻일 수도 있어, 적당히 틀리면서 배우는 쪽이 실력이 더 빨리 늡니다. 오답이 나오면 "아, 이건 복습 목록에 저장되겠구나"라고 편하게 받아들이는 마음가짐이 꾸준한 학습에 훨씬 도움이 됩니다.', action: '다음에 틀리면 바로 "오답만 다시 잡기"로 넘어가 그 자리에서 굳혀 보세요.' },
  { id: 'g_study_immersion', category: '학습법', tags: ['억양', '여행', '일본', '콘텐츠', '열기'], label: '여행 전 일본 콘텐츠로 귀 열기', tipKo: '출발 2~3주 전부터 일본 예능·브이로그를 자막과 함께 틀어두면, 현지에서 실제 억양·속도에 덜 놀라게 됩니다.', detail: '교재 음성은 또박또박하고 속도도 일정하지만, 실제 점원이나 현지인의 말은 훨씬 빠르고 생략도 많아서 처음 들으면 당황하기 쉽습니다. 출발 몇 주 전부터 일본 예능이나 브이로그, 짧은 뉴스를 한국어 자막과 함께 틀어두는 것만으로도 실제 억양과 리듬에 귀가 조금씩 익숙해지는 효과가 있습니다. 완벽히 알아듣지 못해도 괜찮으니, 매일 배경음처럼 켜두는 것만으로도 현지 도착 후 체감 난이도가 확 낮아집니다.', action: '오늘 밤 자막 있는 일본 영상 하나를 배경으로 틀어보세요.' },
  { id: 'g_study_goal_sentence', category: '학습법', tags: ['카드', '오늘', '문장', '정하기'], label: '"오늘 할 수 있는 것" 한 문장 정하기', tipKo: '"오늘은 이 표현 하나만 확실히"처럼 세션마다 목표를 문장 하나로 좁히면 성취감이 뚜렷해져요.', detail: '"일본어를 잘하고 싶다"처럼 막연한 목표는 오늘 무엇을 했는지 스스로 확인하기 어려워 동기가 쉽게 흐려집니다. 반대로 미션 카드 상단에 적힌 "이걸 할 수 있다" 문장처럼, 그날 배울 내용을 구체적인 한 문장 목표로 좁혀두면 세션이 끝났을 때 "오늘은 이걸 해냈다"는 확실한 성취감을 느낄 수 있습니다. 이런 작은 성취감의 반복이 결국 꾸준한 학습 습관을 만드는 가장 큰 동력이 됩니다.', action: '세션 시작 전, 오늘의 목표 문장을 한 번 소리 내어 읽어보세요.' },
  { id: 'g_study_review_before_sleep', category: '학습법', tags: ['카드', '자기', '직전', '5분', '복습'], label: '자기 직전 5분 복습의 힘', tipKo: '잠들기 직전에 본 내용은 수면 중 기억 강화 과정을 거쳐 더 오래 남는다는 연구가 많아요.', detail: '수면은 단순한 휴식이 아니라 낮 동안 입력된 정보를 정리하고 장기 기억으로 옮기는 적극적인 과정으로, 특히 잠들기 직전에 마지막으로 접한 정보가 이 과정에서 우선적으로 강화되는 경향이 있다는 연구 결과가 많습니다. 그래서 하루 중 아무 때나 학습하는 것보다, 자기 직전 5분을 활용해 그날 배운 표현을 가볍게 한 번 더 훑어보는 것이 기억 정착에 특히 효과적입니다. 부담 없이 오늘 배운 카드 몇 개만 다시 보고 잠드는 습관을 들이면, 다음 날 훨씬 또렷하게 기억나는 경험을 할 수 있습니다.', action: '오늘 잠들기 전, 배운 카드 5개만 가볍게 다시 훑어보세요.' },

  // ── 마트·쇼핑(슈퍼·드럭스토어·편의점 실전) ──
  { id: 'g_mart_drugstore_vs_conbini', category: '마트·쇼핑', tags: ['면세', '체크인', '숙소', '편의점', '드럭스토어'], label: '드럭스토어가 편의점보다 저렴해요', tipKo: '같은 생수·과자도 편의점보다 드럭스토어(ドラッグストア)가 대체로 더 저렴해요. 급하지 않으면 드럭스토어를 먼저 찾아보세요.', detail: '편의점은 24시간 운영과 접근성이라는 편리함의 대가로 가격이 슈퍼·드럭스토어보다 다소 높게 책정되는 경우가 많습니다. 반면 마츠모토키요시·웰시아 같은 드럭스토어 체인은 생수·과자·화장품·상비약까지 폭넓게 취급하면서도 가격 경쟁이 치열해 전반적으로 저렴한 편이고, 관광객 대상 면세와 포인트 적립 혜택도 잘 갖춰져 있습니다. 급하게 뭔가 필요한 게 아니라면, 숙소 주변 드럭스토어 위치를 미리 확인해두고 그곳에서 생필품을 사는 습관을 들이면 여행 경비를 상당히 아낄 수 있습니다.', exampleJa: 'ドラッグストアはどこですか', exampleKo: '드럭스토어는 어디에 있나요?', action: '숙소 체크인 후 근처 드럭스토어 위치부터 검색해두세요.' },
  { id: 'g_mart_tax_free_passport', category: '마트·쇼핑', tags: ['면세', '숙소', '여권', '가능'], label: '면세는 여권이 있어야만 가능', tipKo: '免税(めんぜい) 표시가 있는 매장에서 일정 금액 이상 사면 세금을 빼주는데, 반드시 여권 원본을 지참해야 해요.', detail: '免税(면세) 마크가 붙은 매장에서 일정 금액(통상 5,000엔) 이상을 구매하면 소비세를 면제받을 수 있는데, 이 절차는 반드시 여권 원본 제시가 필수이며 사본이나 사진으로는 처리되지 않습니다. 계산대에서 免税でお願いします(면세로 부탁합니다)라고 먼저 말해두면 직원이 별도 카운터나 절차로 안내해주고, 여권에 구매 내역이 첨부되는 방식으로 처리됩니다. 일부 소모품(화장품·식품 등)은 포장을 개봉하면 면세 혜택이 무효가 되고 출국 전까지 개봉하지 않는다는 조건이 붙으니, 이 점도 미리 알아두면 계산대에서 당황하지 않습니다.', exampleJa: '免税でお願いします', exampleKo: '면세로 부탁합니다.', commonMistake: '여권을 숙소에 두고 나오면 그 자리에서 면세를 못 받아요.', action: '쇼핑 예정일에는 항상 여권을 챙겨 나가세요.', missionIds: ['C43'] },
  { id: 'g_mart_expiry_labels', category: '마트·쇼핑', tags: ['편의점', '표시', '종류'], label: '유통기한 표시 두 종류', tipKo: '消費期限(しょうひきげん)은 "이 날짜까지 먹어야" 하는 안전 기한, 賞味期限(しょうみきげん)은 "이 날짜까지 맛있다"는 품질 기한이에요.', detail: '일본의 식품 포장에는 두 가지 다른 성격의 날짜 표시가 있는데, 消費期限은 도시락·삼각김밥처럼 상하기 쉬운 식품에 붙는 "이 날짜까지 안전하게 먹어야 하는" 소비기한이고, 賞味期限은 과자·통조림처럼 비교적 오래가는 식품에 붙는 "이 날짜까지가 가장 맛있는" 품질 유지 기한입니다. 賞味期限이 하루 이틀 지났다고 해서 바로 상하는 것은 아니지만, 消費期限이 지난 식품은 안전을 위해 먹지 않는 것이 원칙입니다. 편의점 도시락류를 살 때는 특히 消費期限 표시를 확인하는 습관을 들이면 좋습니다.', action: '도시락을 살 때는 포장 뒷면의 消費期限 날짜를 한 번 확인해보세요.' },
  { id: 'g_mart_self_checkout', category: '마트·쇼핑', tags: ['현금', '카드', '편의점', '셀프계산대', '사용'], label: '셀프계산대 사용 순서', tipKo: '바구니를 스캐너 옆에 놓고 하나씩 찍은 뒤, 화면에서 결제 수단을 고르면 됩니다. 헷갈리면 근처 직원 호출 버튼을 누르세요.', detail: '일본 슈퍼·편의점의 셀프계산대(セルフレジ)는 대부분 바코드를 하나씩 스캔한 뒤 화면에서 현금·카드·전자결제 중 원하는 결제 수단을 선택하는 흐름으로 되어 있어, 한 번 순서를 익히면 언어 장벽 없이도 쉽게 쓸 수 있습니다. 스캔과 결제가 완전히 분리된 "세미셀프" 방식(직원이 스캔, 손님이 결제만 셀프계산기에서)도 흔한데, 이 경우 직원이 상품을 스캔한 뒤 옆의 결제 전용 기계를 가리키며 안내해줍니다. 사용법이 헷갈리면 화면 근처의 呼び出し(호출) 버튼을 누르거나 すみません이라고 말하면 직원이 도와줍니다.', exampleJa: 'つかいかたがわかりません', exampleKo: '사용법을 모르겠어요.', action: '처음 쓸 땐 옆 사람의 순서를 한 번 관찰한 뒤 따라 해보세요.' },
  { id: 'g_mart_sample_manner', category: '마트·쇼핑', tags: ['매너', '백화점', '시식', '코너'], label: '시식 코너, 하나만 정중하게', tipKo: '슈퍼 시식 코너(試食·ししょく)는 보통 한 사람당 하나가 매너예요. 마음에 들면 いただきます 한마디와 함께 감사 인사를 곁들이면 좋아요.', detail: '슈퍼마켓이나 백화점 지하 식품매장에는 신제품이나 제철 식재료를 맛볼 수 있는 시식 코너(試食)가 자주 마련되어 있는데, 이는 어디까지나 맛보기용이라 한 사람이 여러 개를 연달아 집는 것은 매너에 어긋난다고 여겨집니다. 시식을 하기 전에 가볍게 목례하고, 맛본 뒤에는 おいしいです(맛있어요)나 짧은 감사 인사를 건네면 담당 직원도 좋아하고 자연스러운 인상을 남길 수 있습니다. 아이를 동반한 경우 아이 몫까지 계산해서 하나씩만 집는 것이 일반적인 암묵적 규칙입니다.', exampleJa: 'おいしいです', exampleKo: '맛있어요.', action: '시식 후에는 짧게라도 감사 인사를 건네보세요.' },
  { id: 'g_mart_ship_to_hotel', category: '마트·쇼핑', tags: ['공항', '호텔', '체크인', '숙소', '기념품'], label: '무거운 짐, 호텔로 택배 보내기', tipKo: '쇼핑몰이나 대형 매장에서 산 무거운 물건은 숙소로 택배(宅配便)를 보내는 서비스가 있는 경우가 많아요.', detail: '가전제품·주류·부피 큰 기념품처럼 무겁거나 부피가 큰 쇼핑 품목은 그날 그대로 들고 다니기보다, 매장에 마련된 택배(宅配便) 서비스를 이용해 숙박 중인 호텔이나 공항으로 미리 보내두는 방법이 훨씬 편합니다. 대부분의 대형 쇼핑몰이나 가전 양판점에는 이런 발송 서비스 데스크가 있고, 호텔 이름과 체크인 날짜만 정확히 알려주면 직원이 절차를 안내해줍니다. 짐이 무거워질 것 같은 쇼핑을 계획하고 있다면, 미리 ホテルにおくれますか(호텔로 보낼 수 있나요)라는 표현을 알아두면 유용합니다.', exampleJa: 'ホテルにおくれますか', exampleKo: '호텔로 보낼 수 있나요?', action: '큰 쇼핑 전에는 매장에 택배 서비스가 있는지 먼저 물어보세요.' },
  { id: 'g_mart_fukubukuro', category: '마트·쇼핑', tags: ['편의점', '세일', '정월', '미스터리', '쇼핑백'], label: '정월의 미스터리 쇼핑백 후쿠부쿠로', tipKo: '福袋(ふくぶくろ)는 1월 초에만 파는 "복주머니" — 안에 뭐가 들었는지 모르고 사는 대신 정가보다 훨씬 저렴해요.', detail: '福袋(후쿠부쿠로, 복주머니)는 매년 1월 초 신년 세일 시즌에만 등장하는 일본 특유의 쇼핑 문화로, 봉투 안에 어떤 상품이 들어있는지 모른 채 정가 대비 훨씬 저렴한 가격에 구매하는 일종의 "럭키백"입니다. 의류 브랜드부터 편의점, 캐릭터 상품점까지 다양한 매장이 이 이벤트를 진행하며, 인기 브랜드의 후쿠부쿠로는 개점 전부터 긴 줄이 늘어서는 진풍경을 만들기도 합니다. 정확히 무엇이 들어있을지 예측할 수 없다는 "뽑기"의 재미가 이 문화의 핵심이라, 1월 초에 일본을 여행한다면 한 번쯤 시도해볼 만한 경험입니다.', action: '1월 초 방문이라면 관심 브랜드 매장에 후쿠부쿠로가 있는지 물어보세요.' },
  { id: 'g_mart_pb_brand', category: '마트·쇼핑', tags: ['편의점', '마트', '카레', '조사'], label: '편의점 자체 브랜드가 의외로 고품질', tipKo: '세븐프리미엄·훼미리마트 컬렉션 같은 PB(자체 브랜드) 상품은 유명 브랜드보다 저렴하면서 품질도 준수해서 현지인도 즐겨 사요.', detail: '일본 편의점·마트 체인들은 セブンプレミアム(세븐일레븐), ファミマル(훼미리마트)처럼 자체 브랜드(PB) 상품을 적극적으로 운영하는데, 이들은 대형 제조사 브랜드보다 저렴하면서도 품질 관리가 까다로워 현지인들 사이에서도 평판이 좋은 경우가 많습니다. 특히 냉동식품·레토르트 카레·과자류는 PB 상품만 모아 사도 충분히 만족스러운 여행 간식 쇼핑이 됩니다. 브랜드 이름에 얽매이지 말고 PB 코너를 한 번 둘러보는 것도 알뜰하게 쇼핑하는 요령입니다.', action: '편의점에서 PB 브랜드 코너를 한 번 따로 둘러보세요.' },
  { id: 'g_mart_how_many_left', category: '마트·쇼핑', tags: ['재고', '품절', '문의'], label: '"이거 몇 개 남았어요?" 물어보기', tipKo: '한정 수량 상품이 품절 직전일 때 これ、まだありますか(이거 아직 있나요)로 재고를 물어볼 수 있어요.', detail: '한정판 과자나 인기 상품은 매대에 진열된 것 외에 창고에 여분이 있는 경우가 많아, 눈앞에 보이는 것이 마지막이라고 생각해 포기하기 전에 これ、まだありますか(이거 아직 있나요)라고 한 번 물어보는 것이 좋습니다. 특히 지역 한정판이나 시즌 한정 상품은 뒤쪽 창고에 재고가 남아있는 경우가 흔하므로, 직원에게 물어보는 것만으로 원하는 물건을 구할 수 있는 확률이 꽤 올라갑니다. 재고가 없다면 ないです(없어요)라는 짧은 대답이 돌아오니 그 자체로도 확인이 빠릅니다.', exampleJa: 'これ、まだありますか', exampleKo: '이거 아직 있나요?', action: '품절 직전으로 보이는 한정 상품은 주저 말고 재고를 물어보세요.' },
  { id: 'g_mart_bag_charge', category: '마트·쇼핑', tags: ['편의점', '유료', '기본'], label: '비닐봉투는 유료가 기본', tipKo: '일본도 비닐봉투 유료화가 시행돼서 봉투가 필요 없으면 ふくろはいりません(봉투 필요 없어요)이라고 미리 말하면 됩니다.', detail: '일본은 환경 정책의 일환으로 편의점·슈퍼의 비닐봉투를 유료화했기 때문에, 봉투가 필요 없다면 계산 전에 미리 ふくろはいりません(봉투 필요 없어요)이라고 말하는 것이 자연스러운 흐름입니다. 반대로 봉투가 필요하면 그냥 가만히 있어도 대부분 필요 여부를 물어보므로 だいじょうぶです(괜찮아요, 필요 없다는 뜻으로도 쓰임)나 おねがいします(부탁합니다, 필요하다는 뜻)로 짧게 답하면 됩니다. 에코백이나 작은 접이식 가방을 하나 챙겨 다니면 봉투값도 아끼고 환경에도 도움이 되는 습관이 됩니다.', exampleJa: 'ふくろはいりません', exampleKo: '봉투 필요 없어요.', action: '작은 에코백 하나를 가방에 늘 넣고 다녀보세요.' },

  // ── 요즘 일본(최근 여행 트렌드) ──
  { id: 'g_trend_cashless', category: '요즘 일본', tags: ['현금', '카드', 'Suica', 'PASMO', '식당'], label: '캐시리스 결제가 빠르게 확산 중', tipKo: 'PayPay·라인페이 같은 QR결제가 소규모 식당·노점까지 퍼져서, 신용카드보다 QR결제만 되는 곳도 늘고 있어요.', detail: '몇 년 전까지만 해도 일본은 현금 중심 사회로 유명했지만, 최근 PayPay·LINE Pay 같은 QR코드 기반 결제가 빠르게 확산되면서 오히려 신용카드는 안 받아도 QR결제는 받는 소규모 식당이나 노점이 늘고 있습니다. 다만 해외 발급 카드로는 이런 로컬 QR결제 앱에 가입하기 까다로운 경우가 많아, 여행자 입장에서는 국제 브랜드 교통카드(Suica·PASMO의 모바일 버전)나 국제 카드가 되는 결제 수단을 함께 준비하는 것이 안전합니다. 결제 전 이 가게에서 어떤 수단이 되는지 미리 물어보는 습관이 갈수록 중요해지고 있습니다.', exampleJa: 'カードは使えますか', exampleKo: '카드 쓸 수 있나요?', action: '가게에 들어가기 전, 입구에 붙은 결제수단 스티커를 먼저 확인해보세요.' },
  { id: 'g_trend_overtourism', category: '요즘 일본', tags: ['매너', '교토', '오버투어리즘', '캠페인'], label: '오버투어리즘과 매너 캠페인', tipKo: '교토 등 인기 관광지는 관광객 급증으로 주민 불편이 커져서, 사진 촬영 제한·매너 안내판이 부쩍 늘었어요.', detail: '교토의 게이샤 거리 기온(祇園)처럼 특정 인기 관광지에서는 관광객 급증으로 사생활 침해나 소음 문제가 커지면서, 일부 골목은 사진 촬영을 아예 금지하고 위반 시 과태료를 부과하는 조례까지 등장했습니다. 이런 지역에서는 "이 정도는 괜찮겠지"라는 생각보다 현장에 붙은 안내판과 규칙을 꼼꼼히 확인하는 것이 중요하며, 특히 사유지나 좁은 골목에서의 촬영은 각별히 조심해야 합니다. 여행자가 이런 규칙을 존중하는 태도를 보이는 것이 장기적으로 관광지와 주민이 공존하는 데 도움이 됩니다.', commonMistake: '골목이 예쁘다고 무단으로 들어가 촬영하면 과태료 대상이 될 수 있어요.', action: '인기 관광지에서는 촬영 금지 안내판을 먼저 확인하는 습관을 들이세요.' },
  { id: 'g_trend_accommodation_tax', category: '요즘 일본', tags: ['현금', '체크인', '체크아웃', '숙소', '예약'], label: '숙박세(宿泊税)가 늘고 있어요', tipKo: '도쿄·교토·오사카 등 일부 지자체는 숙박료에 소액의 숙박세를 별도로 부과해요. 체크아웃 때 현금으로 따로 받는 곳도 있어요.', detail: '도쿄·교토·오사카를 비롯한 여러 지자체가 관광 인프라 재원 마련을 위해 숙박세(宿泊税)를 도입했는데, 이는 숙박 요금과 별도로 1박당 일정 금액(대개 100~수백 엔 수준, 요금대에 따라 차등)을 추가로 부과하는 제도입니다. 예약 사이트 결제에 이미 포함된 경우도 있지만, 체크아웃 시 프런트에서 현금으로 별도 징수하는 숙소도 많으므로 소액의 현금을 여유 있게 챙겨두는 것이 좋습니다. 정확한 세율과 부과 방식은 지자체와 숙소마다 달라, 체크인할 때 프런트에 한 번 물어보면 확실합니다.', exampleJa: '宿泊税はありますか', exampleKo: '숙박세가 있나요?', action: '체크아웃 전날, 숙박세용 소액 현금을 미리 확인해두세요.' },
  { id: 'g_trend_self_service_hotel', category: '요즘 일본', tags: ['카드', '호텔', '체크인', '예약'], label: '무인 체크인 호텔이 늘고 있어요', tipKo: '키오스크에서 여권 스캔하고 카드키를 직접 뽑는 무인 체크인 비즈니스호텔이 최근 부쩍 늘었어요.', detail: '인력 부족과 비용 절감을 이유로, 최근 일본의 비즈니스호텔 체인들은 프런트 직원 대신 로비의 키오스크에서 여권을 스캔하고 결제한 뒤 카드키를 직접 발급받는 무인·반무인 체크인 시스템을 빠르게 도입하고 있습니다. 화면은 대부분 다국어(영어·중국어·한국어)를 지원하지만, 기계 오류나 예약 확인이 안 될 때를 대비해 전화나 인터폰으로 연결되는 비상 버튼의 위치를 미리 확인해두면 안심할 수 있습니다. 사람과의 대화 연습 기회는 줄어들지만, 반대로 언어 장벽 없이 절차를 화면으로 차근차근 따라갈 수 있다는 장점도 있습니다.', action: '키오스크 체크인 시, 화면에서 언어를 한국어로 먼저 바꿔보세요.' },
  { id: 'g_trend_luggage_delivery', category: '요즘 일본', tags: ['신칸센', '공항', '호텔', '숙소'], label: '짐 없이 이동하는 "手ぶら旅行"', tipKo: '手ぶら(てぶら, 빈손) 여행 서비스로 공항·역에서 짐을 맡기고 몸만 이동한 뒤, 호텔에서 짐을 받는 방식이 인기예요.', detail: '手ぶら旅行(테부라 료코, "빈손 여행")는 공항이나 주요 역에서 짐을 맡기면 당일 또는 다음 날 숙소로 배송해주는 서비스로, 특히 신칸센으로 여러 도시를 이동하는 여행자들 사이에서 큰 짐 없이 편하게 이동할 수 있어 인기를 끌고 있습니다. 공항 도착 당일 캐리어를 맡기고 관광부터 시작하거나, 다음 도시로 이동하기 전날 짐을 미리 부쳐두는 식으로 활용하면 좁은 열차 안에서 큰 짐 때문에 불편할 일이 줄어듭니다. 서비스마다 배송 소요 시간이 다르므로, 당일 필요한 물건은 작은 가방에 따로 챙기는 것이 요령입니다.', exampleJa: '手ぶら旅行はできますか', exampleKo: '빈손 여행 서비스 되나요?', action: '다음 도시로 이동하기 전날, 짐 배송 서비스가 있는지 검색해보세요.' },
  { id: 'g_trend_solo_seating', category: '요즘 일본', tags: ['라멘', '초밥', '이자카야', '1인', '여행객'], label: '1인 여행객을 위한 좌석이 늘고 있어요', tipKo: '라멘집 특유의 1인용 칸막이 좌석이 이제 카페·이자카야에도 확산돼, 혼자 여행해도 어색하지 않게 즐길 수 있어요.', detail: '원래 라멘 체인점 특유의 문화였던 1인용 칸막이 좌석(独り席)이 최근에는 카페, 회전초밥, 심지어 일부 이자카야에까지 확산되면서, 혼자 여행하는 사람도 눈치 보지 않고 편하게 식사할 수 있는 환경이 크게 늘었습니다. "일본은 혼밥하기 좋은 나라"라는 인식이 예전부터 있었지만, 최근에는 이런 물리적인 좌석 배치 변화까지 더해져 1인 여행객에게 더욱 친화적인 환경이 되고 있습니다. 메뉴판에 1인석 여부가 따로 표시되지 않는 경우도 많으니, 입구에서 ひとりです(혼자예요)라고 말하면 적절한 자리로 안내해줍니다.', exampleJa: 'ひとりです', exampleKo: '혼자예요.', action: '혼자 여행 중이라면 입구에서 자신 있게 ひとりです라고 말해보세요.' },
  { id: 'g_trend_ic_card_unified', category: '요즘 일본', tags: ['카드', 'IC카드', 'Suica', 'PASMO', '전철'], label: '전국 교통 IC카드가 거의 통일됐어요', tipKo: 'Suica·PASMO 등 지역별 IC카드가 이제 전국 거의 대부분의 전철·버스에서 호환돼요. 하나만 있으면 충분해요.', detail: '예전에는 지역마다 발급되는 교통 IC카드(간토의 Suica·PASMO, 간사이의 ICOCA 등)가 서로 호환되지 않아 지역을 옮길 때마다 새 카드를 사야 하는 불편이 있었지만, 최근에는 전국 주요 교통 IC카드 대부분이 상호 호환되도록 통일되어 하나의 카드로 전국 거의 모든 전철·버스·편의점 결제까지 해결할 수 있게 되었습니다. 스마트폰의 모바일 Suica 기능을 쓰면 실물 카드 없이 폰만으로 개찰구를 통과하고 결제까지 할 수 있어, 최근에는 이 방식을 선호하는 여행자도 늘고 있습니다. 다만 일부 지방 소도시의 버스는 여전히 호환이 안 되는 경우가 있으니, 처음 타는 노선이라면 확인 차 물어보는 것이 안전합니다.', exampleJa: 'このカードはつかえますか', exampleKo: '이 카드 쓸 수 있나요?', action: '처음 가는 지역의 버스를 탈 땐 IC카드 호환 여부를 먼저 확인해보세요.' },
  { id: 'g_trend_multilingual_signage', category: '요즘 일본', tags: ['공항', '한자', '다국어', '안내판', '표기'], label: '다국어 안내판이 부쩍 늘었어요', tipKo: '역·관광지 안내판이 일본어·영어·중국어·한국어 4개 언어로 표기되는 경우가 이제 표준이 됐어요.', detail: '외국인 관광객 급증에 대응해, 최근 몇 년 사이 일본의 주요 역·공항·관광지 안내판은 일본어·영어·중국어(간체)·한국어 4개 언어를 함께 표기하는 것이 사실상 표준이 되었습니다. 이 덕분에 한자를 몰라도 한국어 표기만 찾아 읽으면 웬만한 안내는 다 이해할 수 있어, 예전보다 훨씬 여행하기 편한 환경이 되었습니다. 다만 소규모 로컬 상점이나 오래된 시설은 여전히 일본어 단독 표기인 경우가 많으니, 이 경우엔 사진을 찍어 번역 앱으로 확인하는 습관을 들이면 좋습니다.', action: '안내판에서 먼저 한국어 표기가 있는지 훑어보는 습관을 들이세요.' },
  { id: 'g_trend_convenience_evolution', category: '요즘 일본', tags: ['현금', '편의점', '백화점', '택배'], label: '편의점이 점점 작은 백화점처럼', tipKo: '최근 편의점은 즉석 커피·베이커리·택배·복사·ATM·티켓 발권까지 다 되는 종합 생활 거점이 됐어요.', detail: '일본 편의점은 이제 단순히 물건을 사는 곳을 넘어, 즉석 원두커피와 베이커리, 택배 발송·수령, 복사·팩스·프린트, ATM 현금 인출, 콘서트·전시 티켓 발권, 공과금 납부까지 처리하는 사실상의 종합 생활 거점으로 진화했습니다. 여행 중 예상치 못한 문제(짐 보내기, 인쇄, 현금 부족 등)가 생기면 일단 가까운 편의점부터 들어가 보는 것이 대부분 해결책이 될 만큼 기능이 다양해졌습니다. 이런 다기능성 때문에 편의점은 "여행자의 만능 해결사"로 불릴 정도로 활용도가 높습니다.', action: '여행 중 곤란한 일이 생기면 일단 가까운 편의점부터 들어가 보세요.' },

  // ── 일정별 팁(당일치기·단기·한달살기) ──
  { id: 'g_trip_daytrip_light', category: '일정별 팁', tags: ['마트', '당일치기'], label: '당일치기는 짐을 최소화하세요', tipKo: '당일치기라면 코인로커에 짐을 맡기고 몸만 가볍게 다니는 게 훨씬 효율적이에요.', detail: '숙박 없이 당일치기로 여러 도시를 오가는 일정이라면, 큰 캐리어를 그대로 끌고 다니기보다 첫 도착역의 코인로커에 짐을 맡기고 작은 가방만 챙겨 다니는 편이 이동 효율과 체력 모두에서 훨씬 유리합니다. 요즘은 스마트폰 앱으로 빈 로커 위치를 미리 확인할 수 있는 역도 많아, 도착하자마자 로커를 찾아 헤매는 시간을 줄일 수 있습니다. 하루 안에 여러 장소를 봐야 한다면, 짐의 무게가 곧 그날 체력과 시간의 낭비로 직결된다는 점을 꼭 기억해두세요.', action: '당일치기 전날, 목적지 역의 코인로커 위치를 미리 검색해두세요.' },
  { id: 'g_trip_short_packing', category: '일정별 팁', tags: ['드럭스토어', '우산', '3박', '절반'], label: '3박 4일이면 절반만 챙기고 나머지는 현지에서', tipKo: '짧은 여행일수록 다 챙기려다 짐이 커져요. 웬만한 생필품은 드럭스토어에서 훨씬 저렴하게 살 수 있어요.', detail: '3박 4일처럼 짧은 일정에서는 만약을 대비해 이것저것 다 챙기다 보면 오히려 캐리어가 무거워져 이동이 불편해지는 역설이 생깁니다. 세면도구나 상비약, 우산처럼 부피가 큰 생필품은 웬만하면 현지 드럭스토어에서 저렴하게 구할 수 있으므로, 출국 전에는 여권·지갑·충전기처럼 대체 불가능한 것 위주로만 챙기고 나머지는 현지 조달을 염두에 두는 것이 훨씬 가볍고 효율적인 짐 싸기 요령입니다. 짧은 일정일수록 짐의 부피가 이동 동선 전체에 미치는 영향이 크다는 것을 기억해두면 좋습니다.', action: '출국 전, 캐리어에서 현지 드럭스토어로 대체 가능한 물건을 한 번 빼보세요.' },
  { id: 'g_trip_month_lease', category: '일정별 팁', tags: ['호텔', '예약', '한달살기', '맨스리', '맨션'], label: '한달살기는 맨스리 맨션이 편해요', tipKo: '한 달 이상 머문다면 호텔보다 マンスリーマンション(월 단위 임대)이 훨씬 저렴하고 주방도 있어 편해요.', detail: 'マンスリーマンション(맨스리 맨션)은 최소 계약 기간이 한 달 단위인 단기 임대 주택으로, 매일 청소와 서비스가 포함된 호텔보다 숙박 단가가 훨씬 저렴하면서도 주방·세탁기가 딸려 있어 장기 체류에 훨씬 실용적입니다. 대부분 인터넷 예약 사이트에서 외국인도 여권만으로 계약할 수 있고, 보증인이나 복잡한 심사 없이 빠르게 입주할 수 있는 것이 일반 임대 계약과의 큰 차이점입니다. 한 달 이상 한 도시에 머물 계획이라면 호텔 요금을 30일치 계산해보기 전에, 먼저 맨스리 맨션 시세부터 비교해보는 것이 좋습니다.', action: '한달살기를 계획 중이라면 맨스리 맨션 예약 사이트부터 검색해보세요.' },
  { id: 'g_trip_month_hospital', category: '일정별 팁', tags: ['숙소', '한달살기', '동네', '병원', '미리'], label: '한달살기 중이라면 동네 병원을 미리 알아두세요', tipKo: '장기 체류 중 아플 걸 대비해, 도착 초기에 숙소 근처 내과·약국 위치를 미리 확인해두면 안심이 돼요.', detail: '짧은 여행에서는 여행자보험으로 급한 상황만 대처하면 되지만, 한 달 이상 머무는 경우에는 감기나 컨디션 난조로 병원에 가야 할 상황이 생길 확률이 훨씬 높아집니다. 도착 초기, 아직 몸 상태가 괜찮을 때 숙소 근처의 내과(内科)와 야간에도 문을 여는 약국 위치를 미리 확인해두면, 막상 아플 때 급하게 검색하며 헤매는 스트레스를 크게 줄일 수 있습니다. 여행자보험 가입 여부와 관계없이, 처방전이 필요한 약은 반드시 병원 진료를 거쳐야 한다는 점도 함께 기억해두면 좋습니다.', action: '도착 첫 주에 숙소 근처 병원·약국 위치를 지도 앱에 저장해두세요.' },
  { id: 'g_trip_jr_pass_calc', category: '일정별 팁', tags: ['신칸센', 'JR패스', '단기', '손익', '계산'], label: '단기 여행이라면 JR패스 손익부터 계산', tipKo: '여러 도시를 신칸센으로 오가는 일정이면 JR패스가 이득이지만, 한 도시 위주라면 오히려 낱장 승차권이 저렴할 수 있어요.', detail: 'JR패스는 정해진 기간 동안 JR 노선을 무제한 이용할 수 있는 패스지만, 신칸센 왕복 등 장거리 이동이 여러 번 있어야 본전을 뽑는 구조이기 때문에 한 도시 위주로 머물며 근교만 살짝 다녀오는 일정이라면 오히려 그때그때 낱장 승차권을 사는 편이 더 저렴할 수 있습니다. 여행 전 예상 이동 구간의 개별 승차권 요금을 다 더해보고, 그 합계가 패스 가격보다 큰지 작은지 계산해보는 것이 손해를 피하는 확실한 방법입니다. 최근에는 패스 가격이 인상되면서 이 손익분기점도 예전보다 높아졌다는 점을 참고하면 좋습니다.', action: '패스 구매 전, 예상 이동 구간의 개별 승차권 요금 합계부터 계산해보세요.' },
  { id: 'g_trip_month_laundry', category: '일정별 팁', tags: ['숙소', '장마', '한달살기', '빨래', '루틴'], label: '한달살기의 빨래 루틴 만들기', tipKo: '맨스리 맨션에 세탁기가 있어도 건조까지 되는 경우는 드물어요. 근처 코인 빨래방의 건조기 위치도 함께 알아두세요.', detail: '맨스리 맨션 대부분은 세탁기가 딸려 있지만 건조기까지 갖춘 곳은 상대적으로 드물어서, 특히 장마철이나 겨울철에는 실내 건조만으로 빨래가 잘 마르지 않는 문제를 겪기 쉽습니다. 숙소 근처에 건조기를 갖춘 코인 빨래방(コインランドリー) 위치를 미리 알아두면, 세탁은 집에서 하고 건조만 빨래방에서 해결하는 식으로 효율적인 루틴을 만들 수 있습니다. 장기 체류 초반에 이런 생활 인프라를 파악해두는 것이 이후 한 달을 훨씬 편하게 만들어줍니다.', action: '입주 첫 주에 근처 코인 빨래방 위치와 요금을 확인해두세요.' },
  { id: 'g_trip_short_lost_backup', category: '일정별 팁', tags: ['카드', '단기', '여행', '분실', '대비'], label: '단기 여행은 분실 대비를 이중으로', tipKo: '짧은 일정일수록 여권·카드 분실 시 대응할 시간이 부족해요. 사본을 클라우드에 미리 올려두세요.', detail: '일정이 짧을수록 여권이나 카드를 분실했을 때 재발급이나 임시 서류를 처리할 시간적 여유가 상대적으로 부족해, 최악의 경우 남은 일정 전체에 영향을 줄 수 있습니다. 출국 전 여권 사진 면과 카드 앞뒤를 촬영해 클라우드나 이메일에 미리 올려두면, 분실 시 대사관이나 카드사에 신고할 때 훨씬 빠르게 대응할 수 있습니다. 짧은 여행일수록 이런 사전 대비의 가치가 상대적으로 더 크다는 점을 기억해두면 좋습니다.', action: '출국 전, 여권과 카드 사진을 클라우드에 미리 백업해두세요.' },
  { id: 'g_trip_month_sim', category: '일정별 팁', tags: ['카드', '신사', '한달살기', '현지', '회선'], label: '한달살기는 유심보다 현지 회선이 나을 수도', tipKo: '한 달 이상 머문다면 관광객용 데이터 유심보다, 현지 통신사의 단기 회선이 데이터 용량 대비 더 저렴한 경우가 많아요.', detail: '며칠짜리 여행에는 관광객 전용 데이터 유심이나 e심이 간편하지만, 한 달 이상 머무는 경우에는 데이터 사용량이 누적되면서 관광객용 요금제가 오히려 더 비싸지는 경우가 흔합니다. 이런 경우 라쿠텐 모바일 같은 현지 통신사의 단기·저가 회선으로 갈아타면 데이터 용량 대비 비용을 크게 줄일 수 있는데, 다만 일부 회선은 일본 내 주소나 재류카드가 필요할 수 있어 계약 전 조건을 미리 확인해야 합니다. 체류 기간이 길어질수록 통신비도 무시할 수 없는 고정 비용이 된다는 점을 염두에 두세요.', action: '한달살기라면 도착 첫 주에 현지 통신사 단기 요금제를 비교해보세요.' },
  { id: 'g_trip_daytrip_weather', category: '일정별 팁', tags: ['우산', '당일치기', '날씨', '변수'], label: '당일치기는 날씨 변수에 더 취약해요', tipKo: '숙박 없는 당일치기는 갑자기 비가 와도 일정을 못 미뤄요. 우산과 여벌 양말을 작은 가방에 넣어두면 든든해요.', detail: '숙박이 있는 일정이라면 비가 와도 다음 날로 일정을 조정할 여유가 있지만, 당일치기는 그날 하루가 전부이기 때문에 갑작스러운 날씨 변화에 훨씬 취약합니다. 작은 접이식 우산과 여벌 양말 한 켤레만 가방에 넣어두어도, 갑자기 비가 쏟아졌을 때 나머지 일정을 훨씬 덜 힘들게 이어갈 수 있습니다. 당일치기 전날 밤에는 반드시 시간대별 강수 확률까지 확인해두는 습관을 들이면 좋습니다.', action: '당일치기 전날 밤, 시간대별 강수 확률까지 확인해두세요.' },

  // ── 재미·잡학(가볍게 읽는 도시전설·트리비아 — 라이브러리 전용, 학습 세션엔 섞이지 않아요) ──
  // 2026-07-20: 100개는 너무 많다는 피드백으로 관련 있는 두 이야기씩 묶어 50개로 압축하고,
  // 흔한 실수·바로 해보기·실전 예제 필드를 채웠다(트리비아 성격에 맞게 "오해·해볼 것·관련 일본어 한마디"로 재해석).
  { id: 'g_fun_bathhouse_history', category: '재미·잡학', tags: ['예약', '온천', '목욕탕', '혼욕', '노천탕'], label: '에도시대 목욕탕의 숨은 역사', libraryOnly: true, tipKo: '지금은 남녀 온천이 나뉘지만 에도시대엔 혼욕(混浴)이 흔했고, 목욕탕엔 손님 시중을 들던 여성 종업원 유나(湯女)도 있었어요.', detail: '에도시대까지 대중목욕탕과 온천은 남녀 구분 없는 혼욕(混浴)이 자연스러운 풍경이었는데, 메이지 정부가 서구에 "미개하다"는 인상을 주지 않으려 남녀 분리를 법제화하며 지금의 모습이 됐습니다. 같은 시기 목욕탕엔 손님의 머리를 감기고 등을 밀어주던 유나(湯女)라는 여성 종업원도 있었으나, 접객이 도를 넘자 막부가 이를 금지하며 목욕탕은 순수하게 씻는 공간으로 정리됐습니다.', commonMistake: '혼욕을 일본 전역의 오래된 관습이라 오해하기 쉽지만, 지금은 법으로 금지되고 일부 산간 노천탕에만 예외로 남아 있어요.', action: '온천 예약 전 男湯(남탕)·女湯(여탕) 표시를 꼭 확인해보세요.', exampleJa: '混浴はできますか', exampleKo: '혼욕 가능한가요?' },
  { id: 'g_fun_sento_details', category: '재미·잡학', tags: ['목욕탕', '유행', '도쿄', '동네', '정겨운'], label: '동네 목욕탕의 정겨운 디테일 두 가지', libraryOnly: true, tipKo: '목욕탕 벽화가 늘 후지산인 이유와, 사물함 열쇠가 유독 크고 투박한 이유엔 각각 재밌는 사연이 있어요.', detail: '목욕탕 벽에 후지산을 그리는 관행은 1912년 도쿄의 한 목욕탕 주인이 아이들을 위해 화가에게 부탁한 것이 시초로 알려져 전국으로 퍼졌습니다. 사물함 열쇠가 크고 투박한 나무 팻말에 달린 것도 우연이 아니라, 옷을 벗고 있는 동안 잃어버리기 쉬운 상황을 고려해 일부러 눈에 띄고 손목에 차기 편하게 디자인한 것입니다.', commonMistake: '벽화가 어느 목욕탕에나 있는 고대 전통이라 생각하기 쉽지만, 실은 20세기 초에 시작된 비교적 최근 유행이에요.', action: '동네 목욕탕에 가면 벽화와 사물함 열쇠 디자인을 유심히 살펴보세요.' },
  { id: 'g_fun_onsen_rules', category: '재미·잡학', tags: ['예약', '온천', '목욕탕', '규칙'], label: '온천에서 꼭 알아야 할 규칙 두 가지', libraryOnly: true, tipKo: '탕에 들어가기 전 몸부터 씻어야 하고, 문신이 있으면 입장이 제한될 수 있어요 — 둘 다 이유가 있는 규칙이에요.', detail: '온천·목욕탕의 공용 탕은 몸을 씻는 곳이 아니라 담그고 쉬는 곳이라, 반드시 별도 샤워 자리에서 먼저 몸을 씻어야 합니다. 문신 손님 제한은 문신이 오랫동안 야쿠자의 상징으로 여겨져 온 역사 때문인데, 최근엔 문신 스티커로 가리면 허용하거나 전용 시간을 두는 시설도 늘고 있습니다.', commonMistake: '문신 규정이 모든 시설에 똑같이 적용된다고 생각하기 쉽지만, 시설마다 기준이 달라 예약 전 확인이 필요해요.', action: '탕에 들어가기 전 샤워 자리부터 찾아 몸을 씻는 습관을 들이세요.', exampleJa: 'タトゥーがあっても入れますか', exampleKo: '문신이 있어도 들어갈 수 있나요?' },
  { id: 'g_fun_sumo_rituals', category: '재미·잡학', tags: ['스모', '경기', '정화', '의식'], label: '스모 경기 전 정화 의식 두 가지', libraryOnly: true, tipKo: '소금을 뿌리고 다리를 높이 들어 땅을 밟는 시코(四股) — 둘 다 씨름판을 정화하는 신토 의식이에요.', detail: '스모 선수가 경기 전 씨름판에 소금을 뿌리는 것은 소금의 정화력을 빌려 부상과 액운을 씻어낸다는 신토(神道) 의식이고, 한쪽 다리를 최대한 높이 들었다 힘차게 밟는 시코(四股)는 땅속 악귀를 밟아 쫓아낸다는 의미를 담고 있습니다. 둘 다 단순한 퍼포먼스가 아니라 씨름판을 신성한 공간으로 여기는 스모의 종교적 뿌리를 보여줍니다.', commonMistake: '소금 뿌리기를 단순한 쇼로 여기기 쉽지만, 실제로는 매 경기 진지하게 반복되는 정화 의식이에요.', action: '스모 경기 영상에서 소금 뿌리기와 시코 동작을 순서대로 찾아보세요.' },
  { id: 'g_fun_sumo_rank_topknot', category: '재미·잡학', tags: ['스모', '선수', '상투', '계급'], label: '스모 선수의 상투와 최고 계급', libraryOnly: true, tipKo: '은퇴할 때 수백 명이 돌아가며 잘라주는 상투(断髪式)와, 한번 오르면 강등이 없는 최고 계급 요코즈나(横綱) 이야기예요.', detail: '스모 선수가 은퇴하면 단마게식(断髪式)이라는 의식에서 인연 있던 수백 명이 조금씩 가위질하며 상투를 잘라주고 마지막엔 스승이 마무리합니다. 최고 계급 요코즈나는 승급 기준이 극도로 엄격한 대신, 일단 오르면 성적이 나빠도 강등되지 않고 그 자격에 못 미치면 스스로 은퇴하는 것이 관례인 독특한 명예직입니다.', commonMistake: '요코즈나도 다른 계급처럼 성적 나쁘면 강등된다고 오해하기 쉽지만, 실제론 강등 없이 은퇴만 있는 유일한 계급이에요.', action: '좋아하는 스모 선수의 은퇴식 영상을 찾아 상투 자르는 순서를 지켜보세요.' },
  { id: 'g_fun_sumo_body_stage', category: '재미·잡학', tags: ['식당', '신사', '스모', '무대'], label: '스모를 만드는 몸과 신성한 무대', libraryOnly: true, tipKo: '거대한 몸을 만드는 찌개 찬코나베와, 신사 지붕을 본뜬 씨름판 위 지붕 — 둘 다 스모의 정체성을 보여줘요.', detail: '찬코나베는 도장에서 선수들이 함께 만들어 먹는 고단백 찌개로, 살을 찌우는 동시에 훈련으로 지친 몸을 회복시키도록 구성돼 있습니다. 씨름판 위에 매달린 지붕은 신사 본전 지붕 양식을 그대로 본뜬 것으로, 경기장 전체가 신을 모시는 신성한 공간이라는 세계관을 담고 있습니다.', action: '은퇴한 스모 선수가 운영하는 찬코나베 식당을 여행 중 한번 찾아보세요.', exampleJa: 'ちゃんこ鍋を食べてみたいです', exampleKo: '찬코나베를 먹어보고 싶어요.' },
  { id: 'g_fun_shinkansen_service', category: '재미·잡학', tags: ['신칸센', '7분', '기적', '청소팀', '비밀'], label: '신칸센 "7분의 기적" 청소팀의 비밀', libraryOnly: true, tipKo: '테세이 청소팀은 7분 만에 좌석 청소는 물론 방향까지 돌려놔, 승객은 늘 진행 방향을 보고 앉게 돼요.', detail: '테세이(TESSEI) 청소팀은 종착역 도착 후 단 7분 만에 좌석 정리·청소를 마치는 것으로 유명해 하버드 경영대학원 사례로도 다뤄졌는데, 이 작업엔 좌석 등받이를 반대로 돌리는 것도 포함됩니다. 신칸센 좌석은 레버 하나로 전체가 회전하도록 설계돼, 열차가 방향을 바꿀 때마다 모든 좌석을 일괄적으로 돌려 항상 진행 방향을 보게 만듭니다.', action: '플랫폼에서 청소팀의 좌석 회전 작업을 잠깐 지켜보세요.' },
  { id: 'g_fun_shinkansen_names', category: '재미·잡학', tags: ['신칸센', '이름', '담긴', '뜻들'], label: '신칸센이라는 이름에 담긴 뜻들', libraryOnly: true, tipKo: '"탄환열차"라는 별명과, 노조미(희망)·히카리(빛)·코다마(메아리)라는 등급 이름 — 둘 다 속도감을 담은 작명이에요.', detail: '신칸센은 건설 초기 코드네임이 "弾丸列車(탄환열차)"였던 데서 영어 별명 Bullet Train이 유래했습니다. 도카이도 신칸센의 세 등급은 가장 빠른 순서대로 노조미(希望·희망)·히카리(光·빛)·코다마(こだま·메아리)로 이름 붙여, 속도가 느릴수록 "이 역 저 역 다 들르며 되돌아오는 메아리"라는 이미지를 담았습니다.', commonMistake: '노조미가 제일 비싸고 빠른 등급이라 "특별한" 이름 같지만, 사실 세 이름 모두 대등하게 시적인 이미지에서 나온 것이에요.', exampleJa: 'のぞみとひかり、どちらが速いですか', exampleKo: '노조미와 히카리 중 어느 게 더 빨라요?' },
  { id: 'g_fun_shinkansen_lore', category: '재미·잡학', tags: ['신칸센', '둘러싼', '이야기'], label: '신칸센을 둘러싼 특별한 이야기', libraryOnly: true, tipKo: '보면 행운이 온다는 점검열차 닥터옐로우와, 한때 국철이었다가 민영화된 JR — 신칸센의 과거와 현재예요.', detail: '닥터옐로우는 선로를 점검하는 노란색 특수 신칸센으로 시간표가 공개되지 않아, 우연히 마주치면 행운이 온다는 속설이 생겼습니다. 지금의 JR은 원래 정부가 운영하던 일본국유철도였는데, 누적된 부채 문제로 1987년 지역별 회사로 분할 민영화된 뒤 서비스 품질이 크게 개선됐다는 평가를 받습니다.', action: '여행 중 노란 신칸센을 우연히 본다면 사진을 남겨보세요 — 행운의 증거니까요.' },
  { id: 'g_fun_vending_kingdom', category: '재미·잡학', tags: ['자판기', '우동', '세계', '왕국'], label: '세계 최고의 자판기 왕국', libraryOnly: true, tipKo: '일본엔 약 400만 대의 자판기가 있고, 음료·과자를 넘어 즉석 우동까지 파는 자판기도 있어요.', detail: '일본은 인구 대비 자판기 밀도가 세계에서 손꼽히게 높아 전국에 약 400만 대가 설치돼 있다고 알려져 있으며, 치안이 좋고 전기 인프라가 안정적이라 야외 무인 기계가 훼손 없이 잘 유지될 수 있었던 배경으로 꼽힙니다. 음료·과자를 넘어 즉석 조리 우동, 삶은 계란, 신선한 꽃다발까지 파는 이색 자판기도 존재해 "뭐든 파는 나라"라는 별명이 붙었습니다.', commonMistake: '자판기가 다 비슷하다고 생각하기 쉽지만, 지역·장소마다 파는 품목이 크게 달라 발견하는 재미가 있어요.', action: '여행 중 신기한 자판기를 발견하면 무엇을 파는지 한번 들여다보세요.' },
  { id: 'g_fun_vending_hidden_functions', category: '재미·잡학', tags: ['카드', 'IC카드', '편의점', '자판기'], label: '자판기의 숨은 기능 두 가지', libraryOnly: true, tipKo: '밤새 켜진 불빛은 골목길 간이 조명이 되고, 담배 자판기는 성인인증 카드 타스포가 있어야 작동해요.', detail: '자판기는 밤에도 항상 밝게 불이 켜져 있어 가로등이 부족한 골목에서 은근히 간이 조명 역할을 하며 치안에도 도움이 된다는 분석이 있습니다. 반대로 담배 자판기는 미성년자 구매를 막기 위해 2008년부터 성인인증 IC카드 타스포(taspo)를 대야만 작동하도록 제도화됐는데, 외국인은 이 카드를 발급받기 어려워 담배는 편의점에서 사는 편이 간단합니다.', action: '담배가 필요하면 자판기 대신 편의점 계산대에서 직접 구매하세요.' },
  { id: 'g_fun_conbini_hidden_details', category: '재미·잡학', tags: ['편의점', '디테일'], label: '편의점의 숨은 디테일 두 가지', libraryOnly: true, tipKo: '삼각김밥 포장이 김을 눅눅하지 않게 지키는 특허 구조이고, 겨울엔 계산대 옆에 오뎅 코너가 등장해요.', detail: '삼각김밥 비닐 포장은 뜯기 전까지 김과 밥이 서로 안 닿게 분리해뒀다가 포장을 뜯는 순간 김이 밥을 감싸도록 설계된 특허 구조로, 진열대에 오래 있어도 김이 바삭함을 유지하게 해줍니다. 겨울이 되면 편의점 계산대 옆에 오뎅 냄비가 등장해 손님이 원하는 재료를 직접 골라 담아가는 셀프 판매 코너가 열리는데, 이는 일본에서 "겨울이 왔다"는 계절 신호로 여겨집니다.', action: '다음에 삼각김밥을 뜯을 때 포장 뜯는 순서 번호를 따라 그 정교함을 느껴보세요.' },
  { id: 'g_fun_late_night_lodging', category: '재미·잡학', tags: ['전철', '호텔', '숙소', '캡슐호텔', '오사카'], label: '막차 문화가 낳은 두 가지 숙박업', libraryOnly: true, tipKo: '막차를 놓친 회사원을 위해 탄생한 캡슐호텔과, 심야 만화카페·사우나 성행 — 둘 다 "막차 문화"의 산물이에요.', detail: '캡슐호텔은 1979년 오사카에서 막차를 놓쳤거나 야근한 회사원이 저렴하게 하룻밤을 해결하도록 고안된 숙박 형태가 시초입니다. 대도시 전철이 자정 전후로 끊기다 보니 막차를 향해 전력 질주하는 직장인의 모습이 흔한 풍경이 됐고, 막차를 놓친 사람들의 수요 덕분에 심야 영업 만화카페·사우나 같은 업종도 함께 성행하게 됐습니다.', action: '막차 시간이 걱정되면 미리 심야 영업 숙소·만화카페 위치를 검색해두세요.' },
  { id: 'g_fun_showa_service_jobs', category: '재미·잡학', tags: ['호텔', '백화점', '시대', '남긴', '서비스업'], label: '쇼와 시대가 남긴 서비스업 두 가지', libraryOnly: true, tipKo: '러브호텔은 좁은 집에서 사생활을 지키려 발달한 정식 숙박업이고, 백화점 엘리베이터 걸은 정중한 안내로 유명했던 전담 직원이에요.', detail: '러브호텔은 흔히 오해받지만, 여러 세대가 좁은 집에 함께 사는 주거 환경에서 부부·연인이 사생활을 지킬 공간으로 발달한 정식 인허가 숙박업입니다. 쇼와 시대 백화점에는 흰 장갑을 낀 엘리베이터 걸이 층별 안내를 전담해 정중한 멘트로 유명했는데, 지금은 자동화로 대부분 사라졌지만 일부 백화점이 특별 행사 때 재현하기도 합니다.', commonMistake: '러브호텔을 불법적인 업소로 오해하기 쉽지만, 정식으로 인허가받은 합법 숙박업이에요.' },
  { id: 'g_fun_school_ghost_stories', category: '재미·잡학', tags: ['동전', '하나코상', '코쿠리상', '유령', '괴담'], label: '일본 학교괴담의 양대 스타', libraryOnly: true, tipKo: '화장실의 하나코상과 동전으로 여우신에게 묻는 코쿠리상 — 세대를 넘어 전해지는 두 괴담이에요.', detail: '花子さん(하나코상)은 "3층 여자화장실 세 번째 칸 문을 세 번 두드리면 대답한다"는 일본에서 가장 유명한 학교괴담 속 유령입니다. 코쿠리상(こっくりさん)은 동전 위에 손가락을 올리고 질문하면 여우 신이 답한다고 믿는 강령 놀이로, 서양의 위저보드가 메이지 시대 일본 토속 신앙과 결합해 변형된 것으로 추정됩니다.', commonMistake: '두 괴담을 최근에 생긴 도시전설로 여기기 쉽지만, 실은 수십 년간 세대를 거쳐 전해진 고전적인 학교괴담이에요.' },
  { id: 'g_fun_number_communication_quirks', category: '재미·잡학', tags: ['주차', '마트', '지진', '재난', '발음'], label: '숫자와 통신에 얽힌 일본의 습관', libraryOnly: true, tipKo: '死와 발음이 같은 숫자 4를 피하는 병원·주차장, 그리고 스마트폰 시대에도 재난 대비로 남아있는 공중전화예요.', detail: '숫자 4의 발음 し가 죽을 사(死)와 같아 병원 병실이나 층수, 주차 구역에서 4를 아예 건너뛰는 경우가 흔합니다. 한편 일본은 대지진 시 휴대폰 통신망이 마비될 가능성에 대비해 일정 수의 공중전화를 법적으로 유지하도록 규정하고 있는데, 실제 재난 때 통화료가 무료로 전환돼 비상 연락 수단으로 활용된 사례가 있습니다.', action: '엘리베이터를 타면 4층이 빠져 있는지 버튼을 한번 확인해보세요.' },
  { id: 'g_fun_sushi_misconceptions', category: '재미·잡학', tags: ['스시', '얽힌', '오해', '은어'], label: '스시에 얽힌 오해와 은어', libraryOnly: true, tipKo: '캘리포니아 롤은 사실 미국 발명품이고, "오아이소"라는 계산 표현은 원래 손님이 아닌 주인이 쓰던 말이었어요.', detail: '김이 안 보이게 뒤집어 마는 캘리포니아 롤은 1960~70년대 LA의 한 일본인 셰프가 서양 손님 입맛에 맞춰 만든 뒤 일본으로 역수입된 퓨전 스시입니다. "오아이소"는 원래 "정성이 부족했다"며 주인이 겸손하게 계산서를 내밀 때 쓰던 말인데, 지금은 손님이 계산을 청할 때 쓰는 은어로 굳어졌습니다.', commonMistake: '캘리포니아 롤을 전통 일본 스시로 오해하기 쉽지만, 실은 미국에서 태어나 일본으로 돌아온 메뉴예요.', exampleJa: 'すみません、お愛想お願いします', exampleKo: '저기요, 계산 부탁해요.' },
  { id: 'g_fun_lucky_charms', category: '재미·잡학', tags: ['다루마', '행운', '고양'], label: '행운을 부르는 고양이와 다루마', libraryOnly: true, tipKo: '사람보다 고양이가 많은 섬들과, 목표를 세울 때 한쪽 눈부터 채우는 다루마 인형 — 둘 다 행운의 상징이에요.', detail: '다시로지마·아오시마 같은 섬은 쥐를 쫓으려 기르던 고양이가 번식해 지금은 주민보다 고양이가 많은 것으로 유명해졌습니다. 빨간 오뚝이 다루마 인형은 눈동자가 빈 채로 팔리는데, 목표를 세울 때 왼쪽 눈을 채우고 이루면 오른쪽 눈마저 채우는 풍습이 있어 선거철 정치인의 다루마가 뉴스에 자주 등장합니다.', action: '새로운 목표를 세울 때 다루마 인형을 하나 사서 왼쪽 눈을 채워보세요.' },
  { id: 'g_fun_shrine_etiquette_pair', category: '재미·잡학', tags: ['신사', '참배', '오미쿠지', '예절'], label: '신사에서 지키는 두 가지 예절', libraryOnly: true, tipKo: '나쁜 운세 오미쿠지는 나무에 묶어두고, 참배 전엔 데미즈야에서 정해진 순서로 손을 씻어요.', detail: '오미쿠지 결과가 나쁘면 액운을 그 자리에 두고 간다는 의미로 집에 안 가져가고 신사 경내의 나무나 전용 줄에 묶어두는 풍습이 있습니다. 참배 전에는 데미즈야에서 오른손으로 왼손을, 국자를 옮겨 오른손을, 다시 왼손에 받은 물로 입을 헹구는 순서로 몸과 마음을 정갈히 합니다.', commonMistake: '오미쿠지가 나쁘면 다시 뽑아도 된다고 생각하기 쉽지만, 정식 예절은 묶어두고 그대로 받아들이는 거예요.', action: '신사에 가면 데미즈야에서 정해진 순서대로 손을 씻어보세요.' },
  { id: 'g_fun_visual_signals', category: '재미·잡학', tags: ['신사', '참배', '노렌', '간판', '표시'], label: '간판 대신 알려주는 두 가지 표시', libraryOnly: true, tipKo: '입구의 토리이(鳥居)면 신사, 가게 앞 천 노렌(暖簾)이 걸려 있으면 영업 중이라는 뜻이에요.', detail: '신사 입구엔 토리이라는 문이 서 있고 절엔 산문·불상이 있어 이 차이로 구분할 수 있으며, 참배법도 신사는 손뼉을 치고 절은 합장만 하는 점이 다릅니다. 노렌은 가게 이름이 새겨진 짧은 천으로, 걸려 있으면 영업 중·안으로 들이면 영업 종료라는 신호를 겸하는 간판입니다.', action: '거리를 걸으며 노렌이 걸린 가게와 걷힌 가게를 구분해보세요.' },
  { id: 'g_fun_ramen_efficiency_culture', category: '재미·잡학', tags: ['라멘', '자판기', '라멘집', '효율적인', '문화'], label: '라멘집의 효율적인 두 가지 문화', libraryOnly: true, tipKo: '이치란 같은 "대화 금지" 칸막이 좌석과, 주문 실수를 줄여주는 식권 자판기예요.', detail: '이치란 등 일부 라멘집은 옆자리와 완전히 분리된 칸막이 좌석에서 최소한의 접촉만으로 주문이 끝나게 해, 손님이 면발 온도가 식기 전 최상의 상태로 즐기는 데만 집중하게 합니다. 입구의 식권 자판기는 인건비를 줄이고 언어가 다른 손님과의 소통 실수를 방지해 최근 몇 년 새 빠르게 늘었는데, 여행자에겐 오히려 사진 붙은 버튼만 누르면 되는 편리한 시스템입니다.', action: '식권 자판기가 있는 라멘집에서 사진 버튼만으로 주문해보세요.' },
  { id: 'g_fun_ramen_status', category: '재미·잡학', tags: ['라멘', '도쿄', '홋카이도', '국물', '다른'], label: '라멘의 국물과 격이 다른 인정', libraryOnly: true, tipKo: '돈코츠·쇼유·미소·시오 4대 국물 계보와, 세계 최초로 미슐랭 별을 받은 라멘집 이야기예요.', detail: '일본 라멘은 국물 베이스에 따라 규슈식 돈코츠(豚骨), 도쿄식 쇼유(醤油), 홋카이도식 미소(味噌), 담백한 시오(塩) 네 계열로 나뉘어 지역마다 주류 스타일이 뚜렷이 갈립니다. 2015년 도쿄의 라멘집 츠타(蔦)는 세계 최초로 미슐랭 별을 받은 라멘 전문점이 되며, 서민 음식도 미슐랭에 오를 수 있다는 것을 보여줬습니다.', exampleJa: 'とんこつラーメンをください', exampleKo: '돈코츠 라멘 주세요.' },
  { id: 'g_fun_regional_noodle_pride', category: '재미·잡학', tags: ['우동', '다른', '국물', '자부심'], label: '지역마다 다른 면·국물 자부심', libraryOnly: true, tipKo: '"우동현"이라 불리는 가가와현의 우동 사랑과, 간토·간사이가 서로 다른 오뎅 국물 스타일이에요.', detail: '가가와현은 인구 대비 우동집 밀도가 압도적으로 높아 "우동현(うどん県)"이라는 별명이 실제 홍보 슬로건으로 쓰일 정도로 우동에 대한 지역 자부심이 강합니다. 오뎅도 간토는 진한 간장 국물, 간사이는 다시마·가다랑어로 우린 맑은 국물을 선호해 같은 음식이라도 지역별 색이 뚜렷이 갈립니다.', action: '우동집과 오뎅집을 지역별로 비교해 먹어보는 미식 여행도 재밌어요.' },
  { id: 'g_fun_hanami_scenes', category: '재미·잡학', tags: ['벚꽃', '홋카이도', '벚꽃놀', '둘러싼', '진풍경'], label: '벚꽃놀이를 둘러싼 두 가지 진풍경', libraryOnly: true, tipKo: '기상청이 발표하는 벚꽃 전선 예보와, 새벽부터 돗자리로 명당을 맡는 자리싸움이에요.', detail: '매년 봄 기상청은 규슈에서 홋카이도까지 올라가는 벚꽃 개화 예상선을 "사쿠라 젠센(벚꽃 전선)"이라는 이름으로 발표해 여행자들이 최적 시기를 계획하는 데 참고합니다. 유명 명소에서는 좋은 자리를 선점하려 새벽부터, 심지어 전날 밤부터 돗자리를 깔아 표시해두는 자리싸움이 매년 화제가 됩니다.', action: '벚꽃 여행을 계획한다면 출발 직전 최신 사쿠라 젠센 예보를 다시 확인하세요.' },
  { id: 'g_fun_seasonal_outdoor_fun', category: '재미·잡학', tags: ['소바', '타코야키', '축제', '벚꽃', '단풍'], label: '계절 축제의 즐길 거리 두 가지', libraryOnly: true, tipKo: '벚꽃 못지않은 단풍놀이 모미지가리와, 어느 축제를 가든 만나는 포장마차 단골 메뉴들이에요.', detail: '가을엔 봄 벚꽃놀이 못지않게 붉게 물든 단풍을 감상하는 모미지가리(紅葉狩り)를 즐기며, 이 역시 남에서 북으로 물드는 "단풍 전선"이 매년 예보됩니다. 축제 포장마차(屋台)에는 지역과 상관없이 타코야키·야키소바·사과사탕처럼 정해진 단골 메뉴가 늘어서, 어느 지역 축제를 가든 익숙한 라인업을 만날 수 있습니다.', action: '가을에 방문한다면 단풍 전선 예보를 참고해 단풍놀이 명소를 찾아보세요.' },
  { id: 'g_fun_summer_festival_highlights', category: '재미·잡학', tags: ['신사', '축제', '불꽃놀이', '유카타'], label: '여름 축제의 하이라이트 두 가지', libraryOnly: true, tipKo: '신을 태우고 거리를 도는 미코시 행렬과, 유카타 차림으로 즐기는 불꽃놀이 데이트예요.', detail: '미코시(神輿)는 축제 기간 신이 잠시 옮겨 타는 이동식 신사로 여겨지는 가마로, 지역 청년회가 어깨에 메고 구호를 외치며 거리를 행진하는 여름 축제의 대표 장면입니다. 하나비(불꽃놀이) 대회는 유카타를 맞춰 입고 게타를 신은 채 즐기는 것이 정석 데이트 코스로 자리 잡아, 청춘물 콘텐츠에도 단골로 등장합니다.', action: '여름에 방문한다면 유카타를 빌려 입고 불꽃놀이를 구경해보세요.' },
  { id: 'g_fun_holiday_crowds', category: '재미·잡학', tags: ['신사', '참배', '일본인', '명절', '장면'], label: '일본인이 몰리는 명절 두 장면', libraryOnly: true, tipKo: '공휴일이 몰린 골든위크와, 새해 첫 며칠 유명 신사에 수백만 명이 몰리는 하츠모데예요.', detail: '골든위크는 4월 말~5월 초 여러 공휴일이 한 주에 몰려 최대 9일 안팎의 연휴가 만들어지는 기간으로, 이 시기엔 국내외 여행 수요가 폭증해 항공권·숙박료가 크게 오릅니다. 하츠모데(새해 첫 참배)는 메이지신궁 같은 유명 신사에 새해 첫 사흘간 수백만 명이 몰려 몇 시간씩 줄을 서는 진풍경을 만듭니다.', commonMistake: '이 시기가 한적할 거라 기대하면 곤란해요 — 오히려 일 년 중 가장 붐비는 시기예요.' },
  { id: 'g_fun_neighborhoods_that_pull_crowds', category: '재미·잡학', tags: ['아이돌', '여행자', '동네'], label: '여행자를 끌어모으는 두 동네', libraryOnly: true, tipKo: '한류로 성장한 코리아타운 신오쿠보와, 애니메이션 배경지를 찾아가는 성지순례 마을이에요.', detail: '신오쿠보는 다문화 지역이었다가 2000년대 한류 붐을 타고 한국 음식·화장품·아이돌 굿즈점이 밀집한 코리아타운으로 성장했습니다. 애니메이션의 실제 배경 마을을 팬들이 찾아가는 세이치준레이(성지순례) 문화 덕분에, 인구가 줄던 작은 마을이 관광 명소로 되살아난 사례도 여럿 소개됩니다.', commonMistake: '신오쿠보를 관광객만 가는 곳으로 여기기 쉽지만, 실은 일본 젊은 세대에게도 인기 있는 나들이 명소예요.' },
  { id: 'g_fun_industrial_decline_to_culture', category: '재미·잡학', tags: ['오타쿠', '산업', '쇠퇴', '성지'], label: '산업 쇠퇴가 낳은 두 개의 성지', libraryOnly: true, tipKo: '공해로 황폐했던 섬이 현대미술관 성지가 된 나오시마와, 전자상가에서 오타쿠 문화의 중심지로 변신한 아키하바라예요.', detail: '나오시마는 제련소 공해로 황폐했던 작은 섬이었지만 1980년대부터 예술 프로젝트가 시작되며 유명 건축가의 미술관들이 들어서 세계적인 현대미술 순례지가 됐습니다. 아키하바라는 전후 라디오 부품 노점에서 출발해 전자상가로 성장했다가, 온라인 쇼핑에 밀린 빈자리를 애니메이션·게임 매장이 채우며 오타쿠 문화의 성지로 정체성을 바꿨습니다.', action: '나오시마를 방문한다면 미술관뿐 아니라 섬 전체에 흩어진 야외 설치작품도 찾아보세요.' },
  { id: 'g_fun_subculture_trends', category: '재미·잡학', tags: ['유행', '서브컬처', '아이돌', '일본', '만든'], label: '일본 서브컬처가 만든 두 가지 유행', libraryOnly: true, tipKo: '눕히지 않고도 읽히는 이모티콘 카오모지(^_^)와, 콘서트까지 여는 아이돌급 성우들이에요.', detail: '서양식 이모티콘과 달리 눕히지 않아도 표정이 보이는 카오모지(顔文字)는 1986년 한 PC통신 게시판에서 처음 등장했다고 알려져 있습니다. 일본 애니메이션 성우(声優)는 캐릭터 연기를 넘어 자신의 이름으로 음반을 내고 대형 콘서트를 여는 등 아이돌에 가까운 활동을 펼치는 독특한 산업 구조를 갖고 있습니다.', action: '좋아하는 애니메이션의 성우가 콘서트를 여는지 한번 검색해보세요.' },
  { id: 'g_fun_small_joys', category: '재미·잡학', tags: ['카드', '동전', '자판기', '정성', '만든'], label: '작은 정성이 만든 두 가지 즐거움', libraryOnly: true, tipKo: '동전 넣고 돌리는 캡슐토이 가챠가챠와, 캐릭터 얼굴로 꾸민 도시락 캬라벤이에요.', detail: '가챠가챠는 손잡이를 돌릴 때 나는 "가챠" 소리에서 이름 붙은 캡슐토이 자판기로, 이 무작위 뽑기 개념이 훗날 온라인 게임의 "가챠" 확률형 아이템으로 그대로 이어졌습니다(이 앱의 카드 뽑기 이름도 여기서 유래). 캬라벤은 아이 도시락을 김·달걀 등으로 오려 만화 캐릭터 얼굴로 꾸미는 문화로, 지금은 SNS에 완성작을 공유하는 취미 장르로도 발전했습니다.', action: '가챠가챠 매장에서 동전 몇 개로 캡슐토이를 직접 뽑아보세요.' },
  { id: 'g_fun_cute_designs', category: '재미·잡학', tags: ['카드', 'Suica', '축제', '벚꽃'], label: '귀여움을 담은 두 가지 디자인', libraryOnly: true, tipKo: '스이카 카드의 펭귄 캐릭터와, 지역마다 다른 화려한 맨홀 뚜껑 디자인이에요.', detail: '교통카드 Suica의 펭귄 마스코트는 매끄럽게 헤엄치는 이미지가 "개찰구를 막힘없이 통과한다"는 편리함을 상징한다는 컨셉에서 탄생했습니다. 많은 지자체는 하수도 맨홀 뚜껑에 지역 마스코트·벚꽃·축제 장면을 화려하게 그려 넣어, 이를 사진으로 수집하며 여행하는 "맨홀러" 마니아층까지 생겨났습니다.', action: '걷다가 화려한 맨홀 뚜껑을 발견하면 사진으로 남겨보세요.' },
  { id: 'g_fun_national_cheap_treats', category: '재미·잡학', tags: ['국민템'], label: '저렴하지만 확실한 두 가지 국민템', libraryOnly: true, tipKo: '다이소·세리아 등 색깔이 다른 100엔숍들과, 파격적인 한정판 맛으로 화제 모으는 아이스크림 가리가리군이에요.', detail: '일본 100엔숍은 다이소·세리아·캔두 등 여러 체인이 경쟁하는데, 다이소는 압도적인 매장 수와 품목 다양성을, 세리아는 인테리어 소품·디자인 문구 강점을 갖는 등 저마다 색깔이 달라 현지인은 원하는 것에 따라 골라 갑니다. 국민 막대 아이스크림 가리가리군은 저렴한 가격을 유지하면서도 파격적인 한정판 맛으로 매년 화제를 모아, 한 번은 실패작 맛에 회사가 공식 사과문을 낸 일화도 있습니다.', commonMistake: '100엔숍이 다 똑같다고 생각하기 쉽지만, 체인마다 강점이 달라 비교해보는 재미가 있어요.' },
  { id: 'g_fun_railway_trust', category: '재미·잡학', tags: ['일본', '신뢰', '습관'], label: '일본 철도의 신뢰를 만드는 습관 두 가지', libraryOnly: true, tipKo: '손가락으로 가리키며 복창하는 지적확인환창과, 1~2분 지연에도 사과 방송이 나오는 정시성이에요.', detail: '지적확인환창(指差喚呼)은 역무원·기관사가 신호나 계기판을 손가락으로 가리키고 소리 내어 확인하는 전통적인 안전 절차로, 실제로 실수를 크게 줄이는 효과가 검증돼 해외 안전관리 교육에도 참고됩니다. 일본 철도는 정시 운행률이 매우 높아 단 1~2분 지연에도 안내 방송으로 정중히 사과하며, 지각 사유 증명을 위한 지연증명서까지 역에서 발급해줍니다.', action: '역무원이 손가락으로 가리키며 확인하는 모습을 플랫폼에서 한번 관찰해보세요.' },
  { id: 'g_fun_precise_delivery_culture', category: '재미·잡학', tags: ['신칸센', '기차', '택배', '정교함', '배달'], label: '정교함이 돋보이는 배달·도시락 문화', libraryOnly: true, tipKo: '2시간 단위로 시간을 맞추는 택배 다쿠하이빈과, 지역마다 종류가 수천 가지인 기차역 도시락 에키벤이에요.', detail: '다쿠하이빈(宅急便)은 배송 희망 시간을 2시간 단위로 세밀하게 지정할 수 있고 실제로 그 시간을 정확히 지키는 것으로 정평이 나 있습니다. 에키벤은 기차역에서 파는 도시락으로 지역 특산물을 담은 한정판이 전국에 수천 종에 달해, 이를 수집하듯 찾아다니는 마니아층까지 있습니다.', action: '신칸센을 탈 일이 있다면 그 지역 한정 에키벤을 하나 골라 맛보세요.' },
  { id: 'g_fun_old_office_habits', category: '재미·잡학', tags: ['마트', '일본', '회사', '문화'], label: '여전히 남아있는 일본 회사 문화 두 가지', libraryOnly: true, tipKo: '스마트폰 시대에도 관공서에 남은 팩스와, 회의 전에 미리 다 정해두는 네마와시예요.', detail: '일본은 도장 날인 문화와 오래된 시스템 탓에 관공서·병원·중소기업에서 여전히 팩스를 공식 통신 수단으로 씁니다. 네마와시(根回し)는 공식 회의 전에 관계자들과 미리 물밑 조율을 끝내두는 의사결정 관행으로, 실제 회의는 이미 정해진 결론을 확인하는 자리에 가까운 경우가 많습니다.', commonMistake: '팩스가 완전히 사라졌을 거라 생각하기 쉽지만, 관공서·병원에는 여전히 현역이에요.' },
  { id: 'g_fun_considerate_habits', category: '재미·잡학', tags: ['알레르기', '도쿄', '오사카', '일본인', '배려'], label: '일본인의 배려가 담긴 습관 두 가지', libraryOnly: true, tipKo: '코로나 이전부터 자연스러웠던 마스크 착용과, 지역마다 반대인 에스컬레이터 서는 방향이에요.', detail: '일본은 팬데믹 이전부터 꽃가루 알레르기 대책이나 감기 예방, 타인 배려 목적으로 마스크 착용이 일상적이라 거부감이 적었습니다. 에스컬레이터는 도쿄권은 왼쪽, 오사카권은 오른쪽에 서는 관행이 있었는데 오사카가 반대가 된 배경엔 1970년 만국박람회 영향설이 있으며, 최근엔 안전을 이유로 양쪽 다 서는 것이 권장됩니다.', action: '에스컬레이터를 탈 때 그 지역 관행보다 바닥 표시나 안내를 먼저 확인하세요.' },
  { id: 'g_fun_crowded_train_scenes', category: '재미·잡학', tags: ['현금', '카드', '도쿄', '일본', '사회'], label: '일본 사회를 보여주는 두 장면', libraryOnly: true, tipKo: '혼잡한 열차에 승객을 밀어 넣는 오시야와, 카드보다 현금을 오래 선호해온 습관이에요.', detail: '도쿄 초혼잡 노선의 출근 시간대엔 하얀 장갑을 낀 역무원이 승객을 조심스럽게 밀어 넣어 문을 닫는 오시야(押し屋) 업무가 실제로 존재합니다. 일본이 현금 사회를 오래 유지한 데는 위조지폐가 극히 드물어 현금 신뢰도가 높았던 점과, 카드 사용 내역으로 개인정보가 노출되는 것을 꺼리는 문화가 함께 작용했습니다.', commonMistake: '오시야가 옛날 이야기라고 생각하기 쉽지만, 지금도 일부 초혼잡 노선에서 실제로 볼 수 있어요.' },
  { id: 'g_fun_records_and_firsts', category: '재미·잡학', tags: ['도쿄', '일본', '세운', '기록'], label: '일본이 세운 두 가지 기록', libraryOnly: true, tipKo: '에펠탑보다 3m 더 높게 지은 도쿄타워와, 미국 밖 최초로 문을 연 도쿄 디즈니랜드예요.', detail: '1958년 완공된 도쿄타워는 에펠탑을 참고해 설계됐지만 실제 높이는 333m로 에펠탑(약 330m)보다 살짝 더 높게 지어졌습니다. 도쿄 디즈니랜드는 1983년 개장하며 미국 밖에 세워진 세계 최초의 디즈니 테마파크가 됐는데, 디즈니 본사가 아니라 일본 기업 오리엔탈랜드가 라이선스로 운영하는 독특한 구조입니다.', action: '도쿄타워와 도쿄 스카이트리 높이를 검색해서 비교해보세요.' },
  { id: 'g_fun_gray_zone_systems', category: '재미·잡학', tags: ['현금', '택배', '은행', '일본', '행정'], label: '일본의 독특한 법·행정 문화 두 가지', libraryOnly: true, tipKo: '경품 교환소를 거쳐 합법이 되는 파칭코와, 서명 대신 도장을 찍는 한코 문화예요.', detail: '일본 형법은 도박을 금지하지만 파칭코는 손님이 구슬을 경품으로 바꾼 뒤 가게 밖 별도 환금소에서 현금화하는 3단계 구조로 법의 테두리 안에서 운영됩니다. 일본은 서명 대신 개인 인감도장 한코(判子)를 찍는 문화가 강해, 은행 계좌 개설이나 택배 수령 같은 절차에 지금도 도장이 쓰입니다.', commonMistake: '한코가 이제 완전히 사라졌을 거라 생각하기 쉽지만, 택배 수령 등 일상에는 여전히 남아 있어요.' },
  { id: 'g_fun_womens_history_items', category: '재미·잡학', tags: ['지하철', '전철', '세일', '여성', '패션'], label: '여성을 위한 두 가지 제도와 패션', libraryOnly: true, tipKo: '영국 해군복에서 유래한 교복 세일러복과, 성추행 방지를 위한 지하철 여성전용칸이에요.', detail: '일본 여학생 교복의 상징 세일러복은 1920년대 한 여학교 교장이 서양 해군 수병 제복을 참고해 도입한 것이 시초로, 이후 전국으로 퍼져 학원물 콘텐츠의 상징이 됐습니다. 여성전용칸(女性専用車両)은 출퇴근 혼잡 시간대 성추행 피해를 줄이기 위해 도입돼, 특정 칸을 시간대별로 여성만 이용할 수 있게 운영됩니다.', action: '전철을 탈 때 여성전용칸 표시와 운영 시간대를 한번 확인해보세요.' },
  { id: 'g_fun_thoughtful_restrooms', category: '재미·잡학', tags: ['료칸', '화장실', '일본', '배려'], label: '일본 화장실의 세심한 배려 두 가지', libraryOnly: true, tipKo: '화장실 전용 슬리퍼로 갈아 신는 습관과, 인공 물소리로 프라이버시를 지켜주는 버튼이에요.', detail: '일본 가정·료칸에서는 실내 슬리퍼를 신다가도 화장실 앞에서 전용 슬리퍼로 한 번 더 갈아 신는 것이 예절인데, 볼일을 본 뒤 다시 갈아 신는 것을 깜빡하는 게 외국인의 흔한 실수로 꼽힙니다. 비데의 인공 물소리 버튼(오토히메)은 원래 여성들이 소리를 가리려 물을 여러 번 내리던 습관으로 인한 물 낭비를 줄이려 고안된 기능입니다.', commonMistake: '화장실 슬리퍼를 신고 그대로 나가는 것이 외국인이 가장 흔히 하는 실수예요 — 벗어두고 원래 슬리퍼로 갈아 신어야 해요.' },
  { id: 'g_fun_gift_devotion', category: '재미·잡학', tags: ['오미야게', '기념품', '백화점', '선물', '진심인'], label: '선물에 진심인 일본 문화 두 가지', libraryOnly: true, tipKo: '여행 다녀오면 회사에 과자를 돌리는 오미야게 문화와, 각 잡힌 백화점 선물 포장 솜씨예요.', detail: '오미야게는 여행 후 동료·지인에게 그 지역 과자를 나눠주는 거의 의무 같은 관례로, 이 덕분에 낱개 포장된 상자형 기념품이 특히 잘 발달해 있습니다. 백화점 포장 직원은 오랜 훈련으로 종이의 각과 리본 매듭을 흐트러짐 없이 맞추며, 선물의 용도에 맞는 포장지 색까지 알아서 골라주는 세심함으로 유명합니다.', action: '일본에서 선물을 받으면 포장을 뜯기 전에 한번 감상해보세요.' },
  { id: 'g_fun_new_year_traditions', category: '재미·잡학', tags: ['카드', '편의점', '설날', '우체국'], label: '설날을 준비하는 일본의 전통 두 가지', libraryOnly: true, tipKo: '1월 1일 아침 한꺼번에 배달되는 연하장과, 반찬 하나하나에 길한 의미를 담은 찬합 요리 오세치예요.', detail: '넨가장(연하장)은 우체국이 연말 접수분을 따로 모아뒀다가 정확히 1월 1일 아침 한꺼번에 배달하는 새해 인사 카드입니다. 오세치요리는 여러 칸 찬합에 담는데, 콩자반은 "건강하게 일한다", 새우는 "허리 굽을 때까지 장수"처럼 재료마다 길한 의미가 담겨 있습니다.', action: '연말연시에 방문한다면 편의점에서 파는 미니 오세치 세트를 구경해보세요.' },
  { id: 'g_fun_practical_home_wisdom', category: '재미·잡학', tags: ['기념품', '실용적인', '일본', '생활', '도구'], label: '실용적인 일본 생활 도구 두 가지', libraryOnly: true, tipKo: '천 한 장으로 뭐든 싸는 후로시키와, 한번 들어가면 못 나온다는 난방 테이블 코타츠예요.', detail: '후로시키는 정사각형 천 한 장으로 물건 모양에 맞춰 다양한 매듭법으로 무엇이든 감싸는 전통 포장 도구로, 최근엔 일회용 포장을 줄이는 친환경 대안으로 재조명받고 있습니다. 코타츠는 이불 덮은 낮은 테이블 아래 열원을 넣어 하반신을 데우는 겨울 가구로, 온몸을 데우지 않고도 아늑해 "들어가면 못 나온다"는 농담이 있을 정도입니다.', action: '기념품점에서 후로시키를 하나 사서 선물 포장에 써보세요.' },
  { id: 'g_fun_traditional_house_wisdom', category: '재미·잡학', tags: ['료칸', '신사', '다다미', '지진'], label: '일본 전통 가옥의 지혜 두 가지', libraryOnly: true, tipKo: '방 크기를 다다미 장수로 세는 관행과, 못 하나 없이 나무를 짜맞추는 미야다이쿠 목수 기술이에요.', detail: '일본은 방 넓이를 "6조" 처럼 다다미 몇 장 크기인지로 표현하는 것이 오랜 관례로, 지금도 부동산·료칸 안내에 흔히 쓰입니다. 신사·절을 짓는 미야다이쿠(宮大工) 목수는 못이나 접착제 없이 나무를 정교하게 깎아 끼워 맞추는데, 이 짜맞춤 건축이 오히려 지진의 흔들림을 잘 견뎌 수백 년 이상 버틴 건물도 남아 있습니다.', exampleJa: 'このへやは何畳ですか', exampleKo: '이 방은 다다미 몇 장이에요?' },
  { id: 'g_fun_browsing_pleasure_streets', category: '재미·잡학', tags: ['할인', '백화점', '구경', '즐거운', '일본'], label: '구경만 해도 즐거운 일본의 두 거리', libraryOnly: true, tipKo: '헌책방 100곳이 모인 진보초와, 고급 도시락·디저트가 가득한 백화점 지하 데파치카예요.', detail: '진보초는 메이지 시대부터 이어진 헌책방 거리로, 좁은 골목에 100곳 넘는 서점이 늘어서 있어 책을 좋아하는 여행자라면 하루가 부족할 정도입니다. 데파치카는 백화점 지하 식품매장을 뜻하는데 고급 도시락·화과자부터 유명 맛집 테이크아웃까지 모여 있어, 폐점 1~2시간 전 할인 딱지를 노리는 현지인도 많습니다.', action: '진보초에 간다면 관심 분야 전문 서점을 한 곳 정해 구경해보세요.' },
  { id: 'g_fun_unique_cafe_spaces', category: '재미·잡학', tags: ['숙소', '카페', '휴식', '공간'], label: '독특한 카페·휴식 공간 두 곳', libraryOnly: true, tipKo: '밤새 있어도 되는 만화카페와, 로스팅 설비를 눈앞에서 볼 수 있는 나카메구로 스타벅스 리저브 로스터리예요.', detail: '만화킷사는 수많은 만화와 개인 부스, 샤워실까지 갖춰 만화를 보러 오는 손님뿐 아니라 막차를 놓친 사람의 임시 숙소로도 쓰입니다. 나카메구로의 스타벅스 리저브 로스터리는 세계에서 손꼽히는 대형 매장으로, 매장 한가운데서 원두가 실제로 볶아지는 과정을 직접 볼 수 있게 설계돼 있습니다.', action: '나카메구로에 간다면 스타벅스 리저브 로스터리에서 로스팅 과정을 구경해보세요.' },
  { id: 'g_fun_trust_and_nature', category: '재미·잡학', tags: ['벚꽃', '매너', '일본', '자연스러운', '신뢰'], label: '일본의 자연스러운 신뢰와 유전 이야기', libraryOnly: true, tipKo: '정직하게 돈만 넣고 가져가는 시골 무인 채소 판매대와, 사실상 모두 같은 나무의 복제인 벚꽃 소메이요시노예요.', detail: '일본 농촌에는 채소·과일을 진열해두고 손님이 스스로 요금함에 돈을 넣고 가져가는 무인 판매대(無人販売所)가 흔해, 지역 공동체의 신뢰와 치안을 보여주는 사례로 자주 언급됩니다. 벚꽃놀이의 주인공 소메이요시노는 스스로 번식하지 못해 가지 접붙이기로만 늘려와, 전국의 나무가 유전적으로 거의 동일한 클론에 가까워 같은 지역 벚꽃이 거의 동시에 피고 지는 장관을 만듭니다.', commonMistake: '무인 판매대를 관광객도 마음대로 이용해도 되는 곳으로 오해하기 쉽지만, 정가를 정직하게 지불하는 게 매너예요.' },
  { id: 'g_fun_invented_pastimes', category: '재미·잡학', tags: ['기념품', '스탬프', '일본', '만든', '문화'], label: '일본이 만든 두 가지 놀이 문화', libraryOnly: true, tipKo: '특허도 안 낸 채 세계로 퍼진 가라오케와, 역·관광지를 돌게 만드는 스탬프 랠리예요.', detail: '가라오케는 1970년대 초 고베의 한 연주자가 반주만 재생하는 기계를 만든 것이 시초인데, 특허를 신청하지 않아 정작 본인은 큰돈을 못 벌었지만 전 세계 유흥 문화를 바꾼 발명으로 평가받습니다. 스탬프 랠리는 역·관광지·전시회마다 놓인 고유 도안 스탬프를 작은 수첩에 모으는 문화로, 정해진 노선을 다 돌면 한정 기념품을 주는 이벤트도 흔합니다.', action: '다음 여행에서 스탬프 수첩 하나를 마련해 도장을 모아보세요.' },
  // ── 문법 추가(N5~N4 여행 실전 문형) ──
  { id: 'g_grammar_tari_tari', category: '문법', tags: ['たり', 'たりする', '하기'], label: '〜たり〜たりする (~하기도 하고)', tipKo: '여러 행동을 나열할 때 씁니다. かったり、たべたりしました(사기도 하고 먹기도 했어요)처럼 대표 행동 두어 개만 골라 말해요.', detail: '〜たり〜たりする는 여러 행동 중 대표적인 몇 가지만 골라 나열할 때 쓰는 문형으로, 모든 행동을 빠짐없이 말하는 것이 아니라 "이것도 하고 저것도 하고" 정도의 뉘앙스를 전달합니다. 여행 후기를 말할 때 かったり(사기도 하고)、たべたりしました(먹기도 했어요)처럼 두 동사의 た형에 り를 붙이고 마지막에 する를 붙이면 됩니다.', exampleJa: 'おみやげをかったり、しゃしんをとったりしました', exampleKo: '기념품을 사기도 하고 사진을 찍기도 했어요.', action: '오늘 한 일 두 가지를 〜たり〜たりしました로 말해 보세요.' },
  { id: 'g_grammar_sugiru', category: '문법', tags: ['すぎる'], label: '〜すぎる (너무 ~하다)', tipKo: '형용사·동사 어간에 붙여 "너무 ~하다"는 과함을 나타내요. たかすぎます(너무 비싸요)처럼 흥정·불만 표현에 유용해요.', detail: '〜すぎる는 형용사나 동사의 어간에 붙어 정도가 지나치다는 뜻을 더하는 표현으로, たかい(비싸다)에 붙이면 たかすぎる(너무 비싸다)가 됩니다. 가격 흥정이나 양이 많다고 말할 때처럼 감정을 살짝 담아 불만이나 놀람을 표현하기 좋아, 여행 중 실전 회화에서 활용도가 높습니다.', exampleJa: 'このりょうはおおすぎます', exampleKo: '이 양은 너무 많아요.', action: 'たかすぎます(너무 비싸요)를 흥정할 때 써 보세요.' },
  { id: 'g_grammar_yasui_nikui', category: '문법', tags: ['やすい・にくい', '하기'], label: '〜やすい・〜にくい (하기 쉽다/어렵다)', tipKo: '동사 ます형 어간에 붙여 "~하기 쉽다/어렵다"를 나타내요. わかりやすい(이해하기 쉽다), あるきにくい(걷기 어렵다)처럼 써요.', detail: '동사의 ます형에서 ます를 뗀 어간에 やすい를 붙이면 "~하기 쉽다", にくい를 붙이면 "~하기 어렵다"는 뜻이 됩니다. 길이 걷기 편한지, 설명이 이해하기 쉬운지처럼 여행 중 상태를 묘사할 때 자주 쓰이는 실용적인 형용사 파생 문형입니다.', exampleJa: 'このみちはあるきにくいです', exampleKo: '이 길은 걷기 어려워요.', action: 'わかりやすい/わかりにくい를 넣어 오늘 배운 것을 평가해 보세요.' },
  { id: 'g_grammar_n_desu', category: '문법', tags: ['전철', 'んです', '설명', '이유', '강조'], label: '〜んです (설명·이유 강조)', tipKo: '단순 사실보다 "사정이 있어서요"라는 배경 설명 뉘앙스를 더해요. でんしゃにのりおくれたんです(전철을 놓쳐서요)처럼 변명·설명에 자연스러워요.', detail: '〜んです는 문장 끝에 붙어 단순한 사실 전달을 넘어 "그럴 만한 사정이 있다"는 배경 설명의 뉘앙스를 더하는 표현으로, 지각이나 실수에 대한 이유를 말할 때 자연스럽게 들립니다. です만 쓰면 다소 딱딱하게 들릴 수 있는 상황에서 んです를 붙이면 훨씬 인간적이고 설명하는 느낌이 살아납니다.', exampleJa: 'でんしゃにのりおくれたんです', exampleKo: '전철을 놓쳐서요.', action: '지각·실수 상황을 가정해 〜んです로 변명해 보세요.' },
  { id: 'g_grammar_sou_desu', category: '문법', tags: ['そうです', '해요'], label: '〜そうです (~일 것 같다 / ~라고 해요)', tipKo: 'い형용사 어간+そう는 "~해 보인다"(추측), 문장+そうです는 "~라고 해요"(전문)로 뜻이 갈려요.', detail: '〜そうです는 형태에 따라 뜻이 두 가지로 나뉘는데, おいしい처럼 형용사 어간(おいし)에 바로 そう를 붙이면 "맛있어 보인다"는 시각적 추측이 되고, 문장 전체 뒤에 そうです를 붙이면 "~라고 들었다"는 전문(伝聞) 표현이 됩니다. 두 용법을 헷갈리기 쉬우니 형용사 어간+そう(추측) vs 문장+そうです(전언)로 구분해 기억해두면 좋습니다.', exampleJa: 'このラーメン、おいしそうです', exampleKo: '이 라멘 맛있어 보여요.', commonMistake: '형용사 기본형 그대로에 そう를 붙이면 어색해요(おいしいそう✗ → おいしそう○).', action: '눈앞의 음식을 보고 〜そうです로 감상을 말해 보세요.' },
  { id: 'g_grammar_temo_ii', category: '문법', tags: ['てもいいですか', '될까요'], label: '〜てもいいですか (~해도 될까요?)', tipKo: '허락을 구할 때 쓰는 표현이에요. しゃしんをとってもいいですか(사진 찍어도 될까요?)처럼 여행 중 정말 자주 씁니다.', detail: '〜てもいいですか는 동사의 て형 뒤에 붙여 상대방에게 허락을 구하는 표현으로, 사진 촬영·시식·자리 이용 등 여행 중 이것저것 물어봐야 할 순간에 가장 많이 쓰이는 문형 중 하나입니다. 허락하면 いいですよ(좋아요), 곤란하면 ちょっと…(음, 좀…)처럼 완곡하게 거절하는 대답이 돌아올 수 있습니다.', exampleJa: 'しゃしんをとってもいいですか', exampleKo: '사진 찍어도 될까요?', action: '박물관·상점에서 촬영 전 이 표현으로 먼저 물어보세요.' },
  { id: 'g_grammar_nakutemo_ii', category: '문법', tags: ['예약', 'なくてもいいです', '의무없음', '안심'], label: '〜なくてもいいです (~하지 않아도 돼요)', tipKo: '의무가 없음을 말할 때 써요. よやくしなくてもいいです(예약 안 해도 돼요)처럼 안심시키는 안내에 자주 등장해요.', detail: '〜なくてもいいです는 동사의 부정형(ない형)에서 い를 くて로 바꾼 뒤 もいいです를 붙여 "~하지 않아도 된다"는 뜻을 나타내는 문형으로, 필수가 아님을 안내할 때 자주 쓰입니다. 점원이나 안내원이 손님을 안심시킬 때 흔히 들을 수 있는 표현이라, 뜻만 알아둬도 여행 중 불필요한 걱정을 덜 수 있습니다.', exampleJa: 'よやくしなくてもいいです', exampleKo: '예약 안 해도 돼요.', action: '궁금한 절차에 대해 〜なくてもいいですか로 물어보세요.' },
  { id: 'g_grammar_ba_conditional', category: '문법', tags: ['어미', '하면', '조건'], label: '〜ば (~하면, 조건)', tipKo: '동사 어미를 え단으로 바꾸고 ば를 붙이면 "~하면"이라는 조건이 돼요. みぎにいけば、えきがあります(오른쪽으로 가면 역이 있어요)처럼 길안내에 유용해요.', detail: '〜ば형은 동사의 마지막 음을 え단으로 바꾼 뒤 ば를 붙여 만드는 조건형으로, "~하면"이라는 뜻을 나타냅니다. 길을 물었을 때 상대방이 みぎにいけば(오른쪽으로 가면), まっすぐいけば(똑바로 가면)처럼 안내해주는 경우가 많아, 듣기 이해력을 키워두면 길 안내를 훨씬 수월하게 알아들을 수 있습니다.', exampleJa: 'みぎにいけば、えきがあります', exampleKo: '오른쪽으로 가면 역이 있어요.', action: '길을 물을 때 상대의 대답에서 〜ば 형태를 귀 기울여 들어보세요.' },
  { id: 'g_grammar_ta_koto_ga_aru', category: '문법', tags: ['たことがあります'], label: '〜たことがあります (~한 적이 있어요)', tipKo: '경험을 말할 때 씁니다. にほんにきたことがあります(일본에 온 적이 있어요)처럼 스몰토크에 자연스러운 표현이에요.', detail: '〜たことがあります는 동사의 た형(과거형) 뒤에 붙여 "~한 적이 있다"는 경험을 나타내는 문형으로, 처음 만난 사람과 가벼운 대화를 나눌 때 매우 자연스럽게 쓸 수 있습니다. 반대로 경험이 없다면 〜たことがありません(~한 적이 없어요)이라고 답하면 되어, 짝을 이뤄 함께 기억해두면 실전 대화에서 유용합니다.', exampleJa: 'にほんにきたことがあります', exampleKo: '일본에 온 적이 있어요.', action: '점원·현지인과의 스몰토크에서 〜たことがあります를 써 보세요.' },
  { id: 'g_grammar_toki_ni', category: '문법', tags: ['카드', 'とき'], label: '〜とき (~할 때)', tipKo: '동사 기본형·た형 뒤에 とき를 붙이면 "~할 때/~했을 때"가 돼요. こまったときは(곤란할 때는)처럼 도움 요청 상황에 자주 쓰여요.', detail: 'とき는 "때"를 뜻하는 명사로, 동사 기본형 뒤에 붙으면 "~할 때"(아직 일어나지 않은 시점), た형 뒤에 붙으면 "~했을 때"(이미 일어난 시점)라는 미묘한 시제 차이를 나타냅니다. こまったときは、これをみせてください(곤란할 때는 이걸 보여주세요)처럼 비상 상황 대비 안내문에도 자주 등장하는 표현입니다.', exampleJa: 'こまったときは、スタッフをよんでください', exampleKo: '곤란할 때는 직원을 불러주세요.', action: '비상 카드·안내문에서 〜ときは 패턴을 찾아보세요.' },

  // ── 발음 추가 ──
  { id: 'g_pron_ji_zu_pairs', category: '발음', tags: ['발음', 'じ・ぢ', 'ず・づ', '소리', '다른'], label: 'じ・ぢ, ず・づ — 같은 소리, 다른 글자', tipKo: 'じ와 ぢ, ず와 づ는 발음이 사실상 똑같아요. 표기만 다를 뿐 소리 구분에 신경 쓰지 않아도 돼요.', detail: '현대 일본어에서 じ와 ぢ, ず와 づ는 발음상 거의 구분되지 않아 사실상 같은 소리로 발음됩니다. 표기가 갈리는 것은 원래 단어가 만들어진 방식(연탁 현상 등) 때문일 뿐이라, 학습자 입장에서는 발음을 구분하려 애쓰기보다 어느 쪽으로 읽어도 통한다는 점만 기억해두면 충분합니다.' },
  { id: 'g_pron_wa_particle_vs_word', category: '발음', tags: ['조사', '발음', '가나', '히라가나'], label: '조사 は의 발음은 「와」', tipKo: '조사로 쓰이는 は는 「하」가 아니라 「와」로 발음해요. わたしは(저는)에서 실제 소리는 [wa]예요.', detail: '히라가나 は는 단어 안에서는 [ha]로 읽히지만, 주제를 나타내는 조사로 쓰일 때만 예외적으로 [wa]로 발음됩니다. わたしはがくせいです(저는 학생입니다)를 읽을 때 조사 は를 「하」로 읽으면 매우 어색하게 들리므로, 조사 자리의 は는 항상 「와」라는 규칙을 확실히 기억해두어야 합니다.', commonMistake: '표기 그대로 「하」로 읽으면 원어민이 즉시 어색함을 느껴요.' },
  { id: 'g_pron_katakana_rhythm', category: '발음', tags: ['발음', '장음', '가타카나', '외래어', '리듬'], label: '가타카나 외래어의 독특한 리듬', tipKo: '영어 단어를 가타카나로 옮기면 음절이 늘어나(coffee→コーヒー) 리듬이 원어와 많이 달라져요.', detail: '영어 단어가 가타카나로 옮겨지면 일본어의 음절 구조에 맞춰 자음 뒤에 모음이 붙거나 장음이 추가되며 음절 수 자체가 늘어나는 경우가 많습니다(coffee[커피, 2음절]→コーヒー[코-히-, 4박자]). 이 때문에 영어를 아는 사람도 가타카나 발음이 낯설게 느껴질 수 있는데, 오히려 또박또박 박자를 맞춰 읽으면 현지인에게 더 잘 통하는 경우가 많습니다.' },
  { id: 'g_pron_question_intonation', category: '발음', tags: ['억양', '질문인지', '구분'], label: '질문인지 아닌지는 끝 억양으로 구분', tipKo: 'か 없이 말하는 짧은 질문은 문장 끝을 살짝 올려야 질문으로 들려요. 안 올리면 그냥 진술처럼 들려요.', detail: '일본어 회화에서는 짧은 문장 끝을 올리는 것만으로 질문의 의미를 전달하는 경우가 흔한데, 이때 억양을 평탄하게 유지하면 상대방이 질문이 아니라 그냥 하는 말로 오해할 수 있습니다. これ？(이거?)처럼 짧은 단어 하나를 말할 때도 끝을 분명히 올리는 습관을 들이면 의사소통 오해를 줄일 수 있습니다.' },
  { id: 'g_pron_youon_sokuon_combo', category: '발음', tags: ['발음', '촉음', '요음', '요음+촉음', '겹칠'], label: '요음+촉음이 겹칠 때(きゃっ 등)', tipKo: 'きゃ・しゅ・ちょ 같은 요음 뒤에 촉음(っ)이 겹치면 한 박 멈췄다가 요음째로 발음해요.', detail: '요음(きゃ·しゅ·ちょ 등 작은 ゃゅょ가 붙은 소리)과 촉음(っ, 순간적으로 멈추는 소리)이 함께 나오면, 요음 자체는 한 덩어리로 유지한 채 그 뒤에서 한 박자를 쉬었다가 다음 소리로 넘어가야 합니다. 두 요소가 겹치는 단어는 많지 않지만, 마주쳤을 때 요음을 쪼개지 않고 한 박으로 유지하는 것이 핵심입니다.' },
  { id: 'g_pron_n_variation', category: '발음', tags: ['발음', '콧소리', '소리', '따라'], label: '콧소리 ん은 뒤에 오는 소리에 따라 변해요', tipKo: 'ん은 뒤에 오는 자음에 따라 「ㅁ」・「ㄴ」・「응」처럼 살짝 다르게 들려요. 억지로 통일하려 하지 말고 자연스럽게 이어 발음하세요.', detail: 'ん은 표기상 하나의 글자지만 실제 발음은 뒤따르는 소리의 영향을 받아 미묘하게 달라지는데, ぱ・ば행 앞에서는 「ㅁ」에 가깝게, た・だ행 앞에서는 「ㄴ」에 가깝게, 그 외에는 콧소리 「응」에 가깝게 들립니다. 이는 자연스러운 조음 현상이라 억지로 통일해 발음하려 하기보다, 뒤에 오는 소리에 이어지듯 편하게 발음하는 것이 오히려 더 자연스럽습니다.' },
  { id: 'g_pron_double_consonant_timing', category: '발음', tags: ['발음', '촉음', '가나', '박자', '멈춤'], label: '촉음(っ)의 "한 박자 멈춤" 감각', tipKo: 'きって(우표)처럼 っ가 있으면 다음 자음 전에 정확히 한 박자를 쉬어야 해요 — 너무 짧으면 다른 단어로 들려요.', detail: '촉음 っ는 다음 글자의 자음을 준비하며 숨을 잠깐 멈추는 소리로, 이 멈춤이 정확히 한 박자(다른 가나 한 글자와 같은 길이)를 차지해야 합니다. きて(와서)와 きって(우표)처럼 촉음 유무만으로 완전히 다른 단어가 되는 경우가 많아, 이 한 박자 감각을 몸에 익히는 것이 정확한 발음의 핵심입니다.' },
  { id: 'g_pron_foreign_r_sound_review', category: '발음', tags: ['발음', '라행', '중간'], label: '라행 발음은 "ㄹ"과 "ㄷ"의 중간', tipKo: '일본어 ら・り・る・れ・ろ는 한국어 "ㄹ"보다 혀끝을 짧게 톡 튕기는 소리로, 오히려 살짝 "ㄷ"에 가깝게 들릴 때도 있어요.', detail: '일본어의 라행(ら·り·る·れ·ろ)은 영어의 R이나 한국어의 ㄹ과는 조음 방식이 달라, 혀끝을 윗잇몸 뒤쪽에 짧게 한 번 톡 튕기듯 발음합니다. 이 때문에 듣기에 따라 한국어 ㄹ보다 오히려 ㄷ에 가깝게 들리기도 하는데, 너무 굴리듯 길게 발음하면 오히려 부자연스러워지므로 짧고 가볍게 튕기는 느낌을 연습하는 것이 좋습니다.' },

  // ── 회화법 추가 ──
  { id: 'g_conv_aizuchi', category: '회화법', tags: ['맞장구', '相槌', '대화', '살리기'], label: '맞장구(相槌)로 대화를 살리기', tipKo: '상대가 말할 때 「はい」「そうですね」「なるほど」로 짧게 맞장구치면 훨씬 자연스러운 대화가 돼요.', detail: '아이즈치(相槌)는 상대방이 말하는 도중 짧게 맞장구를 쳐서 잘 듣고 있다는 신호를 보내는 일본어 대화의 중요한 습관으로, はい(네)·そうですね(그렇군요)·なるほど(그렇구나)를 적절히 섞어 쓰면 훨씬 자연스러운 리듬의 대화가 됩니다. 침묵하며 듣기만 하면 오히려 상대가 불안해할 수 있어, 짧은 맞장구를 습관화하는 것이 좋습니다.', action: '다음 대화에서 상대 말끝마다 そうですね를 넣어보세요.' },
  { id: 'g_conv_hedging_chotto', category: '회화법', tags: ['거절', 'ちょっと…'], label: '거절은 「ちょっと…」로 부드럽게', tipKo: '직접 「いいえ」라고 하기보다 「ちょっと…」라고 말끝을 흐리면 부드러운 거절로 통해요.', detail: '일본어 회화에서는 직접적인 거절(いいえ)보다 ちょっと…(음, 좀…)처럼 말을 흐리며 여지를 남기는 방식이 훨씬 부드럽고 예의 바르게 받아들여집니다. 뒷말을 굳이 다 하지 않아도 상대방은 이것이 완곡한 거절이라는 것을 자연스럽게 알아채므로, 무언가 곤란하거나 거절하고 싶을 때 이 표현을 기억해두면 유용합니다.', action: '권유를 거절할 때 ちょっと…만으로 대답해 보세요.' },
  { id: 'g_conv_repeat_confirm', category: '회화법', tags: ['숫자확인', '되풀이', '확인하기'], label: '들은 말을 그대로 되풀이해 확인하기', tipKo: '점원이 금액을 말하면 그 숫자를 그대로 따라 말해(오움 반복) 확인하는 습관이 오해를 줄여줘요.', detail: '가격이나 시간처럼 숫자가 중요한 정보를 들었을 때, 그 숫자를 그대로 따라 말하며 확인하는 것은 일본어 실전 회화에서 아주 유용한 습관입니다. 예를 들어 점원이 さんびゃくえんです(300엔입니다)라고 하면 さんびゃくえんですね(300엔이군요)라고 되풀이하면, 잘못 들었을 경우 상대가 바로 정정해줄 수 있어 오해를 크게 줄일 수 있습니다.', action: '금액을 들으면 반드시 한 번 따라 말해 확인해 보세요.' },
  { id: 'g_conv_slow_down_request', category: '회화법', tags: ['이해', '3단계'], label: '이해 못 했을 때 바로 되묻는 3단계', tipKo: '① もう一度お願いします(다시 한번) → ② ゆっくりお願いします(천천히) → ③ やさしい日本語で(쉬운 말로) 순서로 요청해보세요.', detail: '상대의 말을 못 알아들었을 때는 당황하지 말고 단계적으로 요청하는 것이 효과적인데, 먼저 もう一度お願いします(다시 한번 부탁합니다)로 반복을 청하고, 그래도 어려우면 ゆっくりお願いします(천천히 부탁합니다)로 속도를 늦춰달라고 하고, 여전히 어렵다면 やさしい日本語で(쉬운 일본어로)라고 요청하는 3단계 전략이 실전에서 매우 유용합니다.', action: '이 세 표현을 순서대로 외워 언제든 쓸 수 있게 준비하세요.' },
  { id: 'g_conv_pointing_helps', category: '회화법', tags: ['막히면', '손가락'], label: '말이 막히면 손가락으로 가리키세요', tipKo: '단어가 생각 안 나면 주저 말고 메뉴·물건을 손가락으로 가리키며 これ(이거)만 말해도 충분히 통해요.', detail: '완벽한 문장을 만들려다 말이 막히는 것보다, 필요한 물건이나 메뉴를 손가락으로 가리키며 これ、おねがいします(이거 부탁합니다)처럼 최소한의 표현으로 의사를 전달하는 것이 실전에서 훨씬 효과적입니다. 언어보다 몸짓이 더 빠르고 정확하게 뜻을 전달하는 상황도 많으니, 부끄러워하지 말고 적극적으로 가리키는 습관을 들이세요.', action: '다음 주문에서 문장 대신 가리키기+これ만으로 시도해 보세요.' },
  { id: 'g_conv_thanks_variety', category: '회화법', tags: ['감사', '인사', '상황별', '강도'], label: '감사 인사도 상황별로 강도가 달라요', tipKo: 'どうも(가볍게) < ありがとうございます(정중) < どうもありがとうございました(가장 정중, 헤어질 때)처럼 강도가 다양해요.', detail: '일본어의 감사 표현은 상황의 격식에 따라 강도가 세밀하게 나뉘는데, 가벼운 상황에서는 짧게 どうも만으로 충분하고, 일반적인 감사에는 ありがとうございます, 헤어지며 정중하게 마무리할 때는 どうもありがとうございました처럼 더 길고 과거형인 표현을 씁니다. 상황에 맞는 강도를 고르면 훨씬 자연스러운 인상을 줄 수 있습니다.', action: '오늘 하루 상황별로 감사 표현 강도를 바꿔가며 써 보세요.' },
  { id: 'g_conv_apology_levels', category: '회화법', tags: ['사과', '격식', '구분'], label: '사과도 가벼운 것과 정중한 것이 달라요', tipKo: 'すみません(가벼운 사과·부름말) < ごめんなさい(개인적 사과) < もうしわけございません(매우 정중, 격식)로 구분돼요.', detail: 'すみません은 사과뿐 아니라 누군가를 부를 때도 쓰이는 만능 표현이고, ごめんなさい는 좀 더 개인적이고 친근한 사과에 어울리며, もうしわけございません은 비즈니스나 정중한 자리에서 쓰는 가장 격식 있는 사과 표현입니다. 상황의 격식 수준에 맞춰 이 세 표현을 구분해서 쓰면 훨씬 자연스럽게 들립니다.', action: '실수했을 때 상황에 맞는 사과 표현을 골라 말해 보세요.' },
  { id: 'g_conv_silence_is_ok', category: '회화법', tags: ['침묵', '대화'], label: '침묵도 대화의 일부예요', tipKo: '일본어 대화에서는 대답 전 잠깐의 침묵(사이)이 무례가 아니라 신중함의 표시로 받아들여져요.', detail: '서양식 대화 관습에 익숙하면 침묵을 어색하게 느끼기 쉽지만, 일본어 대화 문화에서는 대답하기 전 잠깐의 침묵(間·마)이 오히려 신중하게 생각하고 있다는 긍정적인 신호로 받아들여집니다. 특히 곤란한 질문이나 거절해야 하는 상황에서는 침묵 자체가 완곡한 거절의 신호로 쓰이기도 하니, 빨리 답해야 한다는 조바심을 내려놓아도 괜찮습니다.', action: '대답 전에 잠깐 뜸을 들여도 괜찮다는 것을 기억하세요.' },

  // ── 학습법 추가 ──
  { id: 'g_study_record_own_voice', category: '학습법', tags: ['마트', '억양', '발음', '들어보기'], label: '내 발음을 녹음해서 들어보기', tipKo: '스스로 말할 땐 괜찮게 들려도, 녹음해서 들어보면 실제 문제점이 훨씬 잘 보여요.', detail: '말하는 동안에는 자신의 발음이 괜찮게 느껴지기 쉽지만, 실제로 녹음해서 다시 들어보면 억양이나 발음의 문제점이 훨씬 객관적으로 드러납니다. 스마트폰으로 짧은 문장을 녹음하고 원어민 음성과 비교해보는 것만으로도, 스스로 알아차리지 못했던 습관을 교정하는 데 큰 도움이 됩니다.', action: '오늘 배운 문장 하나를 녹음해서 원음과 비교해 보세요.' },
  { id: 'g_study_review_before_trip', category: '학습법', tags: ['출발', '1주', '전엔', '복습'], label: '출발 1주 전엔 새 내용보다 복습', tipKo: '여행 출발이 임박하면 새로운 표현을 늘리기보다, 이미 배운 것을 확실히 다지는 쪽이 실전에서 더 도움이 돼요.', detail: '출발이 임박한 시점에 새로운 내용을 욱여넣으면 오히려 기존에 익힌 표현까지 헷갈리게 만드는 역효과가 날 수 있습니다. 출발 1주일 전부터는 새로운 학습량을 줄이고, 이미 배운 핵심 표현을 반복해서 확실히 몸에 붙이는 데 집중하는 것이 실전에서 훨씬 안정적으로 작동합니다.', action: '출발 1주 전부터는 "복습" 배너 위주로 학습해 보세요.' },
  { id: 'g_study_mistake_is_data', category: '학습법', tags: ['발음', '틀린', '이유', '적어두기'], label: '틀린 이유를 한 줄로 적어두기', tipKo: '틀렸을 때 "왜 틀렸는지" 한 줄만 적어두면, 나중에 비슷한 실수를 훨씬 빨리 알아챌 수 있어요.', detail: '단순히 정답을 확인하고 넘어가기보다, 왜 틀렸는지(비슷한 발음과 헷갈림, 어순 실수, 뜻을 잘못 기억함 등) 한 줄로 짧게 메모해두면 나중에 비슷한 유형의 실수를 훨씬 빨리 알아차릴 수 있습니다. 이런 메모가 쌓이면 자신만의 취약 패턴을 스스로 파악하는 데 큰 도움이 됩니다.', action: '다음에 틀리면 이유를 한 줄로 메모해보는 습관을 들이세요.' },
  { id: 'g_study_teach_to_learn', category: '학습법', tags: ['팁', '배운', '설명해보기'], label: '배운 걸 남에게 설명해보기', tipKo: '오늘 배운 표현을 친구나 가족에게 짧게 설명해보면, 내가 정말 이해했는지 확실히 드러나요.', detail: '어떤 내용을 진짜로 이해했는지 확인하는 가장 확실한 방법은 그것을 다른 사람에게 설명해보는 것입니다. 오늘 배운 표현이나 문화 팁을 친구나 가족에게 간단히 설명해보면, 말로 풀어내는 과정에서 애매하게 알고 있던 부분이 스스로 드러나고 자연스럽게 복습 효과도 얻을 수 있습니다.', action: '오늘 배운 팁 하나를 주변 사람에게 설명해 보세요.' },
  { id: 'g_study_small_goal_streak', category: '학습법', tags: ['카드', '며칠', '연속'], label: '완벽보다 "며칠 연속"이 더 중요해요', tipKo: '하루 100% 완벽히 하는 것보다, 부담 없는 목표로 꾸준히 이어가는 "연속 기록"이 장기적으로 더 큰 힘이 돼요.', detail: '학습 동기 부여 연구에서는 하루의 완성도보다 며칠간 꾸준히 이어가는 "연속 기록(스트릭)" 자체가 습관 형성에 훨씬 중요한 역할을 한다고 강조합니다. 컨디션이 안 좋은 날은 목표를 낮춰서라도(카드 5개만 등) 연속 기록을 이어가는 것이, 어느 날 무리해서 몰아치고 다음 날 완전히 쉬어버리는 것보다 장기적으로 훨씬 효과적입니다.', action: '오늘 컨디션이 안 좋다면 목표를 낮춰서라도 하루를 이어가 보세요.' },
  { id: 'g_study_use_it_same_day', category: '학습법', tags: ['배운', '표현', '그날', '써보기'], label: '배운 표현은 그날 한 번은 써보기', tipKo: '새로 배운 표현은 그날이 가기 전에 한 번이라도 실제로 소리 내어 써보면 기억에 훨씬 오래 남아요.', detail: '새로 배운 표현을 그날 안에 한 번이라도 실제 상황(가상의 롤플레이라도)에서 소리 내어 사용해보면, 단순히 눈으로만 복습하는 것보다 기억에 훨씬 오래 남는다는 것이 여러 언어학습 연구에서 확인되었습니다. 여행 중이라면 실제로 그 표현을 써볼 기회가 바로 생기니, 배운 즉시 시도해보는 적극성이 중요합니다.', action: '오늘 배운 표현을 잠자리에 들기 전 한 번 소리 내 말해보세요.' },
  { id: 'g_study_compare_similar', category: '학습법', tags: ['표현', '짝지어', '외우기'], label: '비슷한 표현은 짝지어 비교하며 외우기', tipKo: 'ここ・そこ・あそこ처럼 비슷한 표현군은 따로따로 외우기보다 나란히 비교하며 외우면 훨씬 오래 남아요.', detail: '비슷한 형태나 뜻을 가진 표현들은 하나씩 따로 외우기보다, 서로 나란히 놓고 차이점을 비교하며 외우는 것이 기억에 훨씬 효과적입니다. これ・それ・あれ나 ここ・そこ・あそこ처럼 계열을 이루는 표현은 세트로 묶어 학습하면 개별 암기보다 구조적으로 이해하게 되어 오래 기억에 남습니다.', action: '헷갈리는 표현 두 개를 나란히 놓고 차이를 정리해 보세요.' },
  { id: 'g_study_celebrate_progress', category: '학습법', tags: ['카드', '발전', '스스', '인정해주기'], label: '작은 발전도 스스로 인정해주기', tipKo: '처음보다 조금이라도 나아졌다면, 그 자체를 스스로 인정하고 넘어가는 태도가 꾸준함을 만들어요.', detail: '외국어 학습은 눈에 띄는 큰 도약보다 눈에 잘 안 보이는 작은 발전이 쌓여가는 과정이라, 스스로 그 작은 변화를 알아채고 인정해주는 태도가 장기적인 동기 부여에 큰 역할을 합니다. "지난달보다 지금 이 카드를 더 빨리 맞혔다"처럼 구체적인 작은 발전을 의식적으로 알아채는 습관을 들이면 꾸준히 학습을 이어가기가 훨씬 수월해집니다.', action: '이번 주 학습 통계를 확인하고 지난주와 비교해 보세요.' },

  // ── 여행 실전 추가 ──
  { id: 'g_travel_luggage_lock_rule', category: '여행', tags: ['기내', '수하물', '캐리어', 'TSA락'], label: '기내 수하물 캐리어, 자물쇠는 TSA락으로', tipKo: '해외에서 캐리어를 잠글 땐 보안 검색 요원이 열 수 있는 TSA(자물쇠 인증) 제품을 쓰는 것이 안전해요.', detail: '일반 자물쇠로 캐리어를 잠그면 보안 검색 과정에서 짐을 열어야 할 때 자물쇠가 강제로 파손될 수 있는데, TSA 인증 자물쇠는 특수 마스터키로 검색 요원이 손상 없이 열고 다시 잠글 수 있게 설계되어 있습니다. 해외 여행이 잦다면 이 인증 마크가 있는 자물쇠를 하나 마련해두는 것이 짐 보안과 편의를 동시에 지키는 방법입니다.' },
  { id: 'g_travel_emergency_phrases_card', category: '여행', tags: ['카드', '숙소', '알레르기', '응급'], label: '비상 연락 카드 하나 미리 만들어두기', tipKo: '숙소 주소·알레르기·비상연락처를 적은 카드를 지갑에 넣어두면, 말이 막히는 응급상황에서 그대로 보여줄 수 있어요.', detail: '위급하거나 말이 잘 안 통하는 상황에서는 아무리 표현을 외워도 순간적으로 입이 떨어지지 않을 수 있는데, 숙소 주소·알레르기 정보·비상 연락처를 적은 작은 카드를 미리 만들어 지갑에 넣어두면 그 순간 카드를 그대로 보여주는 것만으로 훨씬 빠르고 정확하게 상황을 전달할 수 있습니다.', action: '출국 전 비상 카드 한 장을 만들어 지갑에 넣어두세요.' },
  { id: 'g_travel_convenience_store_wifi', category: '여행', tags: ['공항', '기차', '와이파이', '편의점'], label: '무료 와이파이는 편의점·역에서', tipKo: '주요 편의점·기차역·공항은 대부분 관광객용 무료 와이파이를 제공하니, 데이터가 부족할 때 활용하면 좋아요.', detail: '일본의 주요 편의점 체인과 기차역, 공항 대부분은 외국인 관광객을 위한 무료 와이파이 서비스를 제공하고 있어, 데이터가 부족하거나 잠깐 지도를 확인해야 할 때 요긴하게 활용할 수 있습니다. 다만 최초 접속 시 이메일 등록이 필요한 경우가 많으니, 여유가 있을 때 미리 등록해두는 것이 좋습니다.' },
  { id: 'g_travel_typhoon_season_check', category: '여행', tags: ['신칸센', '태풍', '시즌엔', '예비', '일정'], label: '태풍 시즌엔 예비 일정을 짜두세요', tipKo: '여름~가을 태풍 시즌에 여행한다면, 신칸센·항공편 결항에 대비해 하루 정도 여유 일정을 짜두는 게 안전해요.', detail: '일본은 여름부터 가을까지 태풍의 영향을 자주 받는데, 태풍이 근접하면 신칸센과 항공편이 대거 결항되는 경우가 흔합니다. 이 시기에 여행한다면 촘촘하게 일정을 짜기보다 하루 정도 예비일을 남겨두고, 기상청·항공사 앱으로 출발 전날 미리 운항 상황을 확인하는 습관을 들이는 것이 안전합니다.' },
  { id: 'g_travel_seasonal_clothing_layers', category: '여행', tags: ['일교차', '계절엔', '겹쳐', '입기'], label: '일교차 큰 계절엔 겹쳐 입기', tipKo: '봄·가을은 아침저녁 기온차가 커서, 벗고 입기 편한 겉옷을 겹쳐 입는 것이 여행 내내 편해요.', detail: '일본의 봄과 가을은 아침저녁과 한낮의 기온 차이가 상당히 커서, 두꺼운 옷 한 벌보다 얇은 옷을 여러 겹 겹쳐 입어 상황에 따라 벗고 입기 쉽게 준비하는 것이 훨씬 실용적입니다. 실내 냉난방이 강한 경우도 많아, 가벼운 겉옷 하나를 항상 챙기는 것이 여행 내내 편안함을 유지하는 요령입니다.' },
  { id: 'g_travel_ic_card_balance_check', category: '여행', tags: ['카드', 'IC카드', '편의점', '잔액', '미리'], label: 'IC카드 잔액은 미리 확인하는 습관을', tipKo: '개찰구에서 잔액 부족으로 막히지 않도록, 역 내 잔액 확인 기기나 편의점 계산 화면에서 미리 잔액을 확인해두면 안전해요.', detail: '교통 IC카드는 잔액이 부족하면 개찰구를 통과하지 못하고 막히는 경우가 있어, 특히 출퇴근 혼잡 시간대에 뒷사람에게 폐를 끼칠 수 있습니다. 역 내 잔액 확인·충전 기기나 편의점 계산 시 화면에 표시되는 잔액을 틈틈이 확인해두고, 여유 있을 때 미리 충전해두는 습관을 들이면 안전합니다.' },
  { id: 'g_travel_restaurant_no_seating_wait', category: '여행', tags: ['식당', '인기', '맛집', '대기', '명부'], label: '인기 맛집은 대기 명부에 이름부터', tipKo: '줄이 길어 보이면 우선 입구의 대기 명부(名簿)에 이름과 인원수를 적어두고 기다리는 것이 순서를 놓치지 않는 요령이에요.', detail: '인기 있는 식당은 입구나 벽에 대기 명부를 놓아두는 경우가 많은데, 줄이 길어 보인다고 그냥 지나치기보다 우선 이름과 인원수를 적어두면 그 시간 동안 주변을 둘러보거나 다른 볼일을 볼 수 있어 훨씬 효율적입니다. 이름을 부를 때 대답하지 못하면 순서가 뒤로 밀릴 수 있으니, 호출 시간대에는 근처에 머무는 것이 좋습니다.' },
  { id: 'g_travel_photo_etiquette_people', category: '여행', tags: ['낯선', '사람', '사진', '찍기'], label: '낯선 사람 사진은 허락받고 찍기', tipKo: '거리의 낯선 사람이나 상점 직원을 사진에 담고 싶다면, 촬영 전 一枚撮ってもいいですか(한 장 찍어도 될까요?)로 양해를 구하세요.', detail: '아름다운 거리 풍경 속에 지나가는 사람이 우연히 찍히는 것과 달리, 특정 인물이나 상점 내부·직원을 의도적으로 촬영하고 싶다면 사전에 양해를 구하는 것이 예의입니다. 一枚撮ってもいいですか(한 장 찍어도 될까요)라고 물어보고 허락을 받은 뒤 촬영하면, 불필요한 오해나 불쾌감을 피할 수 있습니다.', exampleJa: '一枚撮ってもいいですか', exampleKo: '한 장 찍어도 될까요?' },

  // ── 마트·쇼핑 추가 ──
  { id: 'g_mart_point_card_hassle', category: '마트·쇼핑', tags: ['카드', '포인트', '거절'], label: '포인트카드는 없으면 그냥 넘어가도 돼요', tipKo: '계산 시 ポイントカードはお持ちですか(포인트카드 있으세요?)라고 물으면, 없으면 だいじょうぶです(괜찮아요)라고 짧게 답하면 끝이에요.', detail: '일본 매장 대부분은 계산 시 자체 포인트카드 소지 여부를 묻는 것이 관례인데, 여행자는 대부분 해당 카드가 없으므로 だいじょうぶです(괜찮아요) 또는 もっていません(없어요)이라고 짧게 답하면 바로 다음 절차로 넘어갑니다. 굳이 길게 설명하지 않아도 되는 짧고 확실한 대답입니다.', exampleJa: 'ポイントカードはお持ちですか', exampleKo: '포인트카드 있으세요?' },
  { id: 'g_mart_weigh_produce_self', category: '마트·쇼핑', tags: ['슈퍼', '채소', '코너', '계량'], label: '슈퍼 채소 코너, 직접 무게 재는 곳도 있어요', tipKo: '일부 슈퍼는 채소·과일을 봉투에 담은 뒤 손님이 직접 계량기에 올려 가격표를 뽑아 붙여야 해요.', detail: '일부 슈퍼마켓의 청과 코너에서는 낱개 판매 채소나 과일을 비닐봉투에 담은 뒤, 근처에 놓인 계량기에 직접 올려 무게에 따른 가격표를 뽑아 봉투에 붙이는 셀프 계량 시스템을 운영합니다. 이 과정을 생략하고 그냥 계산대로 가져가면 가격을 매길 수 없어 다시 돌려보내지는 경우가 있으니, 코너에 계량기가 보이면 먼저 이용하는 것이 좋습니다.' },
  { id: 'g_mart_receipt_for_tax_free', category: '마트·쇼핑', tags: ['면세', '영수증', '공항', '출국'], label: '면세 영수증은 출국 전까지 보관하세요', tipKo: '면세로 구매한 물건의 영수증은 출국 심사에서 확인할 수 있으니, 여권과 함께 잘 보관해야 해요.', detail: '면세로 구매한 물품과 그 영수증은 출국 시 세관에서 확인 절차를 거칠 수 있으므로, 여행 마지막까지 여권 사이에 끼워 두는 등 잃어버리지 않게 잘 보관해야 합니다. 일부 국제공항에서는 출국 전 별도의 면세품 확인 카운터를 거쳐야 하는 경우도 있어, 출발 시간에 여유를 두고 공항에 도착하는 것이 안전합니다.' },
  { id: 'g_mart_drugstore_medicine_types', category: '마트·쇼핑', tags: ['드럭스토어', '등급', '표시'], label: '드럭스토어 약은 등급 표시를 확인하세요', tipKo: '일본 드럭스토어 약은 제1류~제3류로 나뉘는데, 등급이 높을수록 약사 설명이 필요해 진열대가 아닌 카운터에 있어요.', detail: '일본의 일반의약품은 부작용 위험도에 따라 제1류부터 제3류까지 등급이 나뉘는데, 제1류처럼 위험도가 높은 약은 약사의 설명을 들어야 살 수 있어 매대가 아닌 카운터 뒤에 진열되어 있습니다. 원하는 약이 매대에 안 보인다면 직원에게 물어보면 카운터에서 따로 안내받을 수 있습니다.' },
  { id: 'g_mart_convenience_bill_payment', category: '마트·쇼핑', tags: ['편의점', '공과금'], label: '편의점에서 공과금까지 낼 수 있어요', tipKo: '일본 편의점은 전기·가스요금은 물론, 각종 티켓 예매비까지 바코드만 있으면 계산대에서 납부할 수 있어요.', detail: '일본 편의점은 물건 판매를 넘어 전기·수도·가스 같은 공과금, 각종 행사 티켓 예매비, 심지어 일부 세금까지 청구서에 인쇄된 바코드를 스캔해 그 자리에서 납부할 수 있는 종합 결제 창구 역할도 합니다. 장기 체류자라면 이 기능을 알아두면 생활이 훨씬 편리해집니다.' },
  { id: 'g_mart_cosmetics_tester', category: '마트·쇼핑', tags: ['팁', '드럭스토어', '매너', '화장품', '매장'], label: '화장품 매장의 테스터는 자유롭게 써도 돼요', tipKo: '드럭스토어·화장품 매장의 테스터(試供品)는 손님이 자유롭게 발라보고 향을 맡아볼 수 있게 마련된 것이에요.', detail: '일본 드럭스토어와 화장품 전문 매장에는 손님이 구매 전 직접 발라보고 향을 맡아볼 수 있도록 테스터가 곳곳에 비치되어 있는데, 이는 자유롭게 사용해도 되는 서비스입니다. 위생을 위해 대부분 면봉이나 종이 팁이 함께 놓여 있으니 이를 사용해 위생적으로 테스트해보는 것이 매너입니다.' },

  // ── 요즘 일본 추가 ──
  { id: 'g_trend_robot_service_staff', category: '요즘 일본', tags: ['호텔', '체크인', '식당', '프런트', '로봇'], label: '호텔 프런트에 로봇 직원이 있는 곳도', tipKo: '일부 호텔·식당은 인력난 해소를 위해 안내·서빙을 담당하는 로봇을 도입하는 사례가 늘고 있어요.', detail: '최근 일본은 서비스업 인력난이 심화되면서, 일부 호텔의 체크인 카운터나 식당 홀에서 손님을 안내하거나 음식을 서빙하는 로봇을 도입하는 사례가 늘고 있습니다. 이런 로봇은 아직 완전히 사람을 대체하기보다는 반복적인 업무를 보조하는 역할이 많아, 신기한 경험을 원하는 여행자에게는 재미있는 볼거리가 되기도 합니다.' },
  { id: 'g_trend_foreign_worker_increase', category: '요즘 일본', tags: ['편의점', '식당', '외국인', '노동자'], label: '외국인 노동자가 눈에 띄게 늘었어요', tipKo: '최근 일손 부족으로 편의점·식당·공장에서 일하는 외국인 노동자가 크게 늘어, 영어·간단한 한국어가 통하는 곳도 많아졌어요.', detail: '고령화와 인구 감소로 인한 일손 부족이 심화되며, 최근 일본 정부는 외국인 노동자 수용 정책을 크게 완화했고 그 결과 편의점·식당·공장 등에서 외국인 직원을 마주치는 일이 눈에 띄게 늘었습니다. 덕분에 일부 매장에서는 영어나 다른 외국어로도 어느 정도 소통이 가능해진 경우도 있습니다.' },
  { id: 'g_trend_price_increase_awareness', category: '요즘 일본', tags: ['엔저', '계속'], label: '엔저에도 물가는 계속 오르고 있어요', tipKo: '엔화 약세로 여행 경비 부담은 줄었지만, 최근 몇 년 사이 일본 내 식료품·외식 물가도 꾸준히 오르고 있다는 점을 참고하세요.', detail: '엔화 약세 덕분에 원화나 달러 기준 여행 경비는 상대적으로 저렴해졌지만, 일본 내부적으로는 원자재 가격 상승 등의 영향으로 식료품과 외식 물가가 예년보다 꾸준히 오르고 있습니다. "엔저니까 다 저렴하다"는 인식만으로 예산을 짜기보다, 최신 현지 물가를 미리 검색해보는 것이 좋습니다.' },
  { id: 'g_trend_digital_nomad_visa', category: '요즘 일본', tags: ['디지털노마드', '비자'], label: '디지털노마드 비자가 새로 생겼어요', tipKo: '최근 일본은 원격근무 외국인을 위한 디지털노마드 비자를 신설해, 장기 체류 조건으로 일하며 여행하는 것이 가능해졌어요.', detail: '일본은 원격근무가 가능한 외국인 전문직을 유치하기 위해 일정 소득 기준을 충족하면 장기 체류를 허용하는 디지털노마드 비자 제도를 새로 도입했습니다. 이를 통해 관광비자보다 긴 기간 동안 일본에 머물며 일하는 동시에 현지 생활을 경험하는 방식의 체류가 가능해졌습니다.' },
  { id: 'g_trend_ai_translation_devices', category: '요즘 일본', tags: ['호텔', '마트', '식당', 'AI', '번역기'], label: 'AI 번역기가 접객 현장에 자리잡고 있어요', tipKo: '식당·호텔 프런트에서 스마트폰 번역 앱이나 전용 번역기를 활용해 외국인 손님과 소통하는 모습이 흔해졌어요.', detail: '스마트폰 번역 앱과 전용 휴대용 번역기의 정확도가 크게 높아지면서, 이제 많은 식당과 호텔 프런트에서 직원이 직접 이 기기를 이용해 외국인 손님과 실시간으로 소통하는 모습을 흔히 볼 수 있습니다. 여행자 입장에서도 말이 막히면 상대가 먼저 번역기를 꺼내는 경우가 많아, 언어 장벽에 대한 부담이 예전보다 줄었습니다.' },
  { id: 'g_trend_local_guide_apps', category: '요즘 일본', tags: ['현지인', '여행', '가이드'], label: '현지인과 연결해주는 여행 가이드 앱', tipKo: '최근에는 현지 주민이 직접 여행자에게 동네를 안내해주는 매칭 앱·서비스가 늘어 더 깊이 있는 여행이 가능해졌어요.', detail: '정형화된 패키지 투어 대신, 현지 주민과 여행자를 연결해 그 지역만의 숨은 장소를 안내받을 수 있는 매칭형 여행 서비스와 앱이 최근 늘어나고 있습니다. 이런 서비스를 이용하면 가이드북에 없는 로컬 맛집이나 생활 밀착형 정보를 얻을 수 있어, 좀 더 깊이 있는 여행을 원하는 사람들 사이에서 인기를 끌고 있습니다.' },

  // ── 일정별 팁 추가 ──
  { id: 'g_trip_daytrip_train_pass_calc', category: '일정별 팁', tags: ['지하철', '버스', '당일치기', '지역', '확인'], label: '당일치기는 그 지역 1일권부터 확인', tipKo: '당일치기로 한 도시를 집중적으로 돌 계획이면, 개별 승차권보다 그 지역 전용 1일 승차권이 이득인 경우가 많아요.', detail: '하루 동안 한 도시의 여러 명소를 지하철·버스로 오가며 돌아볼 계획이라면, 매번 개별 승차권을 사는 것보다 그 지역 교통기관이 파는 1일 승차권(一日乗車券)을 사는 편이 총비용을 낮추는 경우가 많습니다. 관광안내소나 역에서 이런 패스가 있는지 미리 확인해보는 것이 좋습니다.' },
  { id: 'g_trip_short_trip_priority_list', category: '일정별 팁', tags: ['일정', '우선순위', '단기여행'], label: '3박4일이면 "꼭 갈 곳" 3개만 확실히', tipKo: '짧은 일정일수록 욕심껏 계획을 짜다 지치기 쉬워요. 정말 가고 싶은 곳 2~3곳만 확실히 정하고 나머지는 여유롭게 비워두세요.', detail: '짧은 일정에 너무 많은 장소를 욱여넣으면 이동에만 시간을 다 쓰고 정작 어느 곳도 여유롭게 즐기지 못하는 경우가 흔합니다. 반드시 가고 싶은 곳 2~3곳만 확실히 정해두고 나머지 시간은 비워두면, 예상치 못한 좋은 장소를 우연히 발견하거나 마음에 든 곳에서 더 오래 머무는 여유를 가질 수 있습니다.' },
  { id: 'g_trip_month_gym_membership', category: '일정별 팁', tags: ['한달살기', '단기', '헬스장', '이용권'], label: '한달살기라면 단기 헬스장 이용권도 있어요', tipKo: '많은 일본 헬스장 체인은 여행자를 위한 1개월 단위 단기 회원권을 운영해, 장기 체류 중 운동 루틴을 이어갈 수 있어요.', detail: '일본의 대형 헬스장 체인 중에는 정식 장기 계약 없이 1개월 단위로 이용할 수 있는 단기 회원권을 운영하는 곳이 있어, 한달살기 중에도 운동 루틴을 그대로 이어가고 싶은 사람에게 유용합니다. 외국인도 여권만으로 가입할 수 있는 경우가 많으니, 도착 후 관심 있는 체인의 단기 회원권 여부를 문의해보면 좋습니다.' },
  { id: 'g_trip_daytrip_return_time_buffer', category: '일정별 팁', tags: ['당일치기', '막차', '시간', '여유'], label: '당일치기 막차 시간은 여유 있게 계산하세요', tipKo: '지방 당일치기 여행은 마지막 열차를 놓치면 큰일이니, 계획한 시간보다 30분~1시간 여유를 두고 역으로 이동하세요.', detail: '지방 소도시로 당일치기 여행을 떠날 경우 막차 시간이 도심보다 훨씬 이른 경우가 많아, 여유를 두지 않으면 마지막 열차를 놓쳐 낭패를 볼 수 있습니다. 예정된 귀환 열차 시간보다 30분에서 1시간 정도 여유를 두고 역으로 이동하는 습관을 들이면, 예상치 못한 지연에도 안전하게 대응할 수 있습니다.' },
  { id: 'g_trip_month_local_community', category: '일정별 팁', tags: ['축제', '한달살기', '동네', '모임'], label: '한달살기는 동네 축제·모임에 참여해보세요', tipKo: '장기 체류 중이라면 동네 게시판이나 SNS에서 지역 축제·교류 모임 정보를 찾아 참여해보면 훨씬 깊은 경험이 돼요.', detail: '짧은 여행에서는 접하기 어려운 지역 축제나 주민 교류 모임이, 한 달 이상 머무는 장기 체류자에게는 오히려 좋은 기회가 될 수 있습니다. 동네 게시판이나 지자체 SNS 계정에서 이런 정보를 찾아 참여해보면, 관광객으로서는 볼 수 없는 일본의 일상적인 모습을 훨씬 깊이 경험할 수 있습니다.' },
  { id: 'g_trip_short_trip_jetlag_light', category: '일정별 팁', tags: ['숙소', '일정', '시차', '적응', '하루'], label: '짧은 일정은 시차 적응에 하루를 쓰지 마세요', tipKo: '짧은 여행에서 시차 적응한다고 첫날을 통째로 쉬면 아까워요. 도착 당일은 가벼운 야외 활동으로 몸을 적응시키는 편이 효율적이에요.', detail: '일정이 짧을수록 도착 첫날을 시차 적응을 이유로 통째로 숙소에서 쉬는 것은 아까운 선택이 될 수 있습니다. 대신 도착 당일 가벼운 산책이나 근처 관광으로 햇빛을 쬐고 몸을 적당히 움직이면, 오히려 시차 적응에도 도움이 되면서 짧은 일정을 알차게 활용할 수 있습니다.' },

  // ── 문화 추가 ──
  { id: 'g_culture_gift_giving_both_hands', category: '문화', tags: ['물건', '양손'], label: '물건은 양손으로 주고받아요', tipKo: '명함·선물·거스름돈을 건네거나 받을 때 한 손보다 양손을 쓰면 훨씬 정중한 인상을 줘요.', detail: '일본에서는 명함이나 선물, 심지어 거스름돈을 주고받을 때도 한 손보다 양손을 함께 쓰는 것이 훨씬 정중하고 예의 바른 태도로 여겨집니다. 특히 비즈니스 명함을 교환할 때는 양손으로 공손히 건네고 받는 것이 거의 정해진 예절처럼 지켜집니다.' },
  { id: 'g_culture_indirect_refusal', category: '문화', tags: ['완곡거절', '눈치'], label: '"어렵겠네요"는 사실상 거절이에요', tipKo: '직접 「안 돼요」라고 하지 않고 「ちょっとむずかしいですね」(좀 어렵겠네요)라고 하면, 이는 사실상 정중한 거절이에요.', detail: '일본어 화법에서는 직접적인 거절 대신 완곡한 표현으로 부정적인 의사를 전달하는 경우가 많아, ちょっとむずかしいですね(좀 어렵겠네요)라는 말을 들으면 이는 검토해보겠다는 뜻이 아니라 사실상 거절에 가깝다는 것을 이해하는 것이 중요합니다. 문자 그대로 해석하고 계속 요청하면 서로 곤란해질 수 있습니다.' },
  { id: 'g_culture_business_card_manner', category: '문화', tags: ['명함', '예절'], label: '명함은 받은 자리에서 바로 넣지 않아요', tipKo: '명함을 받으면 그 자리에서 바로 주머니에 넣지 않고, 잠시 테이블 위에 올려두거나 살펴보는 것이 예의로 여겨져요.', detail: '비즈니스 상황에서 명함을 건네받으면 곧바로 주머니나 지갑에 넣기보다, 잠시 그 자리에서 이름과 직함을 확인하듯 살펴본 뒤 테이블 위에 올려두는 것이 상대를 존중하는 예의로 여겨집니다. 이는 여행자가 자주 겪는 상황은 아니지만, 알아두면 일본 문화를 이해하는 데 도움이 됩니다.' },
  { id: 'g_culture_seasonal_greeting_words', category: '문화', tags: ['계절', '인사말', '편지', '메일', '관례'], label: '계절 인사말이 편지·메일에 꼭 들어가요', tipKo: '일본어 격식 편지·이메일은 본론 전에 계절 인사(季節の挨拶)로 시작하는 것이 정형화된 관례예요.', detail: '일본어 격식 편지나 비즈니스 이메일은 본론에 들어가기 전에 그 계절에 맞는 정형화된 인사말(季節の挨拶)로 시작하는 것이 오랜 관례로 자리 잡아 있습니다. 예를 들어 초여름에는 신록이 우거지는 계절이라는 표현을, 한겨울에는 추위가 매서워지는 계절이라는 표현을 넣는 식으로, 계절감을 담아 글을 시작하는 것이 격식 있는 문장 예절로 여겨집니다.' },
  { id: 'g_culture_group_harmony_wa', category: '문화', tags: ['팁', '매너', '집단주의', '조화', '가치관'], label: '와(和) — 튀지 않고 조화를 중시하는 마음', tipKo: '일본 사회 전반에 흐르는 "와(和)"라는 가치관은 개인의 튀는 행동보다 집단의 조화를 우선하는 태도예요.', detail: '와(和)는 조화를 뜻하는 개념으로, 일본 사회 전반에서 개인의 개성이나 주장을 강하게 내세우기보다 집단 안에서의 조화와 균형을 우선시하는 태도로 자주 언급됩니다. 이런 가치관은 공공장소에서의 매너, 줄서기 문화, 완곡한 화법 등 이 앱에서 다룬 여러 문화 팁의 밑바탕에 깔린 공통된 정서이기도 합니다.' },

  // ── 여행 실전 2차 보강(재미·잡학 100→50 압축분을 여행으로 이전) ──
  { id: 'g_travel_insurance_basics', category: '여행', tags: ['카드', '여행자보험', '출국', '필수'], label: '여행자보험은 출국 전 필수로 챙기세요', tipKo: '작은 사고·질병도 해외 의료비는 예상보다 훨씬 비싸요. 출국 전 여행자보험 가입은 선택이 아니라 필수로 여기는 게 안전해요.', detail: '해외에서는 가벼운 진료조차 국내보다 비용이 훨씬 높게 청구되는 경우가 많아, 여행자보험 없이 병원에 갔다가 예상치 못한 큰 비용을 치르는 사례가 적지 않습니다. 신용카드에 기본으로 딸린 보험도 있지만 보장 범위가 제한적인 경우가 많으니, 여행 기간·활동(스키·다이빙 등)에 맞춰 별도 상품을 확인하는 것이 안전합니다.', action: '출국 전 보험 증서를 사진으로 찍어 클라우드에 저장해두세요.' },
  { id: 'g_travel_currency_exchange_timing', category: '여행', tags: ['환전', '공항', '편의점', '출국', '일부'], label: '환전은 출국 전 일부, 도착 후 일부로', tipKo: '환율이 좋을 때 한꺼번에 다 바꾸기보다, 출국 전 소액+도착 후 ATM 인출을 섞으면 유리할 때가 많아요.', detail: '환율은 매일 변동하기 때문에 출국 전 모든 금액을 한 번에 환전하기보다, 초기 필요 경비만 국내에서 환전하고 나머지는 현지 도착 후 편의점 ATM에서 필요할 때마다 인출하는 방식이 환율 변동 위험을 분산시키는 데 유리한 경우가 많습니다. 공항 환전소는 환율이 상대적으로 불리한 편이니 소액만 급히 바꾸는 용도로 쓰는 것이 좋습니다.' },
  { id: 'g_travel_roaming_vs_esim', category: '여행', tags: ['로밍', '신사', 'e심', '일정', '맞춰'], label: '로밍 vs e심, 일정에 맞춰 고르세요', tipKo: '통신사 로밍은 간편하지만 비싸고, e심은 저렴하지만 도착 전 미리 설정해두는 준비가 필요해요.', detail: '통신사 로밍은 기존 번호를 그대로 쓰고 설정도 간단하지만 요금이 상대적으로 비싸고, e심은 데이터 요금이 훨씬 저렴하지만 출국 전 미리 앱으로 구매·설정해두어야 도착 즉시 사용할 수 있습니다. 짧은 여행이고 간편함이 중요하다면 로밍을, 데이터를 많이 쓰거나 비용을 아끼고 싶다면 e심을 미리 준비하는 것이 좋습니다.' },
  { id: 'g_travel_flight_booking_timing', category: '여행', tags: ['금연', '예약', '벚꽃', '항공권', '성수기'], label: '항공권은 성수기 기준 2~3개월 전이 적당해요', tipKo: '너무 일찍도, 너무 늦게도 비쌀 수 있어요. 벚꽃·황금연휴 등 성수기는 최소 2~3개월 전 예약을 목표로 하세요.', detail: '항공권 가격은 수요에 따라 출렁이는데, 벚꽃 시즌이나 골든위크 같은 성수기는 좌석이 빨리 차기 때문에 최소 2~3개월 전에는 예약을 마치는 것이 안전합니다. 반대로 비수기라면 출발 3~4주 전 특가가 나오는 경우도 있어, 일정에 여유가 있다면 가격 알림 서비스를 걸어두고 지켜보는 것도 방법입니다.' },
  { id: 'g_travel_carryon_size_rules', category: '여행', tags: ['예약', '기내', '반입', '캐리어', '크기'], label: '기내 반입 캐리어 크기, 항공사마다 달라요', tipKo: '국내선·저비용항공사는 기내 수하물 크기·무게 제한이 더 엄격한 경우가 많아 미리 확인이 필요해요.', detail: '일본 국내선이나 저비용항공사(LCC)는 대형 항공사보다 기내 반입 수하물의 크기·무게 제한이 더 엄격한 경우가 많아, 국제선 기준으로 준비했다가 국내선 환승에서 추가 요금을 내는 경우가 생길 수 있습니다. 예약한 항공사 홈페이지에서 기내 수하물 규정을 출국 전 다시 한번 확인하는 것이 안전합니다.' },
  { id: 'g_travel_passport_validity', category: '여행', tags: ['여권', '유효기간', '6개월', '이상', '남았는지'], label: '여권 유효기간, 6개월 이상 남았는지 확인', tipKo: '많은 나라가 입국 시 여권 유효기간이 6개월 이상 남아있을 것을 요구해요. 출국 전 꼭 확인하세요.', detail: '일본을 포함한 여러 나라는 입국 심사에서 여권의 잔여 유효기간이 최소 6개월 이상 남아있을 것을 요구하는 경우가 있어, 유효기간이 얼마 안 남았다면 출국 전에 반드시 갱신해야 합니다. 특히 왕복 항공권을 기준으로 계산되므로, 귀국일까지 여유 있게 남았는지도 함께 확인하는 것이 좋습니다.' },
  { id: 'g_travel_medicine_bring_rules', category: '여행', tags: ['상비약', '반입'], label: '상비약, 일부는 반입 제한이 있어요', tipKo: '평소 먹는 처방약을 챙긴다면, 일본 반입 가능 수량·성분 규정을 미리 확인하는 게 안전해요.', detail: '일본은 일부 성분(의사 처방이 필요한 각성제 성분 등)이 포함된 약을 개인이 반입할 때 수량 제한이나 별도 서류(증명서)를 요구하는 경우가 있어, 평소 복용하는 처방약이 있다면 출국 전 반입 가능 여부를 확인하는 것이 안전합니다. 일반적인 감기약·진통제 정도는 개인 사용 목적의 소량이면 대체로 문제가 없습니다.' },
  { id: 'g_travel_luggage_weight_check', category: '여행', tags: ['공항', '귀국', '미리'], label: '귀국 짐, 무게 초과를 미리 대비하세요', tipKo: '쇼핑을 많이 했다면 귀국편 수하물 무게가 초과되기 쉬워요. 여행용 저울을 챙기면 공항에서 당황하지 않아요.', detail: '여행 막바지에 쇼핑을 많이 하면 갈 때보다 짐이 훨씬 무거워져 귀국편 수하물 무게 제한을 초과하는 경우가 흔한데, 작고 가벼운 여행용 전자저울을 챙겨두면 공항에 가기 전 미리 무게를 확인하고 짐을 조정할 수 있습니다. 초과 시 추가 요금이 꽤 비싸므로, 무거운 물건은 기내 수하물로 분산하는 것도 방법입니다.' },
  { id: 'g_travel_no_jetlag_reminder', category: '여행', tags: ['일본', '시차', '시차없음'], label: '일본은 시차가 거의 없어 몸이 편해요', tipKo: '한국과 일본은 시차가 없어(동일 표준시), 장시간 비행 시차 적응 걱정 없이 도착 당일부터 활동할 수 있어요.', detail: '한국과 일본은 같은 표준시를 쓰기 때문에 시차 적응이라는 부담이 거의 없어, 도착 당일부터 무리 없이 일정을 소화할 수 있다는 것이 다른 장거리 여행지와 다른 큰 장점입니다. 비행시간도 짧은 편이라 주말을 이용한 짧은 여행에도 부담이 적습니다.' },
  { id: 'g_travel_useful_apps', category: '여행', tags: ['여행', '번역앱', '지도앱'], label: '여행 전 깔아두면 좋은 앱 몇 가지', tipKo: '지도·환승 검색·번역·배달 앱을 미리 깔고 로그인까지 해두면, 현지에서 데이터 걱정 없이 바로 쓸 수 있어요.', detail: '일본 여행에는 실시간 환승 정보를 보여주는 노선 검색 앱, 오프라인 지도를 받아둘 수 있는 지도 앱, 카메라로 바로 번역되는 번역 앱이 특히 유용한데, 출국 전 미리 설치하고 로그인·오프라인 데이터까지 받아두면 현지에서 데이터가 불안정해도 당황하지 않을 수 있습니다.' },
  { id: 'g_travel_small_bills_ready', category: '여행', tags: ['동전', '잔돈', '편의점', '자판기', '신사'], label: '엔화 소액권·동전을 넉넉히 준비하세요', tipKo: '자판기·코인로커·신사 새전함은 소액권과 동전만 받는 경우가 많아요. 만엔권만 있으면 곤란할 수 있어요.', detail: '자판기, 코인로커, 신사의 새전함처럼 일상적으로 자주 마주치는 결제 상황은 소액권과 동전만 받는 경우가 대부분이라, 만 엔권 같은 고액권만 들고 있으면 정작 필요한 순간에 곤란할 수 있습니다. 편의점에서 물건을 하나 사며 고액권을 미리 잔돈으로 바꿔두는 것도 요령입니다.' },
  { id: 'g_travel_card_foreign_fee', category: '여행', tags: ['카드', '수수료', '해외결제', '미리'], label: '카드 해외결제 수수료, 미리 비교해두세요', tipKo: '카드마다 해외 결제 수수료율이 달라요. 여행 전 수수료가 낮은 카드를 하나 만들어두면 여행 내내 이득이에요.', detail: '해외에서 카드를 쓸 때는 카드사·상품마다 해외 이용 수수료율이 다르게 붙는데, 이 차이가 여행 기간 전체로 보면 꽤 큰 금액이 될 수 있습니다. 출국 전에 해외 수수료가 낮거나 없는 카드를 하나 만들어두면, 별도로 신경 쓰지 않아도 여행 내내 이득을 볼 수 있습니다.' },
  { id: 'g_travel_receipt_habit', category: '여행', tags: ['면세', '영수증', '습관적'], label: '영수증은 습관적으로 챙겨두세요', tipKo: '면세·환불·경비 정산이 필요할 수 있으니, 여행 중 받은 영수증은 바로 버리지 말고 봉투 하나에 모아두세요.', detail: '면세 처리, 물건 교환·환불, 나중에 경비를 정산해야 하는 경우처럼 영수증이 필요한 순간은 생각보다 자주 생기는데, 그때마다 이미 버렸다면 곤란해집니다. 작은 지퍼백이나 봉투 하나를 정해 여행 중 받는 영수증을 모두 모아두면 나중에 필요할 때 훨씬 수월합니다.' },
  { id: 'g_travel_tax_refund_threshold', category: '여행', tags: ['면세', '환급', '최소', '구매', '금액'], label: '면세 환급, 최소 구매 금액을 확인하세요', tipKo: '면세는 한 매장에서 일정 금액 이상 구매해야 적용돼요. 여러 매장에서 조금씩 사면 면세를 못 받을 수 있어요.', detail: '일본의 면세 제도는 같은 매장에서 하루 동안 일정 금액(통상 5,000엔) 이상을 구매해야 적용되기 때문에, 여러 작은 매장에서 조금씩 나눠 사면 각각 기준 금액에 못 미쳐 면세를 받지 못할 수 있습니다. 큰 쇼핑을 계획한다면 가능한 한 곳에서 몰아서 구매하는 것이 면세 혜택을 받기에 유리합니다.' },
  { id: 'g_travel_ic_card_types', category: '여행', tags: ['카드', 'IC카드', 'Suica', 'PASMO', '공항'], label: 'IC카드 종류, 아무거나 하나면 충분해요', tipKo: 'Suica·PASMO·ICOCA 등 이름은 달라도 지금은 전국 대부분 호환돼요. 처음 도착한 공항에서 파는 걸로 하나만 사면 돼요.', detail: '지역별로 이름이 다른 교통 IC카드(간토의 Suica·PASMO, 간사이의 ICOCA 등)는 지금은 전국 주요 교통수단·편의점에서 대부분 호환되므로, 어느 지역에서 사든 하나만 있으면 여행 내내 충분합니다. 처음 도착하는 공항이나 역에서 파는 카드를 사면 그만이라, 지역별로 다시 살 필요가 없습니다.' },
  { id: 'g_travel_jrpass_purchase_window', category: '여행', tags: ['JR패스', '할인', '구매', '시점', '놓치지'], label: 'JR패스는 구매 시점을 놓치지 마세요', tipKo: '일부 할인 패스는 출국 전 온라인으로만 구매 가능해요. 여행지 도착 후엔 못 사는 경우가 있으니 미리 확인하세요.', detail: '일부 지역 한정 철도 패스나 외국인 전용 할인 승차권은 출국 전 온라인으로만 구매하거나, 현지 도착 후 일정 기간 안에 교환해야 하는 조건이 붙는 경우가 있습니다. 원하는 패스가 있다면 이용 조건과 구매 기한을 여행 계획 초기에 확인해두는 것이 안전합니다.' },
  { id: 'g_travel_airport_to_city', category: '여행', tags: ['버스', '택시', '공항', '시내', '선택지'], label: '공항에서 시내까지, 선택지를 미리 비교하세요', tipKo: '리무진버스·특급열차·택시 중 짐 양과 예산에 맞는 이동수단을 미리 정해두면 도착 후 헤매지 않아요.', detail: '공항에서 시내로 이동하는 방법은 저렴하지만 시간이 걸리는 리무진버스, 빠르지만 요금이 있는 특급열차, 편하지만 가장 비싼 택시 등 다양한데, 짐의 양과 예산, 도착 시간대에 따라 미리 정해두면 피곤한 상태로 공항에서 헤매는 일을 줄일 수 있습니다.' },
  { id: 'g_travel_night_bus_option', category: '여행', tags: ['신칸센', '버스', '도쿄', '오사카'], label: '심야버스로 숙박비를 아낄 수 있어요', tipKo: '도시 간 이동에 심야버스를 타면 하룻밤 숙박비를 아끼면서 이동할 수 있어요 — 다만 체력 소모는 감안하세요.', detail: '도쿄·오사카처럼 먼 도시 간 이동에는 신칸센 대신 심야버스를 이용하면 요금이 훨씬 저렴하고 자는 동안 이동해 하루 숙박비까지 아낄 수 있습니다. 다만 좌석에서 자는 만큼 신칸센보다 체력 소모가 크므로, 다음 날 일정이 빡빡하지 않을 때 활용하는 것이 좋습니다.' },
  { id: 'g_travel_rental_car_license', category: '여행', tags: ['렌터카', '국제운전면허', '미리'], label: '렌터카는 국제운전면허를 미리 준비하세요', tipKo: '일본에서 렌터카를 몰려면 국제운전면허증(제네바협약)을 출국 전 발급받아야 해요. 현지에서는 못 만들어요.', detail: '일본에서 렌터카를 이용하려면 국제운전면허증이 필요한데, 이는 한국에서 출국 전에 미리 발급받아야 하며 현지에 도착해서는 만들 수 없습니다. 여권용 사진과 운전면허증만 있으면 당일 발급도 가능하니, 렌터카 계획이 있다면 출국 전 여유를 두고 준비하세요.' },
  { id: 'g_travel_bike_rental_option', category: '여행', tags: ['전철', '버스', '자전거', '호텔', '가나'], label: '자전거 대여로 골목 여행을 즐겨보세요', tipKo: '교토·가나자와 같은 소도시는 자전거 대여소가 잘 되어 있어, 대중교통보다 훨씬 자유롭게 골목을 다닐 수 있어요.', detail: '교토·가나자와처럼 명소가 밀집한 소도시는 대여 자전거 인프라가 잘 갖춰져 있어, 버스·전철보다 훨씬 자유롭게 좁은 골목이나 대중교통이 닿지 않는 곳까지 다닐 수 있습니다. 호텔이나 관광안내소에서 대여·반납이 가능한 곳이 많으니 도착 후 문의해보세요.' },
  { id: 'g_travel_taxi_app_option', category: '여행', tags: ['택시', '호출앱', '언어', '부담'], label: '택시도 앱으로 부르면 언어 부담이 줄어요', tipKo: '길에서 손 흔들어 잡기 어려우면 GO 같은 택시 호출 앱으로 목적지를 입력해 부르면 대화 없이도 이용할 수 있어요.', detail: '일본어로 목적지를 설명하기 부담스럽다면, GO 같은 택시 호출 앱으로 지도에서 목적지를 지정해 택시를 부르면 기사와 대화 없이도 정확하게 이동할 수 있습니다. 예상 요금도 미리 확인할 수 있어 바가지 걱정 없이 이용 가능합니다.' },
  { id: 'g_travel_checkin_checkout_time', category: '여행', tags: ['체크인', '체크아웃', '숙소', '아웃', '시간'], label: '체크인·아웃 시간, 짐 맡기기로 활용하세요', tipKo: '체크인 전·체크아웃 후에도 대부분 숙소가 짐을 맡아줘요. 이 시간을 관광에 활용하면 하루를 더 알차게 써요.', detail: '대부분의 숙소는 정식 체크인 전이나 체크아웃 후에도 짐을 프런트에 맡아주는 서비스를 제공하므로, 이 시간 동안 몸만 가볍게 관광을 다니면 도착일과 출발일도 알차게 활용할 수 있습니다. 큰 짐 없이 다니면 이동도 훨씬 편해집니다.' },
  { id: 'g_travel_ryokan_vs_hotel_vs_hostel', category: '여행', tags: ['료칸', '호텔', '숙소', '온천', '다다미'], label: '료칸·호텔·게스트하우스, 경험이 다 달라요', tipKo: '전통 다다미방과 가이세키 요리를 원하면 료칸, 실속을 원하면 비즈니스호텔, 여행자와 어울리고 싶으면 게스트하우스가 어울려요.', detail: '료칸은 다다미방과 온천, 가이세키 요리까지 포함된 전통적인 숙박 경험을 제공하는 대신 가격이 높은 편이고, 비즈니스호텔은 실속 있고 효율적인 반면 편의시설은 간소하며, 게스트하우스는 저렴하고 다른 여행자와 교류하기 좋지만 개인 공간이 제한적입니다. 여행의 목적에 맞게 숙소 유형을 고르는 것이 만족도를 높이는 요령입니다.' },
  { id: 'g_travel_ryokan_booking_caution', category: '여행', tags: ['료칸', '예약', '식사', '포함', '여부'], label: '료칸 예약, 식사 포함 여부를 꼭 확인하세요', tipKo: '료칸은 대개 1박 2식(조식+석식) 요금인데, 별도로 식사 없는 플랜도 있으니 예약 전 꼭 확인하세요.', detail: '전통 료칸은 보통 저녁 가이세키 요리와 아침 식사가 포함된 1박 2식 요금제가 기본인 경우가 많은데, 최근엔 식사 없이 숙박만 저렴하게 이용하는 플랜도 늘고 있어 예약 페이지에서 식사 포함 여부를 꼼꼼히 확인해야 원하는 경험을 놓치지 않습니다.' },
  { id: 'g_travel_smoking_room_check', category: '여행', tags: ['호텔', '체크인', '금연', '흡연', '예약'], label: '호텔 예약 시 흡연·금연 객실을 확인하세요', tipKo: '흡연 여부에 민감하다면 예약 단계에서 반드시 금연(또는 흡연) 객실을 지정하세요 — 나중에 바꾸기 어려울 수 있어요.', detail: '냄새에 민감한 여행자라면 예약 단계에서 반드시 금연 객실 여부를 확인하고 지정해야 하는데, 인기 시즌에는 원하는 타입의 객실이 이미 다 찼을 수 있어 체크인 당일 변경이 어려운 경우가 많습니다. 예약 확인 메일에 명시된 객실 타입을 미리 다시 확인하는 습관을 들이세요.' },
  { id: 'g_travel_restaurant_reservation_needed', category: '여행', tags: ['스시', '식당', '예약', '인기', '맛집'], label: '인기 맛집은 몇 주 전 예약이 필요해요', tipKo: 'SNS에서 화제가 된 맛집·오마카세는 즉흥 방문이 거의 불가능해요. 여행 계획 단계에서 미리 예약하세요.', detail: 'SNS나 미디어에서 화제가 된 인기 식당, 특히 오마카세 스시나 소규모 맛집은 몇 주에서 몇 달 전에 예약이 마감되는 경우가 흔합니다. 특정 식당을 꼭 가고 싶다면 여행 일정을 짜는 초기 단계에서 바로 예약 가능 여부부터 확인하는 것이 좋습니다.' },
  { id: 'g_travel_allergy_card_prepare', category: '여행', tags: ['카드', '식당', '알레르기', '미리', '번역해'], label: '알레르기 카드를 미리 번역해 준비하세요', tipKo: '알레르기가 있다면 일본어로 미리 적어둔 카드를 보여주는 것이 말로 설명하는 것보다 훨씬 정확하고 빨라요.', detail: '음식 알레르기가 있다면 여행 전 번역 앱이나 번역가의 도움으로 알레르기 성분을 일본어로 정확히 적은 카드를 준비해두면, 현장에서 말로 설명하다 오해가 생기는 위험을 크게 줄일 수 있습니다. 식당에 들어가기 전 카드를 보여주며 확인을 청하는 것이 안전합니다.' },
  { id: 'g_travel_vegetarian_options_limited', category: '여행', tags: ['식당', '채식', '옵션', '미리'], label: '채식 옵션은 미리 검색해두는 게 안전해요', tipKo: '일본은 육수에 가다랑어포를 쓰는 경우가 많아 "채소만 들어간" 메뉴도 완전 채식이 아닐 수 있어요.', detail: '일본 요리는 겉보기에 채소 위주라도 육수에 가다랑어포(가츠오부시)나 어패류 성분이 들어가는 경우가 많아, 엄격한 채식·비건 여행자는 겉모습만 보고 안심하기 어렵습니다. 채식 전문 식당을 미리 검색해두거나, 주문 전 "가다랑어 육수를 쓰나요"처럼 구체적으로 확인하는 습관이 필요합니다.', exampleJa: 'かつおだしは使っていますか', exampleKo: '가다랑어 육수를 쓰나요?' },
  { id: 'g_travel_last_order_time', category: '여행', tags: ['식당', '라스트오더', '시간', '놓치지'], label: '라스트오더 시간을 놓치지 마세요', tipKo: '식당은 폐점 시간보다 먼저 "라스트오더(L.O.)" 시간이 있어요. 이 시간 이후엔 주문 자체가 안 될 수 있어요.', detail: '많은 일본 식당은 실제 폐점 시간보다 먼저 "라스트오더(L.O.)" 시간을 정해두고, 이 시간이 지나면 아직 영업 중이어도 신규 주문을 받지 않는 경우가 흔합니다. 늦은 시간에 식당을 찾는다면 입구에 붙은 라스트오더 시각을 먼저 확인하는 것이 헛걸음을 피하는 방법입니다.' },
  { id: 'g_travel_cash_only_restaurants', category: '여행', tags: ['현금', '카드', '식당', '맛집', '아직'], label: '오래된 맛집은 아직 현금전용인 곳이 많아요', tipKo: '작고 전통 있는 식당일수록 카드·전자결제가 안 되는 곳이 있어요. 현금을 넉넉히 챙기고 들어가세요.', detail: '캐시리스 결제가 빠르게 늘고 있지만, 오래되고 작은 개인 식당·노포일수록 여전히 현금만 받는 경우가 흔합니다. 마음에 든 노포를 발견했는데 카드 결제가 안 될 수 있으니, 식사 전 현금 잔액을 미리 확인해두는 것이 좋습니다.' },
  { id: 'g_travel_fast_turnover_manners', category: '여행', tags: ['라멘', '초밥', '매너', '회전율', '빠른'], label: '회전율 빠른 가게에서는 식사 후 바로 자리를 비워주세요', tipKo: '라멘집·회전초밥처럼 줄이 긴 가게는 식사 후 오래 앉아 있는 것보다 바로 자리를 비켜주는 것이 매너예요.', detail: '대기 줄이 긴 라멘집이나 회전초밥집은 회전율이 매출과 직결되기 때문에, 식사를 마쳤다면 오래 앉아 대화를 이어가기보다 빠르게 자리를 정리하고 나오는 것이 뒤에 기다리는 손님과 가게에 대한 배려로 여겨집니다.' },
  { id: 'g_travel_lost_and_found_system', category: '여행', tags: ['전철', '택시', '분실물', '분실물센터', '신고'], label: '분실물은 의외로 잘 찾아져요', tipKo: '전철·택시에 물건을 두고 내렸다면, 해당 노선·회사의 분실물센터에 바로 연락하면 찾을 확률이 높아요.', detail: '일본은 분실물을 그대로 두거나 습득 후 신고하는 문화가 정착돼 있어, 전철이나 택시에 물건을 두고 내렸어도 해당 노선·택시회사의 분실물센터(忘れ物センター)에 시간·차량 정보와 함께 바로 연락하면 찾을 확률이 의외로 높습니다. 늦게 연락할수록 보관 장소가 이동될 수 있으니 되도록 빨리 연락하는 것이 좋습니다.', exampleJa: '忘れ物をしました', exampleKo: '물건을 두고 내렸어요.' },
  { id: 'g_travel_earthquake_basic_response', category: '여행', tags: ['마트', '지진', '대피', '재난'], label: '지진이 나면 이렇게 대응하세요', tipKo: '흔들리면 우선 튼튼한 테이블 아래로 몸을 피하고, 흔들림이 멈추면 문을 열어 대피로를 확보하세요.', detail: '지진이 발생하면 당황해서 바로 밖으로 뛰쳐나가기보다, 먼저 튼튼한 테이블이나 책상 아래로 몸을 피해 낙하물로부터 머리를 보호하는 것이 우선입니다. 흔들림이 멈춘 뒤에는 문이나 창문을 열어 대피로가 막히지 않게 확보하고, 스마트폰으로 긴급 지진 속보 알림을 켜두면 도움이 됩니다.' },
  { id: 'g_travel_emergency_numbers', category: '여행', tags: ['경찰', '구급차', '긴급', '연락처'], label: '긴급 연락처 두 가지를 외워두세요', tipKo: '경찰은 110, 구급차·화재는 119예요. 말이 안 통해도 일단 걸면 다국어 통역 연결이 가능한 경우가 많아요.', detail: '일본의 긴급 신고 번호는 경찰이 110, 구급차와 화재 신고는 119로 한국과 다르니 출국 전 외워두는 것이 좋습니다. 언어가 통하지 않아도 신고 후 상황을 설명하면 다국어 통역 서비스로 연결해주는 경우가 많으니, 위급 상황에서는 주저하지 말고 전화부터 거는 것이 우선입니다.' },
  { id: 'g_travel_solo_travel_tips', category: '여행', tags: ['숙소', '응급', '가나', '혼자', '위치'], label: '혼자 여행할 땐 숙소 위치를 더 신중히 고르세요', tipKo: '나홀로 여행이라면 역에서 가깝고 늦은 시간에도 밝은 번화가 근처 숙소를 고르는 것이 안전 면에서 유리해요.', detail: '혼자 여행할 때는 동행이 있을 때보다 안전에 좀 더 신경 쓰는 것이 좋은데, 역에서 가깝고 밤에도 인적이 있는 번화가 근처 숙소를 고르면 늦은 귀가나 응급 상황에 대응하기 훨씬 수월합니다. 하루 일정과 귀가 예상 시간을 지인에게 간단히 공유해두는 습관도 도움이 됩니다.' },
  { id: 'g_travel_family_with_kids_tips', category: '여행', tags: ['백화점', '동반', '육아', '기저귀교환대', '수유실'], label: '아이 동반 여행엔 기저귀교환대·수유실 앱을 활용하세요', tipKo: '일본 주요 백화점·역엔 기저귀교환대·수유실이 잘 갖춰져 있어요. 위치를 알려주는 지도 앱을 활용하면 편해요.', detail: '일본의 주요 백화점, 쇼핑몰, 대형 역에는 기저귀교환대와 수유실이 잘 갖춰져 있는 경우가 많아, 이런 시설의 위치를 미리 검색해주는 육아 지원 지도 앱을 활용하면 아이 동반 여행이 한결 수월해집니다. 유모차 대여 서비스를 제공하는 테마파크·시설도 많으니 미리 확인해두세요.' },
  { id: 'g_travel_accessibility_facilities', category: '여행', tags: ['기차', '휠체어', '거동', '불편', '여행자'], label: '휠체어·거동 불편 여행자를 위한 시설도 잘 되어 있어요', tipKo: '주요 역·관광지는 엘리베이터·경사로가 잘 갖춰진 편이지만, 오래된 시설은 예외도 있으니 미리 확인하는 게 좋아요.', detail: '일본의 주요 기차역과 관광지는 엘리베이터·경사로 등 무장애 시설이 비교적 잘 갖춰져 있는 편이지만, 오래된 사찰이나 좁은 골목 상점가처럼 예외적으로 접근이 어려운 곳도 있습니다. 휠체어나 거동이 불편한 동반자와 여행한다면, 방문 예정지의 접근성 정보를 미리 검색하거나 관광안내소에 문의해두는 것이 안전합니다.' },
  { id: 'g_travel_elderly_companion_tips', category: '여행', tags: ['노약자', '어르신', '이동', '거리'], label: '어르신과 함께라면 이동 거리를 넉넉히 잡으세요', tipKo: '노약자 동반 여행은 하루 이동 거리와 계단 유무를 미리 확인해, 무리한 일정보다 여유 있는 동선을 짜는 게 좋아요.', detail: '어르신과 함께하는 여행은 걷는 속도와 체력을 고려해 하루 일정에 여유를 두고, 방문지에 계단이 많은지 엘리베이터가 있는지 미리 확인하는 것이 중요합니다. 중간중간 앉아 쉴 수 있는 카페나 휴게 공간을 동선에 끼워 넣으면 훨씬 편안한 여행이 됩니다.' },
  { id: 'g_travel_couple_trip_ideas', category: '여행', tags: ['료칸', '숙소', '예약', '온천'], label: '커플 여행엔 온천 료칸·야경 명소를 더해보세요', tipKo: '료칸의 개인탕이나 도시 야경 명소는 커플 여행의 만족도를 확실히 높여주는 코스예요.', detail: '커플 여행이라면 대욕장 대신 둘만 이용할 수 있는 개인탕(貸切風呂)이 있는 료칸이나, 도심의 전망대·타워 야경 명소를 일정에 넣으면 특별한 추억을 만들기 좋습니다. 개인탕은 인기가 많아 예약이 금방 차니 숙소 예약 시 함께 신청해두는 것이 좋습니다.' },
  { id: 'g_travel_backpacker_budget_tips', category: '여행', tags: ['배낭여행', '게스트하우스', '정기권'], label: '배낭여행자라면 게스트하우스·정기권을 활용하세요', tipKo: '숙박은 도미토리형 게스트하우스, 이동은 지역 프리패스를 조합하면 예산을 크게 아낄 수 있어요.', detail: '예산을 최대한 아끼고 싶은 배낭여행자에게는 도미토리형 게스트하우스 숙박과, 한 지역을 집중 탐방할 땐 그 지역 전용 프리패스를 조합하는 것이 효율적입니다. 코인로커·코인세탁 등 저비용 인프라가 잘 갖춰져 있는 점도 배낭여행에 유리한 환경입니다.' },
  { id: 'g_travel_luxury_travel_upgrades', category: '여행', tags: ['신칸센', '료칸', '예약', '온천', '럭셔리'], label: '럭셔리 여행이라면 그린샤·스위트 료칸을 고려하세요', tipKo: '예산에 여유가 있다면 신칸센 그린샤(고급석)나 스위트 객실 료칸으로 좀 더 특별한 경험을 더할 수 있어요.', detail: '예산에 여유가 있는 여행이라면 신칸센의 그린샤(그린車, 고급 좌석)로 넓고 조용한 이동을 즐기거나, 최고급 료칸의 스위트 객실·전용 온천으로 한층 특별한 경험을 더할 수 있습니다. 이런 상품은 인기가 높아 예약을 서두르는 것이 좋습니다.' },
  { id: 'g_travel_pet_travel_restrictions', category: '여행', tags: ['반려동물', '동반', '조건', '까다로워요'], label: '반려동물 동반은 조건이 까다로워요', tipKo: '일본은 반려동물 입국에 검역·예방접종 증명 등 까다로운 절차가 있어요. 동반 계획이라면 몇 달 전부터 준비해야 해요.', detail: '반려동물과 함께 일본에 입국하려면 광견병 항체 검사, 예방접종 증명서, 사전 신고 등 복잡한 검역 절차를 몇 달 전부터 준비해야 하며, 절차를 놓치면 장기간 격리되거나 입국이 거부될 수 있습니다. 반려동물 동반 여행을 계획한다면 검역소 홈페이지에서 최신 절차를 충분히 미리 확인해야 합니다.' },
  { id: 'g_travel_wifi_router_rental', category: '여행', tags: ['공항', '와이파이', '예약', '포켓와이파', '대여'], label: '포켓와이파이 대여, 공항에서 바로 받을 수 있어요', tipKo: '여러 명이 함께 데이터를 나눠 쓴다면 유심보다 포켓와이파이 대여가 더 경제적일 수 있어요. 공항 카운터에서 예약 수령이 편해요.', detail: '여러 명이 함께 여행하며 데이터를 나눠 써야 한다면, 개인별 유심보다 여러 기기를 동시에 연결할 수 있는 포켓와이파이 대여가 더 경제적인 경우가 많습니다. 출국 전 온라인으로 예약해두면 공항 도착 카운터에서 바로 수령하고, 귀국 시 반납함에 넣기만 하면 되어 편리합니다.' },
  { id: 'g_travel_coin_locker_size_check', category: '여행', tags: ['마트', '코인로커', '크기', '미리'], label: '코인로커 크기, 큰 캐리어는 미리 확인하세요', tipKo: '역 코인로커는 대형 사이즈 수량이 적어요. 캐리어가 크다면 도착하자마자 대형 로커부터 찾아두는 게 안전해요.', detail: '역의 코인로커는 소형·중형에 비해 캐리어가 들어가는 대형 로커의 수가 훨씬 적어, 인기 관광지 역에서는 낮 시간대에 대형 로커가 금방 동나는 경우가 많습니다. 캐리어를 맡길 계획이라면 도착하자마자 대형 로커부터 확보하거나, 스마트폰 앱으로 빈 로커를 미리 확인하는 것이 안전합니다.' },
  { id: 'g_travel_seasonal_packing_list', category: '여행', tags: ['계절별', '목록'], label: '계절별 짐 목록을 따로 만들어두세요', tipKo: '여름은 자외선차단제·휴대용 선풍기, 겨울은 핫팩·두꺼운 겉옷처럼 계절마다 필수품이 달라요.', detail: '일본은 여름 습도와 겨울 건조·추위가 한국과는 또 다른 방식으로 느껴지는 경우가 많아, 여름엔 자외선차단제와 휴대용 선풍기, 겨울엔 핫팩과 보온성 좋은 겉옷처럼 계절별 필수품을 따로 정리해두면 짐을 빠뜨리지 않고 챙길 수 있습니다.' },
  { id: 'g_travel_language_barrier_backup', category: '여행', tags: ['한자', '최후', '수단', '필담'], label: '말이 안 통할 때의 최후 수단, 필담', tipKo: '번역 앱도 안 통하는 상황이면 종이에 한자·숫자를 적어 보여주는 필담이 의외로 잘 통해요.', detail: '한국어와 일본어는 한자 문화권을 공유해, 번역 앱이 오작동하거나 인터넷이 안 될 때는 종이에 한자나 숫자를 적어 보여주는 필담(筆談)이 의외로 효과적인 최후 수단이 됩니다. 메모장 앱을 켜서 큰 글씨로 보여주는 것도 같은 효과를 냅니다.' },
  { id: 'g_travel_convenience_store_as_hub', category: '여행', tags: ['현금', '와이파이', '편의점', '화장실'], label: '길을 잃으면 일단 편의점부터 찾으세요', tipKo: '편의점은 화장실·ATM·와이파이·지도까지 다 되는 만능 거점이라, 곤란할 때 일단 들어가면 대부분 해결돼요.', detail: '길을 잃거나 화장실이 급하거나 현금이 부족한 등 여행 중 곤란한 상황이 생기면, 일단 가장 가까운 편의점부터 찾는 것이 가장 확실한 해결책입니다. 화장실·ATM·와이파이·프린트까지 웬만한 기능을 다 갖추고 있어 여행자의 만능 피난처 역할을 합니다.' },
  { id: 'g_travel_photo_spot_etiquette', category: '여행', tags: ['편의점', '매너', '인기', '포토스팟'], label: '인기 포토스팟, 줄 서서 순서를 지키세요', tipKo: '유명한 포토스팟은 뒤에 기다리는 사람들을 위해 짧게 찍고 바로 자리를 비켜주는 것이 매너예요.', detail: '후지산이 보이는 편의점 앞이나 유명 골목처럼 SNS로 유명해진 포토스팟은 항상 사진을 찍으려는 사람들로 줄이 생기기 마련이라, 순서를 지켜 기다리고 자신의 차례에는 짧게 찍은 뒤 바로 자리를 비켜주는 것이 다음 사람에 대한 배려입니다.' },
  { id: 'g_travel_weather_app_check', category: '여행', tags: ['일본', '기상청', '실시간', '날씨'], label: '일본 기상청 앱으로 실시간 날씨를 확인하세요', tipKo: '한국 날씨 앱보다 일본 기상청(気象庁)이나 현지 날씨 앱이 시간대별 강수 확률을 더 정확히 알려줘요.', detail: '한국에서 쓰던 날씨 앱은 해외 지역 예보 정밀도가 떨어지는 경우가 많아, 일본 여행 중에는 일본 기상청이나 현지에서 많이 쓰는 날씨 앱을 설치해 시간대별 강수 확률을 확인하는 것이 실제 일정을 짜는 데 훨씬 도움이 됩니다.' },
  { id: 'g_travel_umbrella_share_service', category: '여행', tags: ['편의점', '우산', '비', '대여', '공유'], label: '갑자기 비 오면 우산 대여 서비스를 찾아보세요', tipKo: '역·편의점 근처에 우산 대여·공유 서비스가 있는 도시도 있어요. 비닐우산을 계속 사는 대신 활용해보세요.', detail: '일부 대도시는 역이나 편의점 근처에 저렴하게 빌리고 다른 곳에 반납할 수 있는 우산 대여·공유 서비스를 운영하는데, 갑작스러운 비에 매번 비닐우산을 사서 쌓아두기보다 이런 서비스를 찾아 활용하면 짐도 줄이고 환경에도 도움이 됩니다.' },

  // ── 여행 중 위기 대응 (재난·분실·결제·병원) ──
  { id: 'g_emergency_numbers', category: '여행', tags: ['긴급', '구급', '경찰', '전화번호', '재난'], label: '긴급 전화는 119(구급·소방)와 110(경찰)로 구분돼요', tipKo: '한국과 번호가 달라요! 불이 나거나 다쳤을 때는 119(きゅうきゅう・しょうぼう), 도난·사고 신고는 110(けいさつ)이에요.', detail: '일본의 긴급 전화번호는 용도에 따라 둘로 나뉘는데, 화재·구급(다치거나 아플 때)은 119, 도난·사고 등 경찰 신고는 110입니다. 한국의 119(통합)와 달리 완전히 다른 두 번호로 분리돼 있으므로 여행 전 미리 기억해두는 것이 좋고, 전화를 걸면 火事(かじ, 화재)인지 救急(きゅうきゅう, 구급)인지부터 물어보니 당황하지 말고 상황과 주소·현재 위치를 말하면 됩니다.', exampleJa: '救急車を呼んでください', exampleKo: '구급차를 불러주세요', commonMistake: '한국처럼 119로 도난·사고까지 신고하려 하면 안 돼요 — 경찰은 110입니다.', action: '스마트폰에 119(구급/화재)·110(경찰) 번호를 미리 메모해두세요.', missionIds: ['C51'] },
  { id: 'g_card_declined', category: '여행', tags: ['카드', '결제', '거절', '현금'], label: '카드가 거절되면 당황하지 말고 이렇게 말하세요', tipKo: '해외 카드가 간혹 결제 거절될 때가 있어요. カードが使えないみたいです(카드가 안 되는 것 같아요)라고 말하고 다른 카드나 현금으로 바꿔보세요.', detail: '일본은 아직도 현금 결제 비중이 높은 소규모 매장이 있고, 해외 발급 카드는 간혹 시스템 오류나 한도 문제로 결제가 거절되는 경우가 있습니다. 당황해서 아무 말 없이 카드를 다시 긁기보다, カードが使えないみたいです(카드가 안 되는 것 같아요)라고 상황을 알리고 別のカードで試してもいいですか(다른 카드로 해봐도 될까요) 또는 現金で払います(현금으로 낼게요)로 대응하면 매끄럽게 넘어갈 수 있습니다. 소액 현금을 항상 여유 있게 챙기는 것이 가장 안전한 대비책입니다.', exampleJa: '別のカードで試してもいいですか', exampleKo: '다른 카드로 해봐도 될까요?', action: '카드 거절 시 現金で払います(현금으로 낼게요)를 바로 말할 수 있게 소액 현금을 챙겨두세요.', missionIds: ['C52'] },
  { id: 'g_lost_item_report', category: '여행', tags: ['분실', '여권', '경찰서', '신고'], label: '여권·소지품을 잃어버리면 이렇게 신고하세요', tipKo: '물건을 잃어버렸을 때는 忘れ物をしました(물건을 두고 왔어요) 또는 パスポートをなくしました(여권을 잃어버렸어요)로 신고를 시작해요.', detail: '전철·택시·매장 등에 물건을 두고 내렸다면 忘れ物をしました(물건을 두고 왔어요)라고 알리고 언제·어디서·무엇을 두고 왔는지 설명하면 분실물센터로 연결됩니다. 여권처럼 중요한 물건을 완전히 잃어버렸다면 가까운 交番(こうばん, 파출소)에 가서 パスポートをなくしました(여권을 잃어버렸어요)라고 신고하고 遺失届(いしつとどけ, 분실신고서)를 작성해야 하며, 이 신고 확인서가 있어야 대사관에서 여권 재발급·귀국용 여행증명서 절차를 진행할 수 있습니다.', exampleJa: 'パスポートをなくしました', exampleKo: '여권을 잃어버렸어요', action: '여권을 잃어버리면 먼저 가까운 파출소에서 분실 신고서(紛失届)를 받아두세요 — 대사관 재발급에 필요해요.', missionIds: ['C26'] },
  { id: 'g_hospital_reception', category: '여행', tags: ['병원', '접수처', '진료과', '보험증'], label: '병원 접수처에서는 이 순서로 진행돼요', tipKo: '병원에 가면 먼저 受付(うけつけ, 접수처)에서 保険証(ほけんしょう, 보험증) 유무를 확인받고, 무슨 과(何科/なにか)로 갈지 안내받아요.', detail: '일본 병원은 접수처(受付)에서 시작하는데, 외국인 여행자는 대부분 일본 보험증이 없으므로 保険証はありません(보험증이 없어요)이라고 말하면 자비 진료(自費/じひ)로 안내됩니다. 접수 후 증상에 따라 内科(ないか, 내과)·外科(げか, 외과)처럼 진료과를 안내받고 대기하다가 이름이 불리면 진료실로 들어가며, 진료 후에는 会計(かいけい, 수납)에서 진료비를 정산합니다. 여행자보험이 있다면 진료비 영수증과 명세서(明細書)를 반드시 받아두어야 귀국 후 보험사에 청구할 수 있습니다.', exampleJa: '保険証はありません。自費で大丈夫です', exampleKo: '보험증은 없어요. 자비 진료로 괜찮아요', action: '진료 후 会計(수납)에서 영수증과 명세서(明細書)를 꼭 챙겨 여행자보험 청구에 대비하세요.', missionIds: ['C52'] },
  { id: 'g_izakaya_otoshi', category: '문화', tags: ['이자카야', '오토시', '자릿세', '기본안주'], label: '이자카야의 오토시(お通し)는 주문 안 해도 나와요', tipKo: '자리에 앉으면 주문하지 않아도 작은 기본 안주(お通し)가 나오고, 이건 자릿세 개념이라 대부분 유료(300~500엔 정도)예요.', detail: 'お通し(오토시)는 이자카야에서 자리에 앉자마자 주문 여부와 상관없이 나오는 작은 기본 안주로, 한국의 밑반찬과 달리 대부분 1인당 300~500엔 정도의 자릿세 개념으로 계산서에 자동 포함됩니다. 처음 보는 여행자는 "시키지 않은 음식이 나왔다"고 당황하거나 클레임을 걸기 쉬운데, 이는 정상적인 관행이므로 그냥 받아서 먹으면 되고, 거부하고 싶다면 입점 전에 お通しはいりません(오토시는 필요 없어요)이라고 미리 말해볼 수는 있지만 받아들여지지 않는 가게도 많습니다.', exampleJa: 'これは、お通しです', exampleKo: '이건 기본 안주예요', commonMistake: '주문하지 않은 음식이 나왔다고 놀라거나 무료라고 착각하지 마세요 — 대부분 유료 자릿세예요.', action: '계산서에 お通し代(오토시 요금)가 있는지 확인하고, 당연한 관행이니 놀라지 마세요.' },
  { id: 'g_izakaya_warikan', category: '문화', tags: ['이자카야', '와리캉', '더치페이', '계산'], label: '일본은 와리캉(割り勘, 더치페이)이 기본이에요', tipKo: '친구·동료와 식사하면 割り勘(더치페이)이 일반적이에요. 계산대에서 別々でお願いします(따로따로 부탁합니다)라고 말하면 나눠 계산해줘요.', detail: '割り勘(わりかん)은 인원수대로 금액을 나누는 더치페이 문화로, 일본에서는 친구나 동료 사이 회식에서 한 사람이 전부 계산하기보다 이렇게 나눠 내는 것이 훨씬 일반적입니다. 계산대에서 別々でお願いします(따로따로 부탁합니다)라고 말하면 각자 결제하게 나눠주거나, 총액을 인원수로 나눈 금액을 알려주기도 합니다. 다만 가게에 따라 개별 결제(別会計/べつかいけい)가 불가능해 한 사람이 먼저 낸 뒤 현금으로 정산하는 경우도 있으니, 인원이 많다면 미리 물어보는 것이 좋습니다.', exampleJa: '別々でお願いします', exampleKo: '따로따로 부탁합니다', action: '여럿이 식사할 땐 계산 전에 別々でお願いします로 나눠 낼 수 있는지 먼저 물어보세요.' },
  { id: 'g_onsen_towel_rule', category: '문화', tags: ['온천', '수건', '타월', '탕'], label: '온천 탕 안에는 큰 수건을 가지고 들어가지 않아요', tipKo: '목욕용 큰 타월(バスタオル)은 탈의실에 두고, 몸을 가릴 땐 작은 수건(手ぬぐい/タオル)만 들고 들어가요. 그 수건도 탕 안에는 담그지 않아요.', detail: '일본 온천·대중목욕탕에서는 탈의실의 큰 목욕 타월(バスタオル)을 욕실 안으로 가져가지 않는 것이 규칙입니다. 몸을 씻고 탕에 들어갈 때는 별도로 파는 작은 수건(手(て)ぬぐい 또는 타월)만 들고 가며, 이 작은 수건조차 탕 물에 직접 담그지 않고 머리 위에 올려두거나 탕 밖에 두는 것이 매너입니다. 큰 타월을 들고 욕실에 들어가면 직원이나 다른 이용객이 제지하는 경우가 있으니, 처음이라면 탈의실에 큰 타월을 두고 가는 것을 잊지 마세요.', commonMistake: '큰 목욕 타월을 몸에 두른 채 욕실로 들어가면 안 돼요 — 탈의실에 두고 가세요.', action: '욕실에 들어가기 전, 큰 타월은 탈의실 바구니에 두고 작은 수건만 챙기세요.' },
  { id: 'g_shinkansen_green_car', category: '여행', tags: ['신칸센', '그린샤', '좌석', '업그레이드'], label: '신칸센에는 그린샤(グリーン車)라는 프리미엄 좌석이 있어요', tipKo: '일반차보다 좌석이 넓고 조용한 그린샤(グリーン車)를 추가 요금을 내고 탈 수 있어요. 장거리 이동이나 업무 출장에 인기예요.', detail: '그린샤(グリーン車)는 일반석보다 좌석 간격이 넓고 좌석 수가 적어 쾌적한 신칸센의 상위 등급 칸으로, 일반 승차권·특급권에 그린권(グリーン券) 요금을 추가로 내면 이용할 수 있습니다. 장거리 구간이나 조용한 환경에서 일하고 싶은 여행자에게 인기가 있으며, 그린샤には、グリーン券が必要です(그린샤에는 그린권이 필요합니다)처럼 매표소나 창구에서 요청하면 안내받을 수 있습니다. 일부 신칸센에는 그린샤보다 더 상위인 그란클래스(グランクラス)도 있습니다.', exampleJa: 'グリーン車の切符はありますか', exampleKo: '그린샤 표가 있나요?', action: '장거리 신칸센을 탈 때 예산이 되면 그린샤(グリーン車) 옵션을 창구에서 물어보세요.' },
  { id: 'g_grammar_tara_to_conditional', category: '문법', tags: ['たら', 'と', '조건형', '가정'], label: '〜たら vs 〜と — "만약 ~라면"의 차이', tipKo: '〜たら는 "혹시 ~한다면"(1회성 가정), 〜と는 "~하면 항상"(자동으로 이어지는 결과)에 가까워요. 雨が降ったら(비가 오면, 그날 한정) vs 春になると(봄이 되면, 매번 그런 일)로 구분해요.', detail: '〜たら는 특정 상황을 가정해 "혹시 ~한다면"이라는 1회성 조건을 나타내는 데 자주 쓰이고, 〜と는 앞의 조건이 이루어지면 뒤의 결과가 자동적·습관적으로 따라온다는 뉘앙스가 강합니다. 예를 들어 雨が降ったら、行きません(비가 오면 안 갈게요)은 오늘 하루의 결정이지만, ボタンを押すと、ドアが開きます(버튼을 누르면 문이 열려요)처럼 기계 작동이나 자연스러운 인과관계에는 と가 더 자연스럽습니다. 여행 중에는 자판기·기계 사용법 설명에서 と를, 개인적인 계획·가정에는 たら를 듣게 되는 경우가 많습니다.', exampleJa: '雨が降ったら、キャンセルします', exampleKo: '비가 오면 취소할게요', commonMistake: 'と는 뒤에 의지·명령·권유(〜てください、〜ましょう 등)가 오는 문장에는 잘 쓰이지 않아요 — 그럴 땐 たら를 써요.', action: '자판기·기계 사용법 안내에서 と가 들리면 "이렇게 하면 항상 이렇게 된다"는 뜻으로 이해해보세요.' },
  { id: 'g_conv_listening_keigo_basics', category: '회화법', tags: ['경어', '존경어', '겸양어', '점원'], label: '점원이 쓰는 경어, 못 해도 알아들으면 충분해요', tipKo: '직접 말할 필요는 없지만 いらっしゃいませ(어서 오세요), かしこまりました(알겠습니다, 정중), 〜でございます(〜입니다, 정중)는 매장에서 항상 들리니 알아두면 편해요.', detail: '일본 매장·서비스업 직원은 손님에게 존경어·겸양어가 섞인 정중한 경어(敬語)를 쓰는데, 여행자가 이를 그대로 따라 말할 필요는 없지만 알아듣는 것만으로 응대가 훨씬 편해집니다. いらっしゃいませ는 "어서 오세요"라는 입장 인사로 대답할 필요가 없는 관용구이고, かしこまりました는 요청을 받아들였다는 정중한 "알겠습니다", 〜でございます는 です의 더 정중한 형태로 "~입니다"라는 뜻입니다. 이 세 가지만 알아둬도 매장에서 듣는 대부분의 경어 표현이 훨씬 편하게 들립니다.', exampleJa: 'かしこまりました', exampleKo: '(정중하게) 알겠습니다', action: '매장에서 かしこまりました를 들으면 요청이 받아들여졌다는 뜻이니 안심하고 기다리세요.' },
];

